import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Currency {
  AOA = 'AOA', // Kwanza
  USD = 'USD', // Dólar
  EUR = 'EUR', // Euro
  BRL = 'BRL'  // Real (opcional)
}

export enum CompanyStatus {
  ACTIVE = 'Ativo',
  PAUSED = 'Pausado',
  CLOSED = 'Encerrado'
}

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE'
}

export interface Company {
  id: string;
  name: string;
  industry: string;
  currency: Currency;
  status: CompanyStatus;
  createdAt: number;
}

export interface Transaction {
  id: string;
  companyId: string;
  type: TransactionType;
  amount: number;
  category: string;
  date: string; // ISO Date string YYYY-MM-DD
  description?: string;
  isFixed?: boolean; // Para despesas
}

export interface MonthlyNote {
  id: string;
  companyId: string;
  monthStr: string; // YYYY-MM format
  note: string;
  aiAnalysis?: string;
}

export interface ExchangeRates {
  [key: string]: number; // Base is USD. e.g. { AOA: 900, EUR: 0.92, USD: 1 }
}

export type ViewState = 'dashboard' | 'companies' | 'month-detail' | 'reports';

import { Company, Transaction, MonthlyNote, ExchangeRates } from '../types';
import { MOCK_COMPANIES, MOCK_TRANSACTIONS, INITIAL_RATES } from '../constants';

const KEYS = {
  COMPANIES: 'nrl_companies',
  TRANSACTIONS: 'nrl_transactions',
  NOTES: 'nrl_notes',
  RATES: 'nrl_rates'
};

export const StorageService = {
  getCompanies: (): Company[] => {
    const data = localStorage.getItem(KEYS.COMPANIES);
    return data ? JSON.parse(data) : MOCK_COMPANIES;
  },

  saveCompanies: (companies: Company[]) => {
    localStorage.setItem(KEYS.COMPANIES, JSON.stringify(companies));
  },

  getTransactions: (): Transaction[] => {
    const data = localStorage.getItem(KEYS.TRANSACTIONS);
    return data ? JSON.parse(data) : MOCK_TRANSACTIONS;
  },

  saveTransactions: (transactions: Transaction[]) => {
    localStorage.setItem(KEYS.TRANSACTIONS, JSON.stringify(transactions));
  },

  getNotes: (): MonthlyNote[] => {
    const data = localStorage.getItem(KEYS.NOTES);
    return data ? JSON.parse(data) : [];
  },

  saveNotes: (notes: MonthlyNote[]) => {
    localStorage.setItem(KEYS.NOTES, JSON.stringify(notes));
  },

  getRates: (): ExchangeRates => {
    const data = localStorage.getItem(KEYS.RATES);
    return data ? JSON.parse(data) : INITIAL_RATES;
  },

  saveRates: (rates: ExchangeRates) => {
    localStorage.setItem(KEYS.RATES, JSON.stringify(rates));
  }
};

import { GoogleGenAI } from "@google/genai";
import { Company, Transaction, TransactionType } from '../types';

export const generateFinancialAnalysis = async (
  company: Company,
  transactions: Transaction[],
  monthStr: string
): Promise<string> => {
  if (!process.env.API_KEY) {
    return "API Key não configurada. Configure a variável de ambiente API_KEY para utilizar a IA.";
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const income = transactions
    .filter(t => t.type === TransactionType.INCOME)
    .reduce((acc, curr) => acc + curr.amount, 0);

  const expenses = transactions
    .filter(t => t.type === TransactionType.EXPENSE)
    .reduce((acc, curr) => acc + curr.amount, 0);

  const profit = income - expenses;
  const margin = income > 0 ? ((profit / income) * 100).toFixed(2) : '0';

  const expenseBreakdown = transactions
    .filter(t => t.type === TransactionType.EXPENSE)
    .map(t => `- ${t.category}: ${t.amount} ${company.currency} (${t.description || ''})`)
    .join('\n');

  const prompt = `
    Aja como um consultor financeiro empresarial sênior. O nome do aplicativo é "Na Rota do Lucro".
    Analise os dados financeiros da empresa "${company.name}" (${company.industry}) referentes a ${monthStr}.

    Dados:
    - Moeda: ${company.currency}
    - Receita Total: ${income}
    - Despesa Total: ${expenses}
    - Lucro Líquido: ${profit}
    - Margem de Lucro: ${margin}%

    Lista de Despesas:
    ${expenseBreakdown}

    Por favor, forneça:
    1. Uma análise breve da saúde financeira deste mês.
    2. 3 Sugestões práticas para redução de custos baseadas nas categorias listadas.
    3. Uma previsão otimista para o próximo mês se os custos forem reduzidos em 10%.

    Mantenha o tom profissional, direto e encorajador. Use formatação Markdown simples.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar a análise no momento.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao conectar com a IA. Verifique sua conexão ou tente novamente mais tarde.";
  }
};

import React, { useMemo } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates, Currency } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, DollarSign, Briefcase } from 'lucide-react';

interface DashboardProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

const COLORS = ['#0ea5e9', '#10b981', '#ef4444', '#f59e0b', '#8b5cf6'];

export const Dashboard: React.FC<DashboardProps> = ({ companies, transactions, rates, onNavigate }) => {

  // Convert everything to USD for aggregate stats, strictly for the dashboard summary
  const getConvertedAmount = (amount: number, currency: Currency) => {
    const rate = rates[currency] || 1;
    // Base is USD. If currency is AOA (900), to get USD we divide amount / 900.
    // Wait, typical exchange rate object logic: { AOA: 900 } means 1 USD = 900 AOA.
    // So 900 AOA = 1 USD. Amount / Rate = USD.
    return amount / rate;
  };

  const totals = useMemo(() => {
    let totalIncomeUSD = 0;
    let totalExpenseUSD = 0;

    const activeCompanies = companies.filter(c => c.status !== 'Encerrado');

    activeCompanies.forEach(company => {
      const companyTransactions = transactions.filter(t => t.companyId === company.id);

      const income = companyTransactions
        .filter(t => t.type === TransactionType.INCOME)
        .reduce((sum, t) => sum + t.amount, 0);

      const expense = companyTransactions
        .filter(t => t.type === TransactionType.EXPENSE)
        .reduce((sum, t) => sum + t.amount, 0);

      totalIncomeUSD += getConvertedAmount(income, company.currency);
      totalExpenseUSD += getConvertedAmount(expense, company.currency);
    });

    return {
      income: totalIncomeUSD,
      expense: totalExpenseUSD,
      profit: totalIncomeUSD - totalExpenseUSD
    };
  }, [companies, transactions, rates]);

  // Chart Data Preparation (Last 6 months simplified)
  const chartData = useMemo(() => {
    const data: any[] = [];
    const today = new Date();

    for (let i = 5; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const monthKey = d.toISOString().slice(0, 7); // YYYY-MM

      let mIncome = 0;
      let mExpense = 0;

      transactions.forEach(t => {
        if (t.date.startsWith(monthKey)) {
          const comp = companies.find(c => c.id === t.companyId);
          if (comp) {
             const usdVal = getConvertedAmount(t.amount, comp.currency);
             if (t.type === TransactionType.INCOME) mIncome += usdVal;
             else mExpense += usdVal;
          }
        }
      });

      data.push({
        name: d.toLocaleDateString('pt-PT', { month: 'short' }),
        Entradas: parseFloat(mIncome.toFixed(2)),
        Saídas: parseFloat(mExpense.toFixed(2)),
        Lucro: parseFloat((mIncome - mExpense).toFixed(2))
      });
    }
    return data;
  }, [transactions, companies, rates]);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Visão Geral (USD Estimado)</h2>
        <div className="text-sm text-slate-500">Valores convertidos para USD para agregação</div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Receita Total</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                ${totals.income.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
              <ArrowUpCircle className="w-6 h-6 text-emerald-600 dark:text-emerald-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Despesas Totais</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                ${totals.expense.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-rose-100 dark:bg-rose-900/30 rounded-lg">
              <ArrowDownCircle className="w-6 h-6 text-rose-600 dark:text-rose-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Lucro Líquido</p>
              <h3 className={`text-2xl font-bold mt-1 ${totals.profit >= 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-rose-600 dark:text-rose-400'}`}>
                ${totals.profit.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
              <DollarSign className="w-6 h-6 text-blue-600 dark:text-blue-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 cursor-pointer hover:shadow-md transition-shadow" onClick={() => onNavigate('companies')}>
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Empresas Ativas</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                {companies.filter(c => c.status === 'Ativo').length}
              </h3>
            </div>
            <div className="p-2 bg-purple-100 dark:bg-purple-900/30 rounded-lg">
              <Briefcase className="w-6 h-6 text-purple-600 dark:text-purple-400" />
            </div>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <h3 className="text-lg font-semibold text-slate-800 dark:text-white mb-4">Fluxo de Caixa (Últimos 6 meses)</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#374151" opacity={0.1} />
                <XAxis dataKey="name" stroke="#6b7280" />
                <YAxis stroke="#6b7280" />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }}
                  itemStyle={{ color: '#f8fafc' }}
                />
                <Legend />
                <Bar dataKey="Entradas" fill="#10b981" radius={[4, 4, 0, 0]} />
                <Bar dataKey="Saídas" fill="#ef4444" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <h3 className="text-lg font-semibold text-slate-800 dark:text-white mb-4">Acesso Rápido</h3>
          <div className="flex flex-col space-y-3">
             <button 
                onClick={() => onNavigate('companies')}
                className="w-full py-3 px-4 bg-slate-50 dark:bg-slate-700 hover:bg-slate-100 dark:hover:bg-slate-600 rounded-lg text-left text-sm font-medium transition-colors text-slate-700 dark:text-slate-200 flex items-center gap-2">
                <Briefcase size={16} /> Gerir Empresas
             </button>
             <button 
                onClick={() => onNavigate('month-detail')}
                className="w-full py-3 px-4 bg-brand-50 dark:bg-brand-900/20 hover:bg-brand-100 dark:hover:bg-brand-900/30 rounded-lg text-left text-sm font-medium transition-colors text-brand-700 dark:text-brand-300 flex items-center gap-2">
                <DollarSign size={16} /> Lançar Transação
             </button>
             <div className="p-4 rounded-lg bg-amber-50 dark:bg-amber-900/10 border border-amber-100 dark:border-amber-800 mt-4">
               <h4 className="text-amber-800 dark:text-amber-200 text-sm font-bold mb-1">Dica do Dia</h4>
               <p className="text-xs text-amber-700 dark:text-amber-300">
                 Mantenha o controle de despesas invisíveis (taxas bancárias, assinaturas esquecidas) para aumentar seu Lucro Real.
               </p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Company, Currency, CompanyStatus } from '../types';
import { Plus, Edit2, Trash2, Building, Check } from 'lucide-react';

interface CompanyManagerProps {
  companies: Company[];
  onSave: (company: Company) => void;
  onDelete: (id: string) => void;
}

export const CompanyManager: React.FC<CompanyManagerProps> = ({ companies, onSave, onDelete }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCompany, setCurrentCompany] = useState<Partial<Company>>({});

  const handleEdit = (company?: Company) => {
    if (company) {
      setCurrentCompany({ ...company });
    } else {
      setCurrentCompany({
        name: '',
        industry: '',
        currency: Currency.AOA,
        status: CompanyStatus.ACTIVE,
      });
    }
    setIsEditing(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (currentCompany.name && currentCompany.currency) {
      onSave({
        id: currentCompany.id || Math.random().toString(36).substr(2, 9),
        name: currentCompany.name,
        industry: currentCompany.industry || 'Geral',
        currency: currentCompany.currency as Currency,
        status: currentCompany.status as CompanyStatus,
        createdAt: currentCompany.createdAt || Date.now()
      });
      setIsEditing(false);
    }
  };

  if (isEditing) {
    return (
      <div className="max-w-xl mx-auto bg-white dark:bg-slate-800 p-8 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">
        <h2 className="text-xl font-bold mb-6 text-slate-800 dark:text-white flex items-center gap-2">
          <Building className="text-brand-500" />
          {currentCompany.id ? 'Editar Empresa' : 'Nova Empresa'}
        </h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Nome da Empresa</label>
            <input
              type="text"
              required
              value={currentCompany.name || ''}
              onChange={(e) => setCurrentCompany({ ...currentCompany, name: e.target.value })}
              className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="Ex: Agência Criativa"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Área de Atuação</label>
              <input
                type="text"
                value={currentCompany.industry || ''}
                onChange={(e) => setCurrentCompany({ ...currentCompany, industry: e.target.value })}
                className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none"
                placeholder="Ex: Marketing"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Moeda Padrão</label>
              <select
                value={currentCompany.currency}
                onChange={(e) => setCurrentCompany({ ...currentCompany, currency: e.target.value as Currency })}
                className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none"
              >
                {Object.values(Currency).map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Status</label>
            <div className="flex gap-4">
              {Object.values(CompanyStatus).map(s => (
                 <label key={s} className="flex items-center gap-2 cursor-pointer">
                    <input 
                      type="radio" 
                      name="status"
                      checked={currentCompany.status === s}
                      onChange={() => setCurrentCompany({...currentCompany, status: s})}
                      className="text-brand-600 focus:ring-brand-500"
                    />
                    <span className="text-sm text-slate-700 dark:text-slate-300">{s}</span>
                 </label>
              ))}
            </div>
          </div>

          <div className="flex justify-end gap-3 mt-6">
            <button
              type="button"
              onClick={() => setIsEditing(false)}
              className="px-4 py-2 rounded-lg text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="px-6 py-2 rounded-lg bg-brand-600 hover:bg-brand-700 text-white font-medium flex items-center gap-2 shadow-lg shadow-brand-500/30"
            >
              <Check size={18} /> Salvar Empresa
            </button>
          </div>
        </form>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Gerir Empresas</h2>
        <button
          onClick={() => handleEdit()}
          className="flex items-center gap-2 px-4 py-2 bg-brand-600 hover:bg-brand-700 text-white rounded-lg transition-all shadow-md"
        >
          <Plus size={18} /> Nova Empresa
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {companies.map(company => (
          <div key={company.id} className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-all relative group">
            <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => handleEdit(company)} className="p-1.5 text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-md">
                <Edit2 size={16} />
              </button>
              <button onClick={() => onDelete(company.id)} className="p-1.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-md">
                <Trash2 size={16} />
              </button>
            </div>

            <div className="flex items-center gap-3 mb-4">
              <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center text-slate-600 dark:text-slate-300 font-bold text-lg">
                {company.name.charAt(0)}
              </div>
              <div>
                <h3 className="font-bold text-slate-800 dark:text-white">{company.name}</h3>
                <p className="text-xs text-slate-500 dark:text-slate-400">{company.industry}</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4 text-sm">
              <div className="bg-slate-50 dark:bg-slate-900/50 p-2 rounded">
                <span className="block text-xs text-slate-400">Moeda</span>
                <span className="font-semibold text-slate-700 dark:text-slate-200">{company.currency}</span>
              </div>
              <div className="bg-slate-50 dark:bg-slate-900/50 p-2 rounded">
                <span className="block text-xs text-slate-400">Status</span>
                <span className={`font-semibold ${
                  company.status === CompanyStatus.ACTIVE ? 'text-emerald-500' :
                  company.status === CompanyStatus.PAUSED ? 'text-amber-500' : 'text-rose-500'
                }`}>
                  {company.status}
                </span>
              </div>
            </div>
          </div>
        ))}

        {companies.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-xl">
             <Building className="mx-auto w-12 h-12 mb-3 opacity-50" />
             <p>Nenhuma empresa cadastrada.</p>
             <button onClick={() => handleEdit()} className="text-brand-500 font-medium hover:underline mt-2">Começar agora</button>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Company, Transaction, TransactionType, MonthlyNote } from '../types';
