            onChange={(e) => setNewCategoryName(e.target.value)}
            placeholder={`Nova categoria de ${activeTab === TransactionType.INCOME ? 'Entrada' : 'Despesa'}...`}
            className="flex-1 p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
          />
          <button
            type="submit"
            disabled={!newCategoryName.trim()}
            className="px-6 py-3 bg-brand-600 hover:bg-brand-700 disabled:opacity-50 text-white font-medium rounded-lg flex items-center gap-2 transition-colors"
          >
            <Plus size={18} /> Adicionar
          </button>
        </form>

        {/* List */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {filteredCategories.map(category => (
            <div 
              key={category.id} 
              className="flex items-center justify-between p-4 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 group hover:border-brand-300 dark:hover:border-slate-600 transition-colors"
            >
              {editingId === category.id ? (
                <div className="flex items-center gap-2 w-full">
                  <input
                    type="text"
                    value={editName}
                    onChange={(e) => setEditName(e.target.value)}
                    className="flex-1 p-1.5 text-sm rounded border border-brand-500 bg-white dark:bg-slate-800 outline-none text-slate-900 dark:text-white"
                    autoFocus
                  />
                  <button onClick={saveEdit} className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded"><Check size={16} /></button>
                  <button onClick={() => setEditingId(null)} className="p-1.5 text-slate-400 hover:bg-slate-100 rounded"><X size={16} /></button>
                </div>
              ) : (
                <>
                  <span className="font-medium text-slate-700 dark:text-slate-200">{category.name}</span>
                  <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button 
                      onClick={() => startEdit(category)}
                      className="p-1.5 text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded"
                      title="Renomear (atualiza transações existentes)"
                    >
                      <Edit2 size={16} />
                    </button>
                    <button 
                      onClick={() => onDelete(category.id)}
                      className="p-1.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded"
                      title="Eliminar"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </>
              )}
            </div>
          ))}

          {filteredCategories.length === 0 && (
            <div className="col-span-full py-8 text-center text-slate-400 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-lg">
              <p>Nenhuma categoria cadastrada.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Company, Transaction, TransactionType, MonthlyNote, CategoryItem } from '../types';
import { Plus, Trash2, TrendingUp, TrendingDown, AlertTriangle, Sparkles, FileText } from 'lucide-react';
import { generateFinancialAnalysis } from '../services/geminiService';

interface MonthDetailProps {
  companies: Company[];
  transactions: Transaction[];
  notes: MonthlyNote[];
  categories: CategoryItem[];
  onAddTransaction: (t: Transaction) => void;
  onDeleteTransaction: (id: string) => void;
  onSaveNote: (note: MonthlyNote) => void;
  onAutoAddCategory: (name: string, type: TransactionType) => void;
}

export const MonthDetail: React.FC<MonthDetailProps> = ({ 
  companies, 
  transactions, 
  notes,
  categories,
  onAddTransaction, 
  onDeleteTransaction,
  onSaveNote,
  onAutoAddCategory
}) => {
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>(companies[0]?.id || '');
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7)); // YYYY-MM
  const [activeTab, setActiveTab] = useState<'income' | 'expense'>('income');

  // Transaction Form State
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState('');
  const [desc, setDesc] = useState('');
  const [isFixed, setIsFixed] = useState(false);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  // AI Loading State
  const [aiLoading, setAiLoading] = useState(false);

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // Filter categories for autocomplete based on active tab
  const availableCategories = useMemo(() => {
    const type = activeTab === 'income' ? TransactionType.INCOME : TransactionType.EXPENSE;
    return categories.filter(c => c.type === type);
  }, [categories, activeTab]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => 
      t.companyId === selectedCompanyId && 
      t.date.startsWith(selectedMonth)
    );
  }, [transactions, selectedCompanyId, selectedMonth]);

  const stats = useMemo(() => {
    const income = filteredTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0);
    const expense = filteredTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0);
    const profit = income - expense;
    const margin = income > 0 ? (profit / income) * 100 : 0;

    // Lucro Real (Simulação: Descontando 10% de 'custos invisíveis' ou impostos não lançados)
    const realProfit = profit * 0.90; 

    return { income, expense, profit, margin, realProfit };
  }, [filteredTransactions]);

  const currentNote = notes.find(n => n.companyId === selectedCompanyId && n.monthStr === selectedMonth);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    const type = activeTab === 'income' ? TransactionType.INCOME : TransactionType.EXPENSE;

    // Check if category exists, if not, save it for future reuse
    const categoryExists = categories.some(c => c.name.toLowerCase() === category.toLowerCase() && c.type === type);
    if (!categoryExists) {
      onAutoAddCategory(category, type);
    }

    const newTransaction: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: type,
      amount: parseFloat(amount),
      category: category, // Saves the string
      date,
      description: desc,
      isFixed: activeTab === 'expense' ? isFixed : undefined
    };

    onAddTransaction(newTransaction);
    setAmount('');
    setDesc('');
    setCategory(''); 
  };

  const handleAIAnalysis = async () => {
    if (!selectedCompany) return;
    setAiLoading(true);
    const analysis = await generateFinancialAnalysis(selectedCompany, filteredTransactions, selectedMonth);

    const newNote: MonthlyNote = {
      id: currentNote?.id || Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      monthStr: selectedMonth,
      note: currentNote?.note || '',
      aiAnalysis: analysis
    };
    onSaveNote(newNote);
    setAiLoading(false);
  };

  if (!selectedCompany) return <div className="p-8 text-center text-slate-500">Selecione ou crie uma empresa primeiro.</div>;

  return (
    <div className="space-y-6">
      {/* Top Controls */}
      <div className="flex flex-col md:flex-row gap-4 justify-between bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm">
        <div className="flex flex-col md:flex-row gap-4">
          <div>
            <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 mb-1 uppercase tracking-wider">Empresa</label>
            <select 
              value={selectedCompanyId} 
              onChange={(e) => setSelectedCompanyId(e.target.value)}
              className="bg-slate-50 dark:bg-slate-700 border-none rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 dark:text-white focus:ring-2 focus:ring-brand-500"
            >
              {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 mb-1 uppercase tracking-wider">Mês de Referência</label>
            <input 
              type="month" 
              value={selectedMonth} 
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-slate-50 dark:bg-slate-700 border-none rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 dark:text-white focus:ring-2 focus:ring-brand-500"
            />
          </div>
        </div>
      </div>

      {/* Main Stats for Month */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-emerald-50 dark:bg-emerald-900/20 p-4 rounded-xl border border-emerald-100 dark:border-emerald-900/30">
          <span className="text-emerald-600 dark:text-emerald-400 text-xs font-bold uppercase">Entradas</span>
          <div className="text-xl font-bold text-emerald-700 dark:text-emerald-300 mt-1">
             {selectedCompany.currency} {stats.income.toLocaleString()}
          </div>
        </div>
        <div className="bg-rose-50 dark:bg-rose-900/20 p-4 rounded-xl border border-rose-100 dark:border-rose-900/30">
          <span className="text-rose-600 dark:text-rose-400 text-xs font-bold uppercase">Saídas</span>
          <div className="text-xl font-bold text-rose-700 dark:text-rose-300 mt-1">
             {selectedCompany.currency} {stats.expense.toLocaleString()}
          </div>
        </div>
        <div className="bg-slate-50 dark:bg-slate-700/50 p-4 rounded-xl border border-slate-100 dark:border-slate-600">
          <span className="text-slate-500 dark:text-slate-400 text-xs font-bold uppercase">Lucro Líquido</span>
          <div className={`text-xl font-bold mt-1 ${stats.profit >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
             {selectedCompany.currency} {stats.profit.toLocaleString()}
          </div>
        </div>
        <div className="bg-purple-50 dark:bg-purple-900/20 p-4 rounded-xl border border-purple-100 dark:border-purple-900/30 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-1 opacity-10 group-hover:opacity-20">
            <Sparkles className="w-12 h-12 text-purple-600" />
          </div>
          <span className="text-purple-600 dark:text-purple-400 text-xs font-bold uppercase">Lucro Real (Est.)</span>
          <div className="text-xl font-bold text-purple-700 dark:text-purple-300 mt-1">
             {selectedCompany.currency} {stats.realProfit.toLocaleString()}
          </div>
          <div className="text-[10px] text-purple-400 mt-1">Margem: {stats.margin.toFixed(1)}%</div>
        </div>
      </div>

      {/* Transaction Entry Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Form */}
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
          <div className="flex border-b border-slate-100 dark:border-slate-700">
            <button 
              onClick={() => { setActiveTab('income'); setCategory(''); }}
              className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 ${activeTab === 'income' ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 border-b-2 border-emerald-500' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
            >
              <TrendingUp size={16} /> Receita
            </button>
            <button 
              onClick={() => { setActiveTab('expense'); setCategory(''); }}
              className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 ${activeTab === 'expense' ? 'bg-rose-50 dark:bg-rose-900/20 text-rose-600 border-b-2 border-rose-500' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
            >
              <TrendingDown size={16} /> Despesa
            </button>
          </div>

          <form onSubmit={handleAdd} className="p-6 space-y-4">
            <div>
              <label className="block text-xs text-slate-500 mb-1">Valor</label>
              <div className="relative">
                <span className="absolute left-3 top-2.5 text-slate-400 font-bold text-sm">{selectedCompany.currency}</span>
                <input 
                  type="number" 
                  value={amount} 
                  onChange={e => setAmount(e.target.value)} 
                  className="w-full pl-12 pr-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                  placeholder="0.00"
                  step="0.01"
                  required
                />
              </div>
            </div>

            <div>
              <label className="block text-xs text-slate-500 mb-1">Data</label>
              <input 
                type="date"
                value={date}
                onChange={e => setDate(e.target.value)}
                className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                required
              />
            </div>

            <div>
              <label className="block text-xs text-slate-500 mb-1">Categoria (Digite para criar ou selecione)</label>
              <input 
                list="category-options"
                type="text"
                value={category}
                onChange={e => setCategory(e.target.value)}
                className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                placeholder="Ex: Consultoria, Combustível..."
                required
                autoComplete="off"
              />
              <datalist id="category-options">
                {availableCategories.map(c => (
                  <option key={c.id} value={c.name} />
                ))}
              </datalist>
            </div>

            <div>
              <label className="block text-xs text-slate-500 mb-1">Descrição (Opcional)</label>
              <input 
                type="text" 
                value={desc} 
                onChange={e => setDesc(e.target.value)} 
                className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                placeholder="Ex: Cliente X, Fatura #123"
              />
            </div>

            {activeTab === 'expense' && (
              <label className="flex items-center gap-2 cursor-pointer">
                <input 
                  type="checkbox" 
                  checked={isFixed} 
                  onChange={e => setIsFixed(e.target.checked)}
                  className="rounded text-brand-600 focus:ring-brand-500" 
                />
                <span className="text-sm text-slate-600 dark:text-slate-300">Despesa Fixa (Recorrente)</span>
              </label>
            )}

            <button type="submit" className={`w-full py-3 rounded-lg font-bold text-white shadow-lg transition-transform active:scale-95 ${activeTab === 'income' ? 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-500/30' : 'bg-rose-500 hover:bg-rose-600 shadow-rose-500/30'}`}>
              <Plus className="inline mr-2 w-4 h-4" /> 
              {activeTab === 'income' ? 'Registrar Entrada' : 'Registrar Saída'}
            </button>
          </form>
        </div>

        {/* List & AI */}
        <div className="lg:col-span-2 space-y-6">

          {/* List */}
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 p-4 min-h-[400px]">
            <h3 className="font-bold text-slate-800 dark:text-white mb-4">Lançamentos de {selectedMonth}</h3>

            {filteredTransactions.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                <FileText className="w-12 h-12 mb-2 opacity-50" />
                <p>Nenhum lançamento neste mês.</p>
              </div>
            ) : (
              <div className="space-y-3 max-h-[500px] overflow-y-auto pr-2">
                {filteredTransactions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(t => (
                  <div key={t.id} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-900/50 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-900 transition-colors group">
                    <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-full ${t.type === TransactionType.INCOME ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>
                        {t.type === TransactionType.INCOME ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800 dark:text-white">{t.category}</p>
                        <p className="text-xs text-slate-500">{t.description || '-'} • {new Date(t.date).toLocaleDateString('pt-PT')}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className={`font-bold ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {t.type === TransactionType.INCOME ? '+' : '-'} {t.amount.toLocaleString()}
                      </span>
                      <button onClick={() => onDeleteTransaction(t.id)} className="text-slate-400 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* AI Strategy Section */}
          <div className="bg-indigo-50 dark:bg-indigo-950/30 rounded-xl border border-indigo-100 dark:border-indigo-900 p-6">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-indigo-900 dark:text-indigo-200 flex items-center gap-2">
                <Sparkles className="text-indigo-500" size={20} /> Inteligência Financeira
              </h3>
              <button 
                onClick={handleAIAnalysis}
                disabled={aiLoading}
                className="px-3 py-1.5 bg-indigo-600 text-white text-xs font-bold rounded-lg hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2"
              >
                {aiLoading ? 'Analisando...' : 'Gerar Análise'}
              </button>
            </div>

            {currentNote?.aiAnalysis ? (
              <div className="prose prose-sm dark:prose-invert max-w-none text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-900/50 p-4 rounded-lg border border-indigo-100 dark:border-indigo-900/50 whitespace-pre-line">
                {currentNote.aiAnalysis}
              </div>
            ) : (
              <div className="text-center py-6 text-indigo-400 dark:text-indigo-300/50 text-sm">
                Clique em "Gerar Análise" para receber insights sobre redução de custos e saúde financeira.
              </div>
            )}

            {/* Warning if loss */}
            {stats.profit < 0 && (
              <div className="mt-4 flex items-start gap-2 bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-200 p-3 rounded-lg text-sm">
                <AlertTriangle size={18} className="shrink-0 mt-0.5" />
                <p>Atenção: Este mês está no vermelho. Verifique as sugestões da IA para cortar custos fixos imediatamente.</p>
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Company, Transaction, MonthlyNote, ExchangeRates, ViewState, CategoryItem, TransactionType } from './types';
import { StorageService } from './services/storageService';
import { Dashboard } from './components/Dashboard';
import { CompanyManager } from './components/CompanyManager';
import { MonthDetail } from './components/MonthDetail';
import { Reports } from './components/Reports';
import { CategorySettings } from './components/CategorySettings';
import { LayoutDashboard, Building2, Calendar, FileBarChart, Settings, Menu, X, Sun, Moon, Tag } from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [companies, setCompanies] = useState<Company[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notes, setNotes] = useState<MonthlyNote[]>([]);
  const [rates, setRates] = useState<ExchangeRates>({});
  const [categories, setCategories] = useState<CategoryItem[]>([]);

  // UI State
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);

  // Initialization
  useEffect(() => {
    setCompanies(StorageService.getCompanies());
    setTransactions(StorageService.getTransactions());
    setNotes(StorageService.getNotes());
    setRates(StorageService.getRates());
    setCategories(StorageService.getCategories());

    // Check system preference for dark mode
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setIsDarkMode(true);
    }
  }, []);

  // Theme Toggle Effect
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // Handlers
  const handleSaveCompany = (company: Company) => {
    const exists = companies.find(c => c.id === company.id);
    let newCompanies;
    if (exists) {
      newCompanies = companies.map(c => c.id === company.id ? company : c);
    } else {
      newCompanies = [...companies, company];
    }
    setCompanies(newCompanies);
    StorageService.saveCompanies(newCompanies);
  };

  const handleDeleteCompany = (id: string) => {
    if (confirm('Tem certeza? Todas as transações desta empresa serão ocultas.')) {
      const newCompanies = companies.filter(c => c.id !== id);
      setCompanies(newCompanies);
      StorageService.saveCompanies(newCompanies);
      // Optional: Cascade delete transactions or keep them for history
    }
  };

  const handleAddTransaction = (t: Transaction) => {
    const newTransactions = [...transactions, t];
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleDeleteTransaction = (id: string) => {
    const newTransactions = transactions.filter(t => t.id !== id);
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleSaveNote = (note: MonthlyNote) => {
    // Remove existing note for that month/company if exists
    const filteredNotes = notes.filter(n => !(n.companyId === note.companyId && n.monthStr === note.monthStr));
    const newNotes = [...filteredNotes, note];
    setNotes(newNotes);
    StorageService.saveNotes(newNotes);
  };

  // Category Handlers
  const handleAddCategory = (name: string, type: TransactionType) => {
    // Avoid duplicates
    if (categories.some(c => c.name.toLowerCase() === name.toLowerCase() && c.type === type)) return;

    const newCategory: CategoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      type
    };
    const updatedCategories = [...categories, newCategory];
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);
  };

  const handleEditCategory = (id: string, newName: string) => {
    const oldCategory = categories.find(c => c.id === id);
    if (!oldCategory) return;

    // 1. Update Category List
    const updatedCategories = categories.map(c => c.id === id ? { ...c, name: newName } : c);
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);

    // 2. Update all associated transactions
    const updatedTransactions = transactions.map(t => 
      (t.category === oldCategory.name && t.type === oldCategory.type) 
        ? { ...t, category: newName } 
        : t
    );
    setTransactions(updatedTransactions);
    StorageService.saveTransactions(updatedTransactions);
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('Ao eliminar a categoria, ela deixará de aparecer nas sugestões, mas as transações antigas serão mantidas. Continuar?')) {
      const updatedCategories = categories.filter(c => c.id !== id);
      setCategories(updatedCategories);
      StorageService.saveCategories(updatedCategories);
    }
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => (
    <button
      onClick={() => { setCurrentView(view); setIsSidebarOpen(false); }}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
        currentView === view 
          ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' 
          : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
