import React, { useState } from 'react';
import { Company, Transaction, TransactionType } from '../types';
import { Download, FileText, Calendar, Building, Printer } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface ReportsProps {
  companies: Company[];
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ companies, transactions }) => {
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));

  const generatePDF = () => {
    const company = companies.find(c => c.id === selectedCompanyId);
    if (!company) return;

    // 1. Filtrar Dados
    const monthlyTransactions = transactions.filter(t => 
      t.companyId === selectedCompanyId && 
      t.date.startsWith(selectedMonth)
    );

    const income = monthlyTransactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + t.amount, 0);

    const expense = monthlyTransactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);

    const profit = income - expense;
    const margin = income > 0 ? ((profit / income) * 100).toFixed(2) : '0';

    // Agrupar por categoria
    const categorySummary: Record<string, { type: TransactionType, amount: number }> = {};
    monthlyTransactions.forEach(t => {
      if (!categorySummary[t.category]) {
        categorySummary[t.category] = { type: t.type, amount: 0 };
      }
      categorySummary[t.category].amount += t.amount;
    });

    // 2. Inicializar PDF
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.width;

    // -- CORES --
    const primaryColor = [14, 165, 233]; // Brand-500
    const profitColor = [16, 185, 129]; // Emerald
    const expenseColor = [239, 68, 68]; // Red
    const slateColor = [51, 65, 85]; // Slate-700

    // 3. Cabeçalho
    doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.rect(0, 0, pageWidth, 40, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("Relatório Financeiro Mensal", 14, 20);

    doc.setFontSize(12);
    doc.setFont("helvetica", "normal");
    doc.text(`Empresa: ${company.name}`, 14, 30);

    const [year, month] = selectedMonth.split('-');
    const dateStr = new Date(parseInt(year), parseInt(month)-1).toLocaleDateString('pt-PT', { month: 'long', year: 'numeric' });
    doc.text(`Período: ${dateStr}`, 14, 36);

    doc.setFontSize(10);
    doc.text("Gerado por: Na Rota do Lucro", pageWidth - 60, 36);

    let currentY = 50;

    // 4. Resumo Executivo (Cards)
    doc.setTextColor(slateColor[0], slateColor[1], slateColor[2]);
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text("Resumo Financeiro", 14, currentY);
    currentY += 10;

    const summaryData = [
      [`Receita Total`, `${company.currency} ${income.toLocaleString('pt-PT', { minimumFractionDigits: 2 })}`],
      [`Despesa Total`, `${company.currency} ${expense.toLocaleString('pt-PT', { minimumFractionDigits: 2 })}`],
      [`Lucro Líquido`, `${company.currency} ${profit.toLocaleString('pt-PT', { minimumFractionDigits: 2 })}`],
      [`Margem de Lucro`, `${margin}%`]
    ];

    autoTable(doc, {
      startY: currentY,
      head: [['Indicador', 'Valor']],
      body: summaryData,
      theme: 'grid',
      headStyles: { fillColor: [241, 245, 249], textColor: [51, 65, 85], fontStyle: 'bold' }, // Slate-100
      columnStyles: {
        0: { fontStyle: 'bold', cellWidth: 100 },
        1: { halign: 'right' }
      },
      styles: { fontSize: 11, cellPadding: 6 }
    });

    // @ts-ignore
    currentY = doc.lastAutoTable.finalY + 15;

    // 5. Detalhamento por Categoria (Top 5 Despesas)
    doc.text("Top Despesas por Categoria", 14, currentY);
    currentY += 8;

    const expenseCategories = Object.entries(categorySummary)
      .filter(([_, data]) => data.type === TransactionType.EXPENSE)
      .sort((a, b) => b[1].amount - a[1].amount)
      .map(([name, data]) => [name, `${company.currency} ${data.amount.toLocaleString('pt-PT', { minimumFractionDigits: 2 })}`]);

    if (expenseCategories.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Categoria', 'Total Gasto']],
        body: expenseCategories,
        theme: 'striped',
        headStyles: { fillColor: expenseColor, textColor: 255 },
        columnStyles: { 1: { halign: 'right' } }
      });
      // @ts-ignore
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(10);
      doc.setFont("helvetica", "italic");
      doc.text("Nenhuma despesa registrada neste período.", 14, currentY + 5);
      currentY += 15;
    }

    // 6. Tabela Completa de Transações
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.setTextColor(slateColor[0], slateColor[1], slateColor[2]);
    doc.text("Detalhamento de Transações", 14, currentY);
    currentY += 8;

    const rows = monthlyTransactions
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map(t => [
        new Date(t.date).toLocaleDateString('pt-PT'),
        t.category,
        t.description || '-',
        t.type === TransactionType.INCOME ? 'Entrada' : 'Saída',
        `${company.currency} ${t.amount.toLocaleString('pt-PT', { minimumFractionDigits: 2 })}`
      ]);

    autoTable(doc, {
      startY: currentY,
      head: [['Data', 'Categoria', 'Descrição', 'Tipo', 'Valor']],
      body: rows,
      theme: 'striped',
      headStyles: { fillColor: slateColor, textColor: 255 },
      columnStyles: {
        4: { halign: 'right', fontStyle: 'bold' }
      },
      didParseCell: function(data) {
        // Colorir o texto de Entrada/Saída
        if (data.section === 'body' && data.column.index === 3) {
            if (data.cell.raw === 'Entrada') {
                data.cell.styles.textColor = profitColor;
            } else {
                data.cell.styles.textColor = expenseColor;
            }
        }
      }
    });

    // 7. Salvar PDF
    const filename = `Relatorio_${company.name.replace(/\s+/g, '_')}_${selectedMonth}.pdf`;
    doc.save(filename);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="bg-white dark:bg-slate-800 p-8 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <Printer size={32} />
          </div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">Relatórios Oficiais</h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-lg mx-auto">
            Gere documentos PDF completos com análise financeira, totais por categoria e histórico detalhado para contabilidade ou gestão.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-2xl mx-auto bg-slate-50 dark:bg-slate-900/50 p-6 rounded-xl border border-slate-200 dark:border-slate-700">
          <div>
             <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
               <Building size={16} /> Empresa
             </label>
             <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
             >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
             </select>
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
               <Calendar size={16} /> Mês de Referência
             </label>
             <input 
               type="month" 
               value={selectedMonth} 
               onChange={(e) => setSelectedMonth(e.target.value)}
               className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
             />
          </div>

          <div className="md:col-span-2 pt-2">
            <button 
              onClick={generatePDF}
              className="w-full flex items-center justify-center gap-2 px-6 py-4 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg transition-all shadow-lg shadow-brand-500/20 active:scale-95"
            >
              <Download size={22} />
              Baixar Relatório Completo (PDF)
            </button>
            <p className="text-center text-xs text-slate-400 mt-3">
              O arquivo incluirá o resumo financeiro, análise de categorias e tabela de lançamentos.
            </p>
          </div>
        </div>
      </div>

      {/* Preview Section */}
      <div className="border-t border-slate-200 dark:border-slate-800 pt-8">
        <h3 className="text-lg font-semibold text-slate-700 dark:text-slate-300 mb-4 flex items-center gap-2">
          <FileText size={20} /> O que está incluído no relatório?
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
          <div className="p-4 bg-emerald-50 dark:bg-emerald-900/10 rounded-lg border border-emerald-100 dark:border-emerald-900/20">
            <span className="font-bold text-emerald-700 dark:text-emerald-400 block mb-1">Resumo Executivo</span>
            <p className="text-slate-600 dark:text-slate-400">Totais de entradas, saídas, lucro líquido real e margem de lucratividade do período.</p>
          </div>
          <div className="p-4 bg-blue-50 dark:bg-blue-900/10 rounded-lg border border-blue-100 dark:border-blue-900/20">
            <span className="font-bold text-blue-700 dark:text-blue-400 block mb-1">Análise por Categoria</span>
            <p className="text-slate-600 dark:text-slate-400">Agrupamento automático de gastos para identificar onde o dinheiro está sendo investido.</p>
          </div>
          <div className="p-4 bg-amber-50 dark:bg-amber-900/10 rounded-lg border border-amber-100 dark:border-amber-900/20">
            <span className="font-bold text-amber-700 dark:text-amber-400 block mb-1">Extrato Detalhado</span>
            <p className="text-slate-600 dark:text-slate-400">Lista cronológica de todas as transações com descrições e valores individuais.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates, Currency } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, DollarSign, Briefcase, PieChart as PieChartIcon, TrendingUp, CalendarClock, Calculator } from 'lucide-react';

interface DashboardProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

const COLORS = ['#0ea5e9', '#10b981', '#ef4444', '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ companies, transactions, rates, onNavigate }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));

  // Convert everything to USD for aggregate stats, strictly for the dashboard summary
  const getConvertedAmount = (amount: number, currency: Currency) => {
    const rate = rates[currency] || 1;
    return amount / rate;
  };

  const totals = useMemo(() => {
    let totalIncomeUSD = 0;
    let totalExpenseUSD = 0;

    const activeCompanies = companies.filter(c => c.status !== 'Encerrado');

    activeCompanies.forEach(company => {
      const companyTransactions = transactions.filter(t => t.companyId === company.id);

      const income = companyTransactions
        .filter(t => t.type === TransactionType.INCOME)
        .reduce((sum, t) => sum + t.amount, 0);

      const expense = companyTransactions
        .filter(t => t.type === TransactionType.EXPENSE)
        .reduce((sum, t) => sum + t.amount, 0);

      totalIncomeUSD += getConvertedAmount(income, company.currency);
      totalExpenseUSD += getConvertedAmount(expense, company.currency);
    });

    return {
      income: totalIncomeUSD,
      expense: totalExpenseUSD,
      profit: totalIncomeUSD - totalExpenseUSD
    };
  }, [companies, transactions, rates]);

  // Forecast Logic (Previsão para o Próximo Mês)
  const forecast = useMemo(() => {
    const activeCompanies = companies.filter(c => c.status !== 'Encerrado');
    const today = new Date();
    const currentMonthKey = today.toISOString().slice(0, 7);

    // Get keys for last 3 months for average calculation
    const pastMonths: string[] = [];
    for (let i = 1; i <= 3; i++) {
        const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
        pastMonths.push(d.toISOString().slice(0, 7));
    }

    let projectedIncomeUSD = 0;
    let projectedFixedExpenseUSD = 0;
    let projectedVariableExpenseUSD = 0;

    activeCompanies.forEach(company => {
        // 1. Calculate Average Income (Last 3 months)
        let totalPastIncome = 0;
        let monthsWithIncome = 0;

        pastMonths.forEach(m => {
            const monthlyIncome = transactions
                .filter(t => t.companyId === company.id && t.type === TransactionType.INCOME && t.date.startsWith(m))
                .reduce((acc, t) => acc + t.amount, 0);

            if (monthlyIncome > 0) {
                totalPastIncome += monthlyIncome;
                monthsWithIncome++;
            }
        });

        const avgIncome = monthsWithIncome > 0 ? totalPastIncome / monthsWithIncome : 0;
        projectedIncomeUSD += getConvertedAmount(avgIncome, company.currency);

        // 2. Fixed Expenses (Recurrent) - Based on CURRENT month
        // We assume what is fixed now will repeat next month
        const currentFixedExpenses = transactions
            .filter(t => t.companyId === company.id && t.type === TransactionType.EXPENSE && t.isFixed && t.date.startsWith(currentMonthKey))
            .reduce((acc, t) => acc + t.amount, 0);

        projectedFixedExpenseUSD += getConvertedAmount(currentFixedExpenses, company.currency);

        // 3. Variable Expenses (Average of last 3 months)
        let totalPastVariable = 0;
        let monthsWithVariable = 0;

        pastMonths.forEach(m => {
            const monthlyVariable = transactions
                .filter(t => t.companyId === company.id && t.type === TransactionType.EXPENSE && !t.isFixed && t.date.startsWith(m))
                .reduce((acc, t) => acc + t.amount, 0);

            if (monthlyVariable > 0) {
                totalPastVariable += monthlyVariable;
                monthsWithVariable++;
            }
        });

        const avgVariable = monthsWithVariable > 0 ? totalPastVariable / monthsWithVariable : 0;
        projectedVariableExpenseUSD += getConvertedAmount(avgVariable, company.currency);
    });

    const totalProjectedExpense = projectedFixedExpenseUSD + projectedVariableExpenseUSD;

    return {
        income: projectedIncomeUSD,
        expense: totalProjectedExpense,
        profit: projectedIncomeUSD - totalProjectedExpense,
        fixedShare: totalProjectedExpense > 0 ? (projectedFixedExpenseUSD / totalProjectedExpense) * 100 : 0
    };
  }, [companies, transactions, rates]);

  // Chart Data Preparation (Last 6 months simplified)
  const chartData = useMemo(() => {
    const data: any[] = [];
    const today = new Date();

    for (let i = 5; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const monthKey = d.toISOString().slice(0, 7); // YYYY-MM

      let mIncome = 0;
      let mExpense = 0;

      transactions.forEach(t => {
        if (t.date.startsWith(monthKey)) {
          const comp = companies.find(c => c.id === t.companyId);
          if (comp) {
             const usdVal = getConvertedAmount(t.amount, comp.currency);
             if (t.type === TransactionType.INCOME) mIncome += usdVal;
             else mExpense += usdVal;
          }
        }
      });

      data.push({
        name: d.toLocaleDateString('pt-PT', { month: 'short' }),
        Entradas: parseFloat(mIncome.toFixed(2)),
        Saídas: parseFloat(mExpense.toFixed(2)),
        Lucro: parseFloat((mIncome - mExpense).toFixed(2))
      });
    }
    return data;
  }, [transactions, companies, rates]);

  const pieData = useMemo(() => {
    const data: Record<string, number> = {};
    const activeCompanies = companies.filter(c => c.status !== 'Encerrado');
    const activeCompanyIds = activeCompanies.map(c => c.id);

    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(selectedMonth) && activeCompanyIds.includes(t.companyId)) {
         const comp = companies.find(c => c.id === t.companyId);
         if (comp) {
             const amountUSD = getConvertedAmount(t.amount, comp.currency);
             data[t.category] = (data[t.category] || 0) + amountUSD;
         }
      }
    });

    return Object.entries(data)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
  }, [transactions, companies, rates, selectedMonth]);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Visão Geral (USD Estimado)</h2>
        <div className="text-sm text-slate-500">Valores convertidos para USD para agregação</div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Receita Total</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                ${totals.income.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
              <ArrowUpCircle className="w-6 h-6 text-emerald-600 dark:text-emerald-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
