export default App;

export enum Currency {
  AOA = 'AOA', // Kwanza
  USD = 'USD', // Dólar
  EUR = 'EUR', // Euro
  BRL = 'BRL'  // Real (opcional)
}

export enum CompanyStatus {
  ACTIVE = 'Ativo',
  PAUSED = 'Pausado',
  CLOSED = 'Encerrado'
}

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE'
}

export interface Company {
  id: string;
  name: string;
  industry: string;
  currency: Currency;
  status: CompanyStatus;
  taxRate?: number; // Porcentagem estimada de impostos/custos sobre o lucro
  createdAt: number;
}

export interface Transaction {
  id: string;
  companyId: string;
  type: TransactionType;
  amount: number;
  category: string;
  date: string; // ISO Date string YYYY-MM-DD
  description?: string;
  isFixed?: boolean; // Para despesas
}

export interface MonthlyNote {
  id: string;
  companyId: string;
  monthStr: string; // YYYY-MM format
  note: string;
  aiAnalysis?: string;
}

export interface ExchangeRates {
  [key: string]: number; // Base is USD. e.g. { AOA: 900, EUR: 0.92, USD: 1 }
}

export interface CategoryItem {
  id: string;
  name: string;
  type: TransactionType;
}

export type ViewState = 'dashboard' | 'companies' | 'month-detail' | 'reports' | 'categories';

