            <select 
              value={selectedCompanyId} 
              onChange={(e) => setSelectedCompanyId(e.target.value)}
              className="bg-slate-50 dark:bg-slate-700 border-none rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 dark:text-white focus:ring-2 focus:ring-brand-500"
            >
              {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 mb-1 uppercase tracking-wider">Mês de Referência</label>
            <input 
              type="month" 
              value={selectedMonth} 
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-slate-50 dark:bg-slate-700 border-none rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 dark:text-white focus:ring-2 focus:ring-brand-500"
            />
