                />
                <span className="text-sm text-slate-600 dark:text-slate-300">Despesa Fixa (Recorrente)</span>
              </label>
            )}

            <button type="submit" className={`w-full py-3 rounded-lg font-bold text-white shadow-lg transition-transform active:scale-95 ${activeTab === 'income' ? 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-500/30' : 'bg-rose-500 hover:bg-rose-600 shadow-rose-500/30'}`}>
              <Plus className="inline mr-2 w-4 h-4" /> 
              {activeTab === 'income' ? 'Registrar Entrada' : 'Registrar Saída'}
            </button>
          </form>
        </div>

        {/* List & AI */}
        <div className="lg:col-span-2 space-y-6">

          {/* List */}
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 p-4 min-h-[400px]">
            <h3 className="font-bold text-slate-800 dark:text-white mb-4">Lançamentos de {selectedMonth}</h3>

            {filteredTransactions.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                <FileText className="w-12 h-12 mb-2 opacity-50" />
                <p>Nenhum lançamento neste mês.</p>
              </div>
            ) : (
              <div className="space-y-3 max-h-[500px] overflow-y-auto pr-2">
                {filteredTransactions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(t => (
                  <div key={t.id} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-900/50 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-900 transition-colors group">
                    <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-full ${t.type === TransactionType.INCOME ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>
                        {t.type === TransactionType.INCOME ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800 dark:text-white">{t.category}</p>
                        <p className="text-xs text-slate-500">{t.description || '-'} • {new Date(t.date).toLocaleDateString('pt-PT')}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className={`font-bold ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {t.type === TransactionType.INCOME ? '+' : '-'} {t.amount.toLocaleString()}
                      </span>
                      <button onClick={() => onDeleteTransaction(t.id)} className="text-slate-400 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* AI Strategy Section */}
          <div className="bg-indigo-50 dark:bg-indigo-950/30 rounded-xl border border-indigo-100 dark:border-indigo-900 p-6">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-indigo-900 dark:text-indigo-200 flex items-center gap-2">
                <Sparkles className="text-indigo-500" size={20} /> Inteligência Financeira
              </h3>
              <button 
                onClick={handleAIAnalysis}
                disabled={aiLoading}
                className="px-3 py-1.5 bg-indigo-600 text-white text-xs font-bold rounded-lg hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2"
              >
                {aiLoading ? 'Analisando...' : 'Gerar Análise'}
              </button>
            </div>

            {currentNote?.aiAnalysis ? (
              <div className="prose prose-sm dark:prose-invert max-w-none text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-900/50 p-4 rounded-lg border border-indigo-100 dark:border-indigo-900/50 whitespace-pre-line">
                {currentNote.aiAnalysis}
              </div>
            ) : (
              <div className="text-center py-6 text-indigo-400 dark:text-indigo-300/50 text-sm">
                Clique em "Gerar Análise" para receber insights sobre redução de custos e saúde financeira.
              </div>
            )}

            {/* Warning if loss */}
            {stats.profit < 0 && (
              <div className="mt-4 flex items-start gap-2 bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-200 p-3 rounded-lg text-sm">
                <AlertTriangle size={18} className="shrink-0 mt-0.5" />
                <p>Atenção: Este mês está no vermelho. Verifique as sugestões da IA para cortar custos fixos imediatamente.</p>
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates, Currency } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, DollarSign, Briefcase, PieChart as PieChartIcon, TrendingUp, CalendarClock, Calculator, Settings, X, Save } from 'lucide-react';
import { StorageService } from '../services/storageService';

interface DashboardProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

const COLORS = ['#0ea5e9', '#10b981', '#ef4444', '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ companies, transactions, rates: initialRates, onNavigate }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));
  const [isRateModalOpen, setIsRateModalOpen] = useState(false);
  const [currentRates, setCurrentRates] = useState<ExchangeRates>(initialRates);

  const handleSaveRates = () => {
    StorageService.saveRates(currentRates);
    setIsRateModalOpen(false);
    // Force reload via parent is complex here without context, but since rates come from parent props (initially), 
    // ideally the parent should manage this. For now, we update local logic, but in a real app, we'd lift this state up fully.
    // The App.tsx passes `rates` which are loaded from storage. Since we saved to storage, a reload works, 
    // or we can just rely on the fact that App.tsx might need a callback to update its state.
    // For this implementation, we will assume the visual update relies on `currentRates` for the moment 
    // or we just reload the page to be safe if `onRateChange` isn't provided.
    window.location.reload(); 
  };

  // Use currentRates instead of props rates for immediate feedback if we lifted state, 
  // but since we refresh on save, props.rates is fine after reload.
  const activeRates = currentRates;

  // Convert everything to USD for aggregate stats, strictly for the dashboard summary
  const getConvertedAmount = (amount: number, currency: Currency) => {
    const rate = activeRates[currency] || 1;
    return amount / rate;
  };

  const totals = useMemo(() => {
    let totalIncomeUSD = 0;
    let totalExpenseUSD = 0;

    const activeCompanies = companies.filter(c => c.status !== 'Encerrado');

    activeCompanies.forEach(company => {
      const companyTransactions = transactions.filter(t => t.companyId === company.id);

      const income = companyTransactions
        .filter(t => t.type === TransactionType.INCOME)
        .reduce((sum, t) => sum + t.amount, 0);

      const expense = companyTransactions
        .filter(t => t.type === TransactionType.EXPENSE)
        .reduce((sum, t) => sum + t.amount, 0);

      totalIncomeUSD += getConvertedAmount(income, company.currency);
      totalExpenseUSD += getConvertedAmount(expense, company.currency);
    });

    return {
      income: totalIncomeUSD,
      expense: totalExpenseUSD,
      profit: totalIncomeUSD - totalExpenseUSD
    };
  }, [companies, transactions, activeRates]);

  // Forecast Logic (Previsão para o Próximo Mês)
  const forecast = useMemo(() => {
    const activeCompanies = companies.filter(c => c.status !== 'Encerrado');
    const today = new Date();
    const currentMonthKey = today.toISOString().slice(0, 7);

    // Get keys for last 3 months for average calculation
    const pastMonths: string[] = [];
    for (let i = 1; i <= 3; i++) {
        const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
        pastMonths.push(d.toISOString().slice(0, 7));
    }

    let projectedIncomeUSD = 0;
    let projectedFixedExpenseUSD = 0;
    let projectedVariableExpenseUSD = 0;

    activeCompanies.forEach(company => {
        // 1. Calculate Average Income (Last 3 months)
        let totalPastIncome = 0;
        let monthsWithIncome = 0;

        pastMonths.forEach(m => {
            const monthlyIncome = transactions
                .filter(t => t.companyId === company.id && t.type === TransactionType.INCOME && t.date.startsWith(m))
                .reduce((acc, t) => acc + t.amount, 0);

            if (monthlyIncome > 0) {
                totalPastIncome += monthlyIncome;
                monthsWithIncome++;
            }
        });

        const avgIncome = monthsWithIncome > 0 ? totalPastIncome / monthsWithIncome : 0;
        projectedIncomeUSD += getConvertedAmount(avgIncome, company.currency);

        // 2. Fixed Expenses (Recurrent) - Based on CURRENT month
        // We assume what is fixed now will repeat next month
        const currentFixedExpenses = transactions
            .filter(t => t.companyId === company.id && t.type === TransactionType.EXPENSE && t.isFixed && t.date.startsWith(currentMonthKey))
            .reduce((acc, t) => acc + t.amount, 0);

        projectedFixedExpenseUSD += getConvertedAmount(currentFixedExpenses, company.currency);

        // 3. Variable Expenses (Average of last 3 months)
        let totalPastVariable = 0;
        let monthsWithVariable = 0;

        pastMonths.forEach(m => {
            const monthlyVariable = transactions
                .filter(t => t.companyId === company.id && t.type === TransactionType.EXPENSE && !t.isFixed && t.date.startsWith(m))
                .reduce((acc, t) => acc + t.amount, 0);

            if (monthlyVariable > 0) {
                totalPastVariable += monthlyVariable;
                monthsWithVariable++;
            }
        });

        const avgVariable = monthsWithVariable > 0 ? totalPastVariable / monthsWithVariable : 0;
        projectedVariableExpenseUSD += getConvertedAmount(avgVariable, company.currency);
    });

    const totalProjectedExpense = projectedFixedExpenseUSD + projectedVariableExpenseUSD;

    return {
        income: projectedIncomeUSD,
        expense: totalProjectedExpense,
        profit: projectedIncomeUSD - totalProjectedExpense,
        fixedShare: totalProjectedExpense > 0 ? (projectedFixedExpenseUSD / totalProjectedExpense) * 100 : 0
    };
  }, [companies, transactions, activeRates]);

  // Chart Data Preparation (Last 6 months simplified)
  const chartData = useMemo(() => {
    const data: any[] = [];
    const today = new Date();

    for (let i = 5; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const monthKey = d.toISOString().slice(0, 7); // YYYY-MM

      let mIncome = 0;
      let mExpense = 0;

      transactions.forEach(t => {
        if (t.date.startsWith(monthKey)) {
          const comp = companies.find(c => c.id === t.companyId);
          if (comp) {
             const usdVal = getConvertedAmount(t.amount, comp.currency);
             if (t.type === TransactionType.INCOME) mIncome += usdVal;
             else mExpense += usdVal;
          }
        }
      });

      data.push({
        name: d.toLocaleDateString('pt-PT', { month: 'short' }),
        Entradas: parseFloat(mIncome.toFixed(2)),
        Saídas: parseFloat(mExpense.toFixed(2)),
        Lucro: parseFloat((mIncome - mExpense).toFixed(2))
      });
    }
    return data;
  }, [transactions, companies, activeRates]);

  const pieData = useMemo(() => {
    const data: Record<string, number> = {};
    const activeCompanies = companies.filter(c => c.status !== 'Encerrado');
    const activeCompanyIds = activeCompanies.map(c => c.id);

    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(selectedMonth) && activeCompanyIds.includes(t.companyId)) {
         const comp = companies.find(c => c.id === t.companyId);
         if (comp) {
             const amountUSD = getConvertedAmount(t.amount, comp.currency);
             data[t.category] = (data[t.category] || 0) + amountUSD;
         }
      }
    });

    return Object.entries(data)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
  }, [transactions, companies, activeRates, selectedMonth]);

  return (
    <div className="space-y-6 animate-fade-in relative">

      {/* Settings Modal */}
      {isRateModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl max-w-md w-full p-6 animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                <Settings className="text-brand-500" /> Taxas de Câmbio
              </h3>
              <button onClick={() => setIsRateModalOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                <X size={24} />
              </button>
            </div>

            <p className="text-sm text-slate-500 dark:text-slate-400 mb-4">
              Defina quantos da moeda local equivalem a 1 USD (Dólar). Usado apenas para visualização unificada no Dashboard.
            </p>

            <div className="space-y-4">
              {Object.keys(currentRates).filter(k => k !== 'USD').map(currency => (
                <div key={currency}>
                  <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                    1 USD = ? {currency}
                  </label>
                  <input 
                    type="number" 
                    step="0.01"
                    value={currentRates[currency]}
                    onChange={(e) => setCurrentRates({...currentRates, [currency]: parseFloat(e.target.value)})}
                    className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                  />
                </div>
              ))}
            </div>

            <div className="mt-8 flex justify-end gap-3">
              <button onClick={() => setIsRateModalOpen(false)} className="px-4 py-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">Cancelar</button>
              <button onClick={handleSaveRates} className="px-4 py-2 bg-brand-600 text-white rounded-lg hover:bg-brand-700 flex items-center gap-2">
                <Save size={18} /> Salvar & Atualizar
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Visão Geral (USD Estimado)</h2>
           <div className="text-sm text-slate-500">Valores consolidados em Dólar.</div>
        </div>
        <button 
          onClick={() => setIsRateModalOpen(true)}
          className="flex items-center gap-2 px-3 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg text-sm font-medium text-slate-600 dark:text-slate-300 transition-colors"
        >
          <Settings size={16} /> Configurar Câmbio
        </button>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
