  onNavigate: (view: any) => void;
}

const COLORS = ['#0ea5e9', '#10b981', '#ef4444', '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ companies, transactions, rates: initialRates, onNavigate }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));
  const [isRateModalOpen, setIsRateModalOpen] = useState(false);
  const [currentRates, setCurrentRates] = useState<ExchangeRates>(initialRates);

  const handleSaveRates = () => {
    StorageService.saveRates(currentRates);
    setIsRateModalOpen(false);
    window.location.reload(); 
  };

  const activeRates = currentRates;

  // 1. OTIMIZAÇÃO: Criar um Mapa de Empresas Ativas para acesso O(1)
  // Evita ter que fazer .find() no array de empresas para cada transação
  const activeCompanyMap = useMemo(() => {
    const map = new Map<string, Company>();
    companies.forEach(c => {
      if (c.status !== 'Encerrado') {
        map.set(c.id, c);
      }
    });
    return map;
  }, [companies]);

  // Helper para conversão (dentro do escopo para usar activeRates)
  const getConvertedAmount = (amount: number, currency: Currency) => {
    const rate = activeRates[currency] || 1;
    return amount / rate;
  };

  // 2. OTIMIZAÇÃO: Cálculo de Totais em uma única passada (O(N) transactions)
  const totals = useMemo(() => {
    let totalIncomeUSD = 0;
    let totalExpenseUSD = 0;

    transactions.forEach(t => {
      const company = activeCompanyMap.get(t.companyId);
      if (!company) return; // Ignora transações de empresas encerradas ou inexistentes

      const usdValue = getConvertedAmount(t.amount, company.currency);

      if (t.type === TransactionType.INCOME) {
        totalIncomeUSD += usdValue;
      } else {
        totalExpenseUSD += usdValue;
      }
    });

    return {
      income: totalIncomeUSD,
      expense: totalExpenseUSD,
      profit: totalIncomeUSD - totalExpenseUSD
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // 3. OTIMIZAÇÃO: Forecast (Previsão)
  const forecast = useMemo(() => {
    const today = new Date();
    const currentMonthKey = today.toISOString().slice(0, 7);

    // Gerar chaves dos últimos 3 meses
    const pastMonthsSet = new Set<string>();
    for (let i = 1; i <= 3; i++) {
        const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
        pastMonthsSet.add(d.toISOString().slice(0, 7));
    }

    // Estrutura temporária para acumular dados por empresa
    // Stats: { [companyId]: { incomeSum: 0, incomeMonths: Set(), fixedSum: 0, variableSum: 0, variableMonths: Set() } }
    const companyStats = new Map<string, {
      incomeSum: number;
      incomeMonths: Set<string>;
      fixedSum: number; // Apenas do mês atual
      variableSum: number;
      variableMonths: Set<string>;
    }>();

    // Inicializar mapa com empresas ativas
    activeCompanyMap.forEach((_, id) => {
      companyStats.set(id, {
        incomeSum: 0,
        incomeMonths: new Set(),
        fixedSum: 0,
        variableSum: 0,
        variableMonths: new Set()
      });
    });

    // Passada única nas transações
    transactions.forEach(t => {
      const stats = companyStats.get(t.companyId);
      if (!stats) return; // Empresa não ativa

      const monthKey = t.date.slice(0, 7);

      // Lógica de Receita (Últimos 3 meses)
      if (t.type === TransactionType.INCOME && pastMonthsSet.has(monthKey)) {
        stats.incomeSum += t.amount;
        stats.incomeMonths.add(monthKey);
      }

      // Lógica de Despesa
      if (t.type === TransactionType.EXPENSE) {
        // Fixa: Considera apenas o mês atual (projecao de recorrencia)
        if (t.isFixed && monthKey === currentMonthKey) {
          stats.fixedSum += t.amount;
        }
        // Variável: Média dos últimos 3 meses
        if (!t.isFixed && pastMonthsSet.has(monthKey)) {
          stats.variableSum += t.amount;
          stats.variableMonths.add(monthKey);
        }
      }
    });

    // Reduzir os stats para valores finais em USD
    let projectedIncomeUSD = 0;
    let projectedFixedExpenseUSD = 0;
    let projectedVariableExpenseUSD = 0;

    companyStats.forEach((stats, companyId) => {
      const company = activeCompanyMap.get(companyId)!;

      // Média de Receita
      const avgIncome = stats.incomeMonths.size > 0 ? stats.incomeSum / stats.incomeMonths.size : 0;
      projectedIncomeUSD += getConvertedAmount(avgIncome, company.currency);

      // Despesa Fixa (Total do mês atual)
      projectedFixedExpenseUSD += getConvertedAmount(stats.fixedSum, company.currency);

      // Média de Despesa Variável
      const avgVariable = stats.variableMonths.size > 0 ? stats.variableSum / stats.variableMonths.size : 0;
      projectedVariableExpenseUSD += getConvertedAmount(avgVariable, company.currency);
    });

    const totalProjectedExpense = projectedFixedExpenseUSD + projectedVariableExpenseUSD;

    return {
        income: projectedIncomeUSD,
        expense: totalProjectedExpense,
        profit: projectedIncomeUSD - totalProjectedExpense,
        fixedShare: totalProjectedExpense > 0 ? (projectedFixedExpenseUSD / totalProjectedExpense) * 100 : 0
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // 4. OTIMIZAÇÃO: Chart Data
  const chartData = useMemo(() => {
    // Inicializar estrutura dos últimos 6 meses
    const last6Months = new Map<string, { name: string, income: number, expense: number }>();
    const today = new Date();

    for (let i = 5; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const key = d.toISOString().slice(0, 7);
      last6Months.set(key, {
        name: d.toLocaleDateString('pt-PT', { month: 'short' }),
        income: 0,
        expense: 0
      });
    }

    // Passada única
    transactions.forEach(t => {
      const monthKey = t.date.slice(0, 7);
      const monthData = last6Months.get(monthKey);

      if (monthData) {
        const company = activeCompanyMap.get(t.companyId);
        if (company) { // Apenas empresas ativas ou todas? Geralmente histórico mantém tudo, mas seguindo lógica anterior:
           // Se quisermos manter histórico de empresas fechadas, precisaríamos de outro mapa. 
           // Assumindo consistência com o Dashboard atual: apenas empresas ativas contribuem para a visão atual.
           const usdVal = getConvertedAmount(t.amount, company.currency);
           if (t.type === TransactionType.INCOME) monthData.income += usdVal;
           else monthData.expense += usdVal;
        }
      }
    });

    return Array.from(last6Months.values()).map(d => ({
      name: d.name,
      Entradas: parseFloat(d.income.toFixed(2)),
      Saídas: parseFloat(d.expense.toFixed(2)),
      Lucro: parseFloat((d.income - d.expense).toFixed(2))
    }));

  }, [transactions, activeCompanyMap, activeRates]);

  // 5. OTIMIZAÇÃO: Pie Chart
  const pieData = useMemo(() => {
    const dataMap = new Map<string, number>();

    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(selectedMonth)) {
         const company = activeCompanyMap.get(t.companyId);
         if (company) {
             const amountUSD = getConvertedAmount(t.amount, company.currency);
             const currentVal = dataMap.get(t.category) || 0;
             dataMap.set(t.category, currentVal + amountUSD);
         }
      }
    });

    return Array.from(dataMap.entries())
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
  }, [transactions, activeCompanyMap, activeRates, selectedMonth]);

  return (
    <div className="space-y-6 animate-fade-in relative">

      {/* Settings Modal */}
      {isRateModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl max-w-md w-full p-6 animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                <Settings className="text-brand-500" /> Taxas de Câmbio
              </h3>
              <button onClick={() => setIsRateModalOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                <X size={24} />
              </button>
            </div>

            <p className="text-sm text-slate-500 dark:text-slate-400 mb-4">
              Defina quantos da moeda local equivalem a 1 USD (Dólar). Usado apenas para visualização unificada no Dashboard.
            </p>

            <div className="space-y-4">
              {Object.keys(currentRates).filter(k => k !== 'USD').map(currency => (
                <div key={currency}>
                  <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                    1 USD = ? {currency}
                  </label>
                  <input 
                    type="number" 
                    step="0.01"
                    value={currentRates[currency]}
                    onChange={(e) => setCurrentRates({...currentRates, [currency]: parseFloat(e.target.value)})}
                    className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                  />
                </div>
              ))}
            </div>

            <div className="mt-8 flex justify-end gap-3">
              <button onClick={() => setIsRateModalOpen(false)} className="px-4 py-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">Cancelar</button>
              <button onClick={handleSaveRates} className="px-4 py-2 bg-brand-600 text-white rounded-lg hover:bg-brand-700 flex items-center gap-2">
                <Save size={18} /> Salvar & Atualizar
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Visão Geral (USD Estimado)</h2>
           <div className="text-sm text-slate-500">Valores consolidados em Dólar.</div>
        </div>
        <button 
          onClick={() => setIsRateModalOpen(true)}
          className="flex items-center gap-2 px-3 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg text-sm font-medium text-slate-600 dark:text-slate-300 transition-colors"
        >
          <Settings size={16} /> Configurar Câmbio
        </button>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Receita Total</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                ${totals.income.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
              <ArrowUpCircle className="w-6 h-6 text-emerald-600 dark:text-emerald-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Despesas Totais</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                ${totals.expense.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-rose-100 dark:bg-rose-900/30 rounded-lg">
              <ArrowDownCircle className="w-6 h-6 text-rose-600 dark:text-rose-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Lucro Líquido</p>
              <h3 className={`text-2xl font-bold mt-1 ${totals.profit >= 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-rose-600 dark:text-rose-400'}`}>
                ${totals.profit.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
              <DollarSign className="w-6 h-6 text-blue-600 dark:text-blue-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 cursor-pointer hover:shadow-md transition-shadow" onClick={() => onNavigate('companies')}>
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Empresas Ativas</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                {activeCompanyMap.size}
              </h3>
            </div>
            <div className="p-2 bg-purple-100 dark:bg-purple-900/30 rounded-lg">
              <Briefcase className="w-6 h-6 text-purple-600 dark:text-purple-400" />
            </div>
          </div>
        </div>
      </div>

      {/* FORECAST SECTION - PREVISÃO DE LUCRO */}
      <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl p-6 shadow-lg text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10">
          <CalendarClock size={120} />
        </div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-4">
             <Calculator className="text-white/80" />
             <h3 className="text-lg font-bold">Previsão para o Próximo Mês</h3>
             <span className="text-xs bg-white/20 px-2 py-0.5 rounded-full">Inteligência Preditiva</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <div className="bg-white/10 rounded-lg p-4 backdrop-blur-sm border border-white/10">
               <p className="text-indigo-100 text-sm mb-1">Entrada Projetada (Média 3 meses)</p>
               <p className="text-2xl font-bold flex items-center gap-2">
                 <TrendingUp size={20} className="text-emerald-300" />
                 ${forecast.income.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
               </p>
             </div>

             <div className="bg-white/10 rounded-lg p-4 backdrop-blur-sm border border-white/10">
               <p className="text-indigo-100 text-sm mb-1">Despesa Projetada (Fixas + Média Var.)</p>
               <p className="text-2xl font-bold text-white">
                 ${forecast.expense.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
               </p>
               <p className="text-xs text-indigo-200 mt-1">
                 {forecast.fixedShare.toFixed(0)}% referente a custos fixos recorrentes
               </p>
             </div>

             <div className="bg-white/20 rounded-lg p-4 backdrop-blur-sm border border-white/20 shadow-inner">
               <p className="text-white text-sm font-semibold mb-1">Lucro Potencial</p>
               <p className={`text-3xl font-extrabold ${forecast.profit >= 0 ? 'text-emerald-300' : 'text-rose-300'}`}>
                 ${forecast.profit.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
               </p>
               <p className="text-xs text-white/70 mt-1">
                 Baseado no histórico recente e despesas ativas.
               </p>
             </div>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <h3 className="text-lg font-semibold text-slate-800 dark:text-white mb-4">Fluxo de Caixa (Últimos 6 meses)</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#374151" opacity={0.1} />
                <XAxis dataKey="name" stroke="#6b7280" />
                <YAxis stroke="#6b7280" />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }}
                  itemStyle={{ color: '#f8fafc' }}
                />
                <Legend />
                <Bar dataKey="Entradas" fill="#10b981" radius={[4, 4, 0, 0]} />
                <Bar dataKey="Saídas" fill="#ef4444" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <h3 className="text-lg font-semibold text-slate-800 dark:text-white mb-4">Acesso Rápido</h3>
          <div className="flex flex-col space-y-3">
             <button 
                onClick={() => onNavigate('companies')}
                className="w-full py-3 px-4 bg-slate-50 dark:bg-slate-700 hover:bg-slate-100 dark:hover:bg-slate-600 rounded-lg text-left text-sm font-medium transition-colors text-slate-700 dark:text-slate-200 flex items-center gap-2">
                <Briefcase size={16} /> Gerir Empresas
             </button>
             <button 
                onClick={() => onNavigate('month-detail')}
                className="w-full py-3 px-4 bg-brand-50 dark:bg-brand-900/20 hover:bg-brand-100 dark:hover:bg-brand-900/30 rounded-lg text-left text-sm font-medium transition-colors text-brand-700 dark:text-brand-300 flex items-center gap-2">
                <DollarSign size={16} /> Lançar Transação
             </button>
             <div className="p-4 rounded-lg bg-amber-50 dark:bg-amber-900/10 border border-amber-100 dark:border-amber-800 mt-4">
               <h4 className="text-amber-800 dark:text-amber-200 text-sm font-bold mb-1">Dica do Dia</h4>
               <p className="text-xs text-amber-700 dark:text-amber-300">
                 Mantenha o controle de despesas invisíveis (taxas bancárias, assinaturas esquecidas) para aumentar seu Lucro Real.
               </p>
             </div>
          </div>
        </div>
      </div>

      {/* Expense Pie Chart Section */}
      <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-semibold text-slate-800 dark:text-white flex items-center gap-2">
              <PieChartIcon size={20} className="text-slate-500" />
              Distribuição de Despesas (USD)
            </h3>
            <input 
                type="month" 
                value={selectedMonth} 
                onChange={(e) => setSelectedMonth(e.target.value)}
                className="bg-slate-50 dark:bg-slate-700 border-none rounded-lg px-3 py-1.5 text-sm font-semibold text-slate-700 dark:text-white focus:ring-2 focus:ring-brand-500 outline-none"
            />
          </div>

          {pieData.length > 0 ? (
            <div className="h-72 flex flex-col md:flex-row items-center">
              <div className="w-full md:w-1/2 h-full">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={pieData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                    >
                      {pieData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip 
                      formatter={(value: number) => `$${value.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`}
                      contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }}
                      itemStyle={{ color: '#f8fafc' }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
              <div className="w-full md:w-1/2 mt-4 md:mt-0 space-y-2 max-h-64 overflow-y-auto custom-scrollbar pr-2">
                 {pieData.map((entry, index) => (
                   <div key={index} className="flex items-center justify-between text-sm">
                     <div className="flex items-center gap-2">
                       <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                       <span className="text-slate-600 dark:text-slate-300">{entry.name}</span>
                     </div>
                     <span className="font-semibold text-slate-800 dark:text-white">
                       ${entry.value.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                     </span>
                   </div>
                 ))}
              </div>
            </div>
          ) : (
            <div className="h-72 flex items-center justify-center text-slate-400">
              <p>Nenhuma despesa registrada neste mês.</p>
            </div>
          )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Company, Transaction, MonthlyNote, ExchangeRates, ViewState, CategoryItem, TransactionType } from './types';
import { StorageService } from './services/storageService';
import { Dashboard } from './components/Dashboard';
import { CompanyManager } from './components/CompanyManager';
import { MonthDetail } from './components/MonthDetail';
import { Reports } from './components/Reports';
import { CategorySettings } from './components/CategorySettings';
import { LayoutDashboard, Building2, Calendar, FileBarChart, Settings, Menu, X, Sun, Moon, Tag, Download } from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [companies, setCompanies] = useState<Company[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notes, setNotes] = useState<MonthlyNote[]>([]);
  const [rates, setRates] = useState<ExchangeRates>({});
  const [categories, setCategories] = useState<CategoryItem[]>([]);

  // UI State
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Initialization
  useEffect(() => {
    setCompanies(StorageService.getCompanies());
    setTransactions(StorageService.getTransactions());
    setNotes(StorageService.getNotes());
    setRates(StorageService.getRates());
    setCategories(StorageService.getCategories());

    // Check system preference for dark mode
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setIsDarkMode(true);
    }

    // PWA Install Event Listener
    const handleBeforeInstallPrompt = (e: Event) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setDeferredPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    // Cleanup function
    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  // Theme Toggle Effect
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // PWA Install Handler
  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    // Show the install prompt
    deferredPrompt.prompt();
    // Wait for the user to respond to the prompt
    const { outcome } = await deferredPrompt.userChoice;
    console.log(`User response to the install prompt: ${outcome}`);
    // We've used the prompt, and can't use it again, throw it away
    setDeferredPrompt(null);
  };

  // Handlers
  const handleSaveCompany = (company: Company) => {
    const exists = companies.find(c => c.id === company.id);
    let newCompanies;
    if (exists) {
      newCompanies = companies.map(c => c.id === company.id ? company : c);
    } else {
      newCompanies = [...companies, company];
    }
    setCompanies(newCompanies);
    StorageService.saveCompanies(newCompanies);
  };

  const handleDeleteCompany = (id: string) => {
    if (confirm('Tem certeza? Todas as transações desta empresa serão ocultas.')) {
      const newCompanies = companies.filter(c => c.id !== id);
      setCompanies(newCompanies);
      StorageService.saveCompanies(newCompanies);
      // Optional: Cascade delete transactions or keep them for history
    }
  };

  const handleAddTransaction = (t: Transaction) => {
    const newTransactions = [...transactions, t];
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleDeleteTransaction = (id: string) => {
    const newTransactions = transactions.filter(t => t.id !== id);
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleSaveNote = (note: MonthlyNote) => {
    // Remove existing note for that month/company if exists
    const filteredNotes = notes.filter(n => !(n.companyId === note.companyId && n.monthStr === note.monthStr));
    const newNotes = [...filteredNotes, note];
    setNotes(newNotes);
    StorageService.saveNotes(newNotes);
  };

  // Category Handlers
  const handleAddCategory = (name: string, type: TransactionType) => {
    // Avoid duplicates
    if (categories.some(c => c.name.toLowerCase() === name.toLowerCase() && c.type === type)) return;

    const newCategory: CategoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      type
    };
    const updatedCategories = [...categories, newCategory];
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);
  };

  const handleEditCategory = (id: string, newName: string) => {
    const oldCategory = categories.find(c => c.id === id);
    if (!oldCategory) return;

    // 1. Update Category List
    const updatedCategories = categories.map(c => c.id === id ? { ...c, name: newName } : c);
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);

    // 2. Update all associated transactions
    const updatedTransactions = transactions.map(t => 
      (t.category === oldCategory.name && t.type === oldCategory.type) 
        ? { ...t, category: newName } 
        : t
    );
    setTransactions(updatedTransactions);
    StorageService.saveTransactions(updatedTransactions);
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('Ao eliminar a categoria, ela deixará de aparecer nas sugestões, mas as transações antigas serão mantidas. Continuar?')) {
      const updatedCategories = categories.filter(c => c.id !== id);
      setCategories(updatedCategories);
      StorageService.saveCategories(updatedCategories);
    }
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => (
    <button
      onClick={() => { setCurrentView(view); setIsSidebarOpen(false); }}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
        currentView === view 
          ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' 
          : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black/50 lg:hidden backdrop-blur-sm"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed lg:static inset-y-0 left-0 z-30 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transform transition-transform duration-300 ease-in-out flex flex-col
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3">
          <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">
            R
          </div>
          <h1 className="text-xl font-bold tracking-tight text-slate-800 dark:text-white">Rota do Lucro</h1>
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          <NavItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem view="companies" icon={Building2} label="Empresas" />
          <NavItem view="month-detail" icon={Calendar} label="Gestão Mensal" />
          <NavItem view="categories" icon={Tag} label="Categorias" />
          <NavItem view="reports" icon={FileBarChart} label="Relatórios" />
        </nav>

        <div className="p-4 border-t border-slate-100 dark:border-slate-800 space-y-4">

           {deferredPrompt && (
             <button 
               onClick={handleInstallClick}
               className="w-full flex items-center justify-center gap-2 p-3 rounded-lg bg-emerald-600 hover:bg-emerald-700 text-white font-medium shadow-md transition-colors animate-pulse"
             >
               <Download size={18} />
               Instalar App
             </button>
           )}

           <div className="bg-slate-50 dark:bg-slate-800 rounded-xl p-4">
              <p className="text-xs text-slate-500 dark:text-slate-400 mb-2">Modo Escuro</p>
              <button 
                onClick={() => setIsDarkMode(!isDarkMode)}
                className="w-full flex items-center justify-between p-2 rounded-lg bg-white dark:bg-slate-700 shadow-sm border border-slate-200 dark:border-slate-600"
              >
                 <span className="text-sm font-medium flex items-center gap-2">
                    {isDarkMode ? <Moon size={14} /> : <Sun size={14} />} 
                    {isDarkMode ? 'Ativado' : 'Desativado'}
                 </span>
                 <div className={`w-8 h-4 rounded-full relative transition-colors ${isDarkMode ? 'bg-brand-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-0.5 left-0.5 w-3 h-3 bg-white rounded-full transition-transform ${isDarkMode ? 'translate-x-4' : 'translate-x-0'}`} />
                 </div>
              </button>
           </div>
           <div className="text-xs text-center text-slate-400">v1.2.0</div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Header */}
        <header className="h-16 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 flex items-center justify-between px-6 sticky top-0 z-10">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden p-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"
          >
            <Menu size={24} />
          </button>

          <div className="text-sm font-medium text-slate-500 dark:text-slate-400">
             {currentView === 'dashboard' && 'Visão Geral'}
             {currentView === 'companies' && 'Cadastro de Clientes'}
             {currentView === 'month-detail' && 'Lançamentos e Análise'}
             {currentView === 'categories' && 'Personalização de Categorias'}
             {currentView === 'reports' && 'Exportação'}
          </div>

          <div className="flex items-center gap-4">
            <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700 flex items-center justify-center text-slate-600 dark:text-slate-300 font-bold text-xs">
               AD
            </div>
          </div>
        </header>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8 scrollbar-hide">
          <div className="max-w-7xl mx-auto animate-fade-in">
            {currentView === 'dashboard' && (
              <Dashboard 
                companies={companies} 
                transactions={transactions} 
                rates={rates}
                onNavigate={setCurrentView} 
              />
            )}

            {currentView === 'companies' && (
              <CompanyManager 
                companies={companies} 
                onSave={handleSaveCompany} 
                onDelete={handleDeleteCompany} 
              />
            )}

            {currentView === 'month-detail' && (
              <MonthDetail 
                companies={companies}
                transactions={transactions}
                notes={notes}
                categories={categories}
                rates={rates}
                onAddTransaction={handleAddTransaction}
                onDeleteTransaction={handleDeleteTransaction}
                onSaveNote={handleSaveNote}
                onAutoAddCategory={handleAddCategory}
              />
            )}

            {currentView === 'categories' && (
              <CategorySettings 
                categories={categories}
                onAdd={handleAddCategory}
                onEdit={handleEditCategory}
                onDelete={handleDeleteCategory}
              />
            )}

            {currentView === 'reports' && (
              <Reports 
                companies={companies}
                transactions={transactions}
                rates={rates}
              />
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates, Currency } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, DollarSign, Briefcase, PieChart as PieChartIcon, TrendingUp, CalendarClock, Calculator, Settings, X, Save } from 'lucide-react';
import { StorageService } from '../services/storageService';

interface DashboardProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

const COLORS = ['#0ea5e9', '#10b981', '#ef4444', '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ companies, transactions, rates: initialRates, onNavigate }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));
  const [isRateModalOpen, setIsRateModalOpen] = useState(false);
  const [currentRates, setCurrentRates] = useState<ExchangeRates>(initialRates);

  // Sync state when props change (Critical for initial load)
  useEffect(() => {
    if (Object.keys(initialRates).length > 0) {
      setCurrentRates(initialRates);
    }
  }, [initialRates]);

  const handleSaveRates = () => {
    StorageService.saveRates(currentRates);
    setIsRateModalOpen(false);
    window.location.reload(); 
  };

  const activeRates = currentRates;

  // Mapa de Empresas Ativas para acesso O(1)
  const activeCompanyMap = useMemo(() => {
    const map = new Map<string, Company>();
    companies.forEach(c => {
      if (c.status !== 'Encerrado') {
        map.set(c.id, c);
      }
    });
    return map;
  }, [companies]);

  // Helper para conversão SEGURA
  const getConvertedAmount = (amount: number, currency: Currency) => {
    // Se a taxa não existir, assume 1 (USD) para evitar divisão por zero/undefined -> NaN
    const rate = activeRates[currency];
    const safeRate = (rate !== undefined && rate > 0) ? rate : 1;
    return amount / safeRate;
  };

  // Cálculo de Totais (O(N))
  const totals = useMemo(() => {
    let totalIncomeUSD = 0;
    let totalExpenseUSD = 0;

    transactions.forEach(t => {
      const company = activeCompanyMap.get(t.companyId);
      if (!company) return; 

      const usdValue = getConvertedAmount(t.amount, company.currency);

      if (t.type === TransactionType.INCOME) {
        totalIncomeUSD += usdValue;
      } else {
        totalExpenseUSD += usdValue;
      }
    });

    return {
      income: totalIncomeUSD,
      expense: totalExpenseUSD,
      profit: totalIncomeUSD - totalExpenseUSD
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // Forecast (Previsão)
  const forecast = useMemo(() => {
    const today = new Date();
    const currentMonthKey = today.toISOString().slice(0, 7);

    const pastMonthsSet = new Set<string>();
    for (let i = 1; i <= 3; i++) {
        const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
        pastMonthsSet.add(d.toISOString().slice(0, 7));
    }

    const companyStats = new Map<string, {
      incomeSum: number;
      incomeMonths: Set<string>;
      fixedSum: number;
      variableSum: number;
      variableMonths: Set<string>;
    }>();

    activeCompanyMap.forEach((_, id) => {
      companyStats.set(id, {
        incomeSum: 0,
        incomeMonths: new Set(),
        fixedSum: 0,
        variableSum: 0,
        variableMonths: new Set()
      });
    });

    transactions.forEach(t => {
      const stats = companyStats.get(t.companyId);
      if (!stats) return;

      const monthKey = t.date.slice(0, 7);

      if (t.type === TransactionType.INCOME && pastMonthsSet.has(monthKey)) {
        stats.incomeSum += t.amount;
        stats.incomeMonths.add(monthKey);
      }

      if (t.type === TransactionType.EXPENSE) {
        if (t.isFixed && monthKey === currentMonthKey) {
          stats.fixedSum += t.amount;
        }
        if (!t.isFixed && pastMonthsSet.has(monthKey)) {
          stats.variableSum += t.amount;
          stats.variableMonths.add(monthKey);
        }
      }
    });

    let projectedIncomeUSD = 0;
    let projectedFixedExpenseUSD = 0;
    let projectedVariableExpenseUSD = 0;

    companyStats.forEach((stats, companyId) => {
      const company = activeCompanyMap.get(companyId)!;

      const avgIncome = stats.incomeMonths.size > 0 ? stats.incomeSum / stats.incomeMonths.size : 0;
      projectedIncomeUSD += getConvertedAmount(avgIncome, company.currency);

      projectedFixedExpenseUSD += getConvertedAmount(stats.fixedSum, company.currency);

      const avgVariable = stats.variableMonths.size > 0 ? stats.variableSum / stats.variableMonths.size : 0;
      projectedVariableExpenseUSD += getConvertedAmount(avgVariable, company.currency);
    });

    const totalProjectedExpense = projectedFixedExpenseUSD + projectedVariableExpenseUSD;

    return {
        income: projectedIncomeUSD,
        expense: totalProjectedExpense,
        profit: projectedIncomeUSD - totalProjectedExpense,
        fixedShare: totalProjectedExpense > 0 ? (projectedFixedExpenseUSD / totalProjectedExpense) * 100 : 0
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // Chart Data
  const chartData = useMemo(() => {
    const last6Months = new Map<string, { name: string, income: number, expense: number }>();
    const today = new Date();

    for (let i = 5; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const key = d.toISOString().slice(0, 7);
      last6Months.set(key, {
        name: d.toLocaleDateString('pt-PT', { month: 'short' }),
        income: 0,
        expense: 0
      });
    }

    transactions.forEach(t => {
      const monthKey = t.date.slice(0, 7);
      const monthData = last6Months.get(monthKey);

      if (monthData) {
        const company = activeCompanyMap.get(t.companyId);
        if (company) {
           const usdVal = getConvertedAmount(t.amount, company.currency);
           if (t.type === TransactionType.INCOME) monthData.income += usdVal;
           else monthData.expense += usdVal;
        }
      }
    });

    return Array.from(last6Months.values()).map(d => ({
      name: d.name,
      Entradas: parseFloat(d.income.toFixed(2)),
      Saídas: parseFloat(d.expense.toFixed(2)),
      Lucro: parseFloat((d.income - d.expense).toFixed(2))
    }));

  }, [transactions, activeCompanyMap, activeRates]);

  // Pie Chart
  const pieData = useMemo(() => {
    const dataMap = new Map<string, number>();

    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(selectedMonth)) {
         const company = activeCompanyMap.get(t.companyId);
         if (company) {
             const amountUSD = getConvertedAmount(t.amount, company.currency);
             const currentVal = dataMap.get(t.category) || 0;
             dataMap.set(t.category, currentVal + amountUSD);
         }
      }
    });

    return Array.from(dataMap.entries())
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
  }, [transactions, activeCompanyMap, activeRates, selectedMonth]);

  return (
    <div className="space-y-6 animate-fade-in relative">

      {/* Settings Modal */}
      {isRateModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl max-w-md w-full p-6 animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                <Settings className="text-brand-500" /> Taxas de Câmbio
              </h3>
              <button onClick={() => setIsRateModalOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                <X size={24} />
              </button>
            </div>

            <p className="text-sm text-slate-500 dark:text-slate-400 mb-4">
              Defina quantos da moeda local equivalem a 1 USD (Dólar). 
            </p>

            <div className="space-y-4">
              {Object.keys(currentRates).filter(k => k !== 'USD').map(currency => (
                <div key={currency}>
                  <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                    1 USD = ? {currency}
                  </label>
                  <input 
                    type="number" 
                    step="0.01"
                    value={currentRates[currency]}
                    onChange={(e) => setCurrentRates({...currentRates, [currency]: parseFloat(e.target.value)})}
                    className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                  />
                </div>
              ))}
            </div>

            <div className="mt-8 flex justify-end gap-3">
              <button onClick={() => setIsRateModalOpen(false)} className="px-4 py-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">Cancelar</button>
              <button onClick={handleSaveRates} className="px-4 py-2 bg-brand-600 text-white rounded-lg hover:bg-brand-700 flex items-center gap-2">
                <Save size={18} /> Salvar & Atualizar
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Visão Geral (USD)</h2>
           <div className="text-sm text-slate-500">Todos os valores foram convertidos para Dólar.</div>
        </div>
        <button 
          onClick={() => setIsRateModalOpen(true)}
          className="flex items-center gap-2 px-3 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg text-sm font-medium text-slate-600 dark:text-slate-300 transition-colors"
        >
          <Settings size={16} /> Configurar Câmbio
        </button>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Receita Total</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                ${totals.income.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
              <ArrowUpCircle className="w-6 h-6 text-emerald-600 dark:text-emerald-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Despesas Totais</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                ${totals.expense.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-rose-100 dark:bg-rose-900/30 rounded-lg">
              <ArrowDownCircle className="w-6 h-6 text-rose-600 dark:text-rose-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Lucro Líquido</p>
              <h3 className={`text-2xl font-bold mt-1 ${totals.profit >= 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-rose-600 dark:text-rose-400'}`}>
                ${totals.profit.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </h3>
            </div>
            <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
              <DollarSign className="w-6 h-6 text-blue-600 dark:text-blue-400" />
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 cursor-pointer hover:shadow-md transition-shadow" onClick={() => onNavigate('companies')}>
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Empresas Ativas</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                {activeCompanyMap.size}
              </h3>
            </div>
            <div className="p-2 bg-purple-100 dark:bg-purple-900/30 rounded-lg">
              <Briefcase className="w-6 h-6 text-purple-600 dark:text-purple-400" />
            </div>
          </div>
        </div>
      </div>

      {/* FORECAST SECTION */}
      <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl p-6 shadow-lg text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10">
          <CalendarClock size={120} />
        </div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-4">
             <Calculator className="text-white/80" />
             <h3 className="text-lg font-bold">Previsão para o Próximo Mês</h3>
             <span className="text-xs bg-white/20 px-2 py-0.5 rounded-full">Inteligência Preditiva</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <div className="bg-white/10 rounded-lg p-4 backdrop-blur-sm border border-white/10">
               <p className="text-indigo-100 text-sm mb-1">Entrada Projetada (Média 3 meses)</p>
               <p className="text-2xl font-bold flex items-center gap-2">
                 <TrendingUp size={20} className="text-emerald-300" />
                 ${forecast.income.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
               </p>
             </div>

             <div className="bg-white/10 rounded-lg p-4 backdrop-blur-sm border border-white/10">
               <p className="text-indigo-100 text-sm mb-1">Despesa Projetada (Fixas + Média Var.)</p>
               <p className="text-2xl font-bold text-white">
                 ${forecast.expense.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
               </p>
               <p className="text-xs text-indigo-200 mt-1">
                 {forecast.fixedShare.toFixed(0)}% referente a custos fixos recorrentes
               </p>
