};

import React, { useState, useMemo } from 'react';
import { Company, Transaction, TransactionType, MonthlyNote, CategoryItem, ExchangeRates } from '../types';
import { Plus, Trash2, TrendingUp, TrendingDown, AlertTriangle, Sparkles, FileText } from 'lucide-react';
import { generateFinancialAnalysis } from '../services/geminiService';

interface MonthDetailProps {
  companies: Company[];
  transactions: Transaction[];
  notes: MonthlyNote[];
  categories: CategoryItem[];
  rates: ExchangeRates;
  onAddTransaction: (t: Transaction) => void;
  onDeleteTransaction: (id: string) => void;
  onSaveNote: (note: MonthlyNote) => void;
  onAutoAddCategory: (name: string, type: TransactionType) => void;
}

export const MonthDetail: React.FC<MonthDetailProps> = ({ 
  companies, 
  transactions, 
  notes,
  categories,
  rates,
  onAddTransaction, 
  onDeleteTransaction,
  onSaveNote,
  onAutoAddCategory
}) => {
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>(companies[0]?.id || '');
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7)); // YYYY-MM
  const [activeTab, setActiveTab] = useState<'income' | 'expense'>('income');

  // Transaction Form State
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState('');
  const [desc, setDesc] = useState('');
  const [isFixed, setIsFixed] = useState(false);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  // AI Loading State
  const [aiLoading, setAiLoading] = useState(false);

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // Helper: Convert to USD
  const toUSD = (amt: number, currency?: string) => {
    if (!currency) return amt;
    const rate = rates[currency] || 1;
    return amt / rate;
  };

  // Filter categories for autocomplete based on active tab
  const availableCategories = useMemo(() => {
    const type = activeTab === 'income' ? TransactionType.INCOME : TransactionType.EXPENSE;
    return categories.filter(c => c.type === type);
  }, [categories, activeTab]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => 
      t.companyId === selectedCompanyId && 
      t.date.startsWith(selectedMonth)
    );
  }, [transactions, selectedCompanyId, selectedMonth]);

  const stats = useMemo(() => {
    // Calcula em moeda original primeiro, depois converte totais
    const income = filteredTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0);
    const expense = filteredTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0);
    const profit = income - expense;
    const margin = income > 0 ? (profit / income) * 100 : 0;

    // Lucro Real (Utiliza a taxa configurada na empresa ou 0 se não houver)
    const taxRate = selectedCompany?.taxRate || 0;
    const realProfit = profit * (1 - (taxRate / 100));

    // Converter para USD
    const currency = selectedCompany?.currency;
    return { 
      incomeUSD: toUSD(income, currency), 
      expenseUSD: toUSD(expense, currency), 
      profitUSD: toUSD(profit, currency), 
      margin, 
      realProfitUSD: toUSD(realProfit, currency), 
      taxRate 
    };
  }, [filteredTransactions, selectedCompany, rates]);

  const currentNote = notes.find(n => n.companyId === selectedCompanyId && n.monthStr === selectedMonth);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    const type = activeTab === 'income' ? TransactionType.INCOME : TransactionType.EXPENSE;

    // Check if category exists, if not, save it for future reuse
    const categoryExists = categories.some(c => c.name.toLowerCase() === category.toLowerCase() && c.type === type);
    if (!categoryExists) {
      onAutoAddCategory(category, type);
    }

    const newTransaction: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: type,
      amount: parseFloat(amount),
      category: category, // Saves the string
      date,
      description: desc,
      isFixed: activeTab === 'expense' ? isFixed : undefined
    };

    onAddTransaction(newTransaction);
    setAmount('');
    setDesc('');
    setCategory(''); 
  };

  const handleAIAnalysis = async () => {
    if (!selectedCompany) return;
    setAiLoading(true);
    const analysis = await generateFinancialAnalysis(selectedCompany, filteredTransactions, selectedMonth);

    const newNote: MonthlyNote = {
      id: currentNote?.id || Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      monthStr: selectedMonth,
      note: currentNote?.note || '',
      aiAnalysis: analysis
    };
    onSaveNote(newNote);
    setAiLoading(false);
  };

  if (!selectedCompany) return <div className="p-8 text-center text-slate-500">Selecione ou crie uma empresa primeiro.</div>;

  return (
    <div className="space-y-6">
      {/* Top Controls */}
      <div className="flex flex-col md:flex-row gap-4 justify-between bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm">
        <div className="flex flex-col md:flex-row gap-4">
          <div>
            <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 mb-1 uppercase tracking-wider">Empresa</label>
            <select 
              value={selectedCompanyId} 
              onChange={(e) => setSelectedCompanyId(e.target.value)}
              className="bg-slate-50 dark:bg-slate-700 border-none rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 dark:text-white focus:ring-2 focus:ring-brand-500"
            >
              {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 mb-1 uppercase tracking-wider">Mês de Referência</label>
            <input 
              type="month" 
              value={selectedMonth} 
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-slate-50 dark:bg-slate-700 border-none rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 dark:text-white focus:ring-2 focus:ring-brand-500"
            />
          </div>
        </div>
        <div className="flex items-center gap-2 text-sm text-slate-500">
           <span className="font-bold text-slate-700 dark:text-slate-300">Moeda da Empresa:</span> {selectedCompany.currency}
           <span className="text-xs text-slate-400">(Convertido para USD na visualização)</span>
        </div>
      </div>

      {/* Main Stats for Month (USD) */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-emerald-50 dark:bg-emerald-900/20 p-4 rounded-xl border border-emerald-100 dark:border-emerald-900/30">
          <span className="text-emerald-600 dark:text-emerald-400 text-xs font-bold uppercase">Entradas (USD)</span>
          <div className="text-xl font-bold text-emerald-700 dark:text-emerald-300 mt-1">
             $ {stats.incomeUSD.toLocaleString('en-US', { minimumFractionDigits: 2 })}
          </div>
        </div>
        <div className="bg-rose-50 dark:bg-rose-900/20 p-4 rounded-xl border border-rose-100 dark:border-rose-900/30">
          <span className="text-rose-600 dark:text-rose-400 text-xs font-bold uppercase">Saídas (USD)</span>
          <div className="text-xl font-bold text-rose-700 dark:text-rose-300 mt-1">
             $ {stats.expenseUSD.toLocaleString('en-US', { minimumFractionDigits: 2 })}
          </div>
        </div>
        <div className="bg-slate-50 dark:bg-slate-700/50 p-4 rounded-xl border border-slate-100 dark:border-slate-600">
          <span className="text-slate-500 dark:text-slate-400 text-xs font-bold uppercase">Lucro Líquido (USD)</span>
          <div className={`text-xl font-bold mt-1 ${stats.profitUSD >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
             $ {stats.profitUSD.toLocaleString('en-US', { minimumFractionDigits: 2 })}
          </div>
        </div>
        <div className="bg-purple-50 dark:bg-purple-900/20 p-4 rounded-xl border border-purple-100 dark:border-purple-900/30 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-1 opacity-10 group-hover:opacity-20">
            <Sparkles className="w-12 h-12 text-purple-600" />
          </div>
          <span className="text-purple-600 dark:text-purple-400 text-xs font-bold uppercase">Lucro Real (USD)</span>
          <div className="text-xl font-bold text-purple-700 dark:text-purple-300 mt-1">
             $ {stats.realProfitUSD.toLocaleString('en-US', { minimumFractionDigits: 2 })}
          </div>
          <div className="text-[10px] text-purple-400 mt-1">
             Desc. Impostos/Taxas: {stats.taxRate}%
          </div>
        </div>
      </div>

      {/* Transaction Entry Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Form */}
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
          <div className="flex border-b border-slate-100 dark:border-slate-700">
            <button 
              onClick={() => { setActiveTab('income'); setCategory(''); }}
              className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 ${activeTab === 'income' ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 border-b-2 border-emerald-500' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
            >
              <TrendingUp size={16} /> Receita
            </button>
            <button 
              onClick={() => { setActiveTab('expense'); setCategory(''); }}
              className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 ${activeTab === 'expense' ? 'bg-rose-50 dark:bg-rose-900/20 text-rose-600 border-b-2 border-rose-500' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
            >
              <TrendingDown size={16} /> Despesa
            </button>
          </div>

          <form onSubmit={handleAdd} className="p-6 space-y-4">
            <div>
              <label className="block text-xs text-slate-500 mb-1">Valor (Moeda Original: {selectedCompany.currency})</label>
              <div className="relative">
                <span className="absolute left-3 top-2.5 text-slate-400 font-bold text-sm">{selectedCompany.currency}</span>
                <input 
                  type="number" 
                  value={amount} 
                  onChange={e => setAmount(e.target.value)} 
                  className="w-full pl-12 pr-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                  placeholder="0.00"
                  step="0.01"
                  required
                />
              </div>
            </div>

            <div>
              <label className="block text-xs text-slate-500 mb-1">Data</label>
              <input 
                type="date"
                value={date}
                onChange={e => setDate(e.target.value)}
                className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                required
              />
            </div>

            <div>
              <label className="block text-xs text-slate-500 mb-1">Categoria (Digite para criar ou selecione)</label>
              <input 
                list="category-options"
                type="text"
                value={category}
                onChange={e => setCategory(e.target.value)}
                className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                placeholder="Ex: Consultoria, Combustível..."
                required
                autoComplete="off"
              />
              <datalist id="category-options">
                {availableCategories.map(c => (
                  <option key={c.id} value={c.name} />
                ))}
              </datalist>
            </div>

            <div>
              <label className="block text-xs text-slate-500 mb-1">Descrição (Opcional)</label>
              <input 
                type="text" 
                value={desc} 
                onChange={e => setDesc(e.target.value)} 
                className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
                placeholder="Ex: Cliente X, Fatura #123"
              />
            </div>

            {activeTab === 'expense' && (
              <label className="flex items-center gap-2 cursor-pointer">
                <input 
                  type="checkbox" 
                  checked={isFixed} 
                  onChange={e => setIsFixed(e.target.checked)}
                  className="rounded text-brand-600 focus:ring-brand-500" 
                />
                <span className="text-sm text-slate-600 dark:text-slate-300">Despesa Fixa (Recorrente)</span>
              </label>
            )}

            <button type="submit" className={`w-full py-3 rounded-lg font-bold text-white shadow-lg transition-transform active:scale-95 ${activeTab === 'income' ? 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-500/30' : 'bg-rose-500 hover:bg-rose-600 shadow-rose-500/30'}`}>
              <Plus className="inline mr-2 w-4 h-4" /> 
              {activeTab === 'income' ? 'Registrar Entrada' : 'Registrar Saída'}
            </button>
          </form>
        </div>

        {/* List & AI */}
        <div className="lg:col-span-2 space-y-6">

          {/* List */}
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 p-4 min-h-[400px]">
            <h3 className="font-bold text-slate-800 dark:text-white mb-4">Lançamentos de {selectedMonth} (em USD)</h3>

            {filteredTransactions.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                <FileText className="w-12 h-12 mb-2 opacity-50" />
                <p>Nenhum lançamento neste mês.</p>
              </div>
            ) : (
              <div className="space-y-3 max-h-[500px] overflow-y-auto pr-2">
                {filteredTransactions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(t => {
                   const usdAmount = toUSD(t.amount, selectedCompany.currency);
                   return (
                  <div key={t.id} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-900/50 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-900 transition-colors group">
                    <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-full ${t.type === TransactionType.INCOME ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>
                        {t.type === TransactionType.INCOME ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800 dark:text-white">{t.category}</p>
                        <p className="text-xs text-slate-500">{t.description || '-'} • {new Date(t.date).toLocaleDateString('pt-PT')}</p>
                        <p className="text-[10px] text-slate-400">Orig: {selectedCompany.currency} {t.amount.toLocaleString()}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className={`font-bold ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {t.type === TransactionType.INCOME ? '+' : '-'} ${usdAmount.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                      </span>
                      <button onClick={() => onDeleteTransaction(t.id)} className="text-slate-400 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                )})}
              </div>
            )}
          </div>

          {/* AI Strategy Section */}
          <div className="bg-indigo-50 dark:bg-indigo-950/30 rounded-xl border border-indigo-100 dark:border-indigo-900 p-6">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-indigo-900 dark:text-indigo-200 flex items-center gap-2">
                <Sparkles className="text-indigo-500" size={20} /> Inteligência Financeira
              </h3>
              <button 
                onClick={handleAIAnalysis}
                disabled={aiLoading}
                className="px-3 py-1.5 bg-indigo-600 text-white text-xs font-bold rounded-lg hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2"
              >
                {aiLoading ? 'Analisando...' : 'Gerar Análise'}
              </button>
            </div>

            {currentNote?.aiAnalysis ? (
              <div className="prose prose-sm dark:prose-invert max-w-none text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-900/50 p-4 rounded-lg border border-indigo-100 dark:border-indigo-900/50 whitespace-pre-line">
                {currentNote.aiAnalysis}
              </div>
            ) : (
              <div className="text-center py-6 text-indigo-400 dark:text-indigo-300/50 text-sm">
                Clique em "Gerar Análise" para receber insights sobre redução de custos e saúde financeira.
              </div>
            )}

            {/* Warning if loss */}
            {stats.profitUSD < 0 && (
              <div className="mt-4 flex items-start gap-2 bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-200 p-3 rounded-lg text-sm">
                <AlertTriangle size={18} className="shrink-0 mt-0.5" />
                <p>Atenção: Este mês está no vermelho. Verifique as sugestões da IA para cortar custos fixos imediatamente.</p>
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates } from '../types';
import { Download, FileText, Calendar, Building, Printer, FileSpreadsheet } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface ReportsProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
}

export const Reports: React.FC<ReportsProps> = ({ companies, transactions, rates }) => {
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));

  // Helper: Convert to USD
  const toUSD = (amt: number, currency?: string) => {
    if (!currency) return amt;
    const rate = rates[currency] || 1;
    return amt / rate;
  };

  const getFilteredData = () => {
     const company = companies.find(c => c.id === selectedCompanyId);
     if (!company) return null;

     const monthlyTransactions = transactions.filter(t => 
      t.companyId === selectedCompanyId && 
      t.date.startsWith(selectedMonth)
    );

    return { company, monthlyTransactions };
  }

  const generatePDF = () => {
    const data = getFilteredData();
    if (!data) return;
    const { company, monthlyTransactions } = data;

    const incomeUSD = monthlyTransactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + toUSD(t.amount, company.currency), 0);

    const expenseUSD = monthlyTransactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + toUSD(t.amount, company.currency), 0);

    const profitUSD = incomeUSD - expenseUSD;
    const margin = incomeUSD > 0 ? ((profitUSD / incomeUSD) * 100).toFixed(2) : '0';

    // Agrupar por categoria (USD)
    const categorySummary: Record<string, { type: TransactionType, amount: number }> = {};
    monthlyTransactions.forEach(t => {
      const usdAmount = toUSD(t.amount, company.currency);
      if (!categorySummary[t.category]) {
        categorySummary[t.category] = { type: t.type, amount: 0 };
      }
      categorySummary[t.category].amount += usdAmount;
    });

    // 2. Inicializar PDF
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.width;

    // -- CORES --
    const primaryColor = [14, 165, 233]; // Brand-500
    const profitColor = [16, 185, 129]; // Emerald
    const expenseColor = [239, 68, 68]; // Red
    const slateColor = [51, 65, 85]; // Slate-700

    // 3. Cabeçalho
    doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.rect(0, 0, pageWidth, 40, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("Relatório Financeiro Mensal (USD)", 14, 20);

    doc.setFontSize(12);
    doc.setFont("helvetica", "normal");
    doc.text(`Empresa: ${company.name}`, 14, 30);

    const [year, month] = selectedMonth.split('-');
    const dateStr = new Date(parseInt(year), parseInt(month)-1).toLocaleDateString('pt-PT', { month: 'long', year: 'numeric' });
    doc.text(`Período: ${dateStr}`, 14, 36);

    doc.setFontSize(10);
    doc.text("Gerado por: Na Rota do Lucro", pageWidth - 60, 36);

    let currentY = 50;

    // 4. Resumo Executivo (Cards)
    doc.setTextColor(slateColor[0], slateColor[1], slateColor[2]);
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text("Resumo Financeiro (Valores em Dólar)", 14, currentY);
    currentY += 10;

    const summaryData = [
      [`Receita Total`, `$ ${incomeUSD.toLocaleString('en-US', { minimumFractionDigits: 2 })}`],
      [`Despesa Total`, `$ ${expenseUSD.toLocaleString('en-US', { minimumFractionDigits: 2 })}`],
      [`Lucro Líquido`, `$ ${profitUSD.toLocaleString('en-US', { minimumFractionDigits: 2 })}`],
      [`Margem de Lucro`, `${margin}%`]
    ];

    autoTable(doc, {
      startY: currentY,
      head: [['Indicador', 'Valor (USD)']],
      body: summaryData,
      theme: 'grid',
      headStyles: { fillColor: [241, 245, 249], textColor: [51, 65, 85], fontStyle: 'bold' }, // Slate-100
      columnStyles: {
        0: { fontStyle: 'bold', cellWidth: 100 },
        1: { halign: 'right' }
      },
      styles: { fontSize: 11, cellPadding: 6 }
    });

    // @ts-ignore
    currentY = doc.lastAutoTable.finalY + 15;

    // 5. Detalhamento por Categoria (Top 5 Despesas)
    doc.text("Top Despesas por Categoria (USD)", 14, currentY);
    currentY += 8;

    const expenseCategories = Object.entries(categorySummary)
      .filter(([_, data]) => data.type === TransactionType.EXPENSE)
      .sort((a, b) => b[1].amount - a[1].amount)
      .map(([name, data]) => [name, `$ ${data.amount.toLocaleString('en-US', { minimumFractionDigits: 2 })}`]);

    if (expenseCategories.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Categoria', 'Total Gasto (USD)']],
        body: expenseCategories,
        theme: 'striped',
        headStyles: { fillColor: expenseColor, textColor: 255 },
        columnStyles: { 1: { halign: 'right' } }
      });
      // @ts-ignore
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(10);
      doc.setFont("helvetica", "italic");
      doc.text("Nenhuma despesa registrada neste período.", 14, currentY + 5);
      currentY += 15;
    }

    // 6. Tabela Completa de Transações
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.setTextColor(slateColor[0], slateColor[1], slateColor[2]);
    doc.text("Detalhamento de Transações", 14, currentY);
    currentY += 8;

    const rows = monthlyTransactions
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map(t => [
        new Date(t.date).toLocaleDateString('pt-PT'),
        t.category,
        t.description || '-',
        t.type === TransactionType.INCOME ? 'Entrada' : 'Saída',
        `$ ${toUSD(t.amount, company.currency).toLocaleString('en-US', { minimumFractionDigits: 2 })}`
      ]);

    autoTable(doc, {
      startY: currentY,
      head: [['Data', 'Categoria', 'Descrição', 'Tipo', 'Valor (USD)']],
      body: rows,
      theme: 'striped',
      headStyles: { fillColor: slateColor, textColor: 255 },
      columnStyles: {
        4: { halign: 'right', fontStyle: 'bold' }
      },
      didParseCell: function(data) {
        // Colorir o texto de Entrada/Saída
        if (data.section === 'body' && data.column.index === 3) {
            if (data.cell.raw === 'Entrada') {
                data.cell.styles.textColor = profitColor;
            } else {
                data.cell.styles.textColor = expenseColor;
            }
        }
      }
    });

    // 7. Salvar PDF
    const filename = `Relatorio_USD_${company.name.replace(/\s+/g, '_')}_${selectedMonth}.pdf`;
    doc.save(filename);
  };

  const generateCSV = () => {
    const data = getFilteredData();
    if (!data) return;
    const { company, monthlyTransactions } = data;

    const headers = ['Data', 'Empresa', 'Tipo', 'Categoria', 'Descrição', 'Valor Original', 'Moeda Orig.', 'Valor USD'];
    const rows = monthlyTransactions.map(t => [
      t.date,
      company.name,
      t.type === TransactionType.INCOME ? 'Entrada' : 'Saida',
      `"${t.category}"`, // Escape quotes
      `"${t.description || ''}"`,
      t.amount,
      company.currency,
      toUSD(t.amount, company.currency).toFixed(2)
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `Extrato_USD_${company.name}_${selectedMonth}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="bg-white dark:bg-slate-800 p-8 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <Printer size={32} />
          </div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">Relatórios Oficiais (USD)</h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-lg mx-auto">
            Gere documentos completos com análise financeira, totais por categoria e histórico detalhado, convertidos para Dólar.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-2xl mx-auto bg-slate-50 dark:bg-slate-900/50 p-6 rounded-xl border border-slate-200 dark:border-slate-700">
          <div>
             <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
               <Building size={16} /> Empresa
             </label>
             <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
             >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
             </select>
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
               <Calendar size={16} /> Mês de Referência
             </label>
             <input 
               type="month" 
               value={selectedMonth} 
               onChange={(e) => setSelectedMonth(e.target.value)}
               className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
             />
          </div>

          <div className="md:col-span-2 pt-2 flex flex-col md:flex-row gap-3">
            <button 
              onClick={generatePDF}
              className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg transition-all shadow-lg shadow-brand-500/20 active:scale-95"
            >
              <FileText size={22} />
              Baixar PDF (USD)
            </button>

            <button 
              onClick={generateCSV}
              className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-lg transition-all shadow-lg shadow-emerald-500/20 active:scale-95"
            >
              <FileSpreadsheet size={22} />
              Baixar CSV (Excel)
            </button>
          </div>

          <div className="md:col-span-2 text-center text-xs text-slate-400 mt-1">
             PDF para leitura e impressão, CSV para análise em Excel. Todos os valores convertidos.
          </div>
        </div>
      </div>

      {/* Preview Section */}
      <div className="border-t border-slate-200 dark:border-slate-800 pt-8">
        <h3 className="text-lg font-semibold text-slate-700 dark:text-slate-300 mb-4 flex items-center gap-2">
          <FileText size={20} /> O que está incluído no relatório?
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
          <div className="p-4 bg-emerald-50 dark:bg-emerald-900/10 rounded-lg border border-emerald-100 dark:border-emerald-900/20">
            <span className="font-bold text-emerald-700 dark:text-emerald-400 block mb-1">Resumo em Dólar</span>
            <p className="text-slate-600 dark:text-slate-400">Totais de entradas, saídas, lucro líquido real e margem de lucratividade convertidos.</p>
          </div>
          <div className="p-4 bg-blue-50 dark:bg-blue-900/10 rounded-lg border border-blue-100 dark:border-blue-900/20">
            <span className="font-bold text-blue-700 dark:text-blue-400 block mb-1">Análise por Categoria</span>
            <p className="text-slate-600 dark:text-slate-400">Agrupamento automático de gastos para identificar onde o dinheiro está sendo investido.</p>
          </div>
          <div className="p-4 bg-amber-50 dark:bg-amber-900/10 rounded-lg border border-amber-100 dark:border-amber-900/20">
            <span className="font-bold text-amber-700 dark:text-amber-400 block mb-1">Extrato Detalhado</span>
            <p className="text-slate-600 dark:text-slate-400">Lista cronológica de todas as transações com valores em USD e Moeda Original.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates, Currency } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, DollarSign, Briefcase, PieChart as PieChartIcon, TrendingUp, CalendarClock, Calculator, Settings, X, Save } from 'lucide-react';
import { StorageService } from '../services/storageService';

interface DashboardProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

const COLORS = ['#0ea5e9', '#10b981', '#ef4444', '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ companies, transactions, rates: initialRates, onNavigate }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));
  const [isRateModalOpen, setIsRateModalOpen] = useState(false);
  const [currentRates, setCurrentRates] = useState<ExchangeRates>(initialRates);

  // Sync state when props change
  useEffect(() => {
    if (Object.keys(initialRates).length > 0) {
      setCurrentRates(initialRates);
    }
  }, [initialRates]);

  const handleSaveRates = () => {
    StorageService.saveRates(currentRates);
    setIsRateModalOpen(false);
    window.location.reload(); 
  };

  const activeRates = currentRates;

  // Mapa de Empresas Ativas
  const activeCompanyMap = useMemo(() => {
    const map = new Map<string, Company>();
    companies.forEach(c => {
      if (c.status !== 'Encerrado') {
        map.set(c.id, c);
      }
    });
    return map;
  }, [companies]);

  // Helper para conversão para AOA (Kwanza)
  // Lógica: Converte da moeda original para USD (Base), depois de USD para AOA.
  const getConvertedToAOA = (amount: number, currency: Currency) => {
    const rateToUSD = activeRates[currency]; // Ex: 900 AOA = 1 USD
    const rateUSDToAOA = activeRates[Currency.AOA] || 900; // Taxa do Kwanza

    // Proteção contra divisão por zero
    const safeRateToUSD = (rateToUSD !== undefined && rateToUSD > 0) ? rateToUSD : 1;

    // 1. Converte para USD Base
    const amountInUSD = amount / safeRateToUSD;

    // 2. Converte USD para AOA
    return amountInUSD * rateUSDToAOA;
  };

  // Helper de formatação
  const formatAOA = (val: number) => {
    return val.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  // Cálculo de Totais (O(N))
  const totals = useMemo(() => {
    let totalIncome = 0;
    let totalExpense = 0;

    transactions.forEach(t => {
      const company = activeCompanyMap.get(t.companyId);
      if (!company) return; 

      const aoaValue = getConvertedToAOA(t.amount, company.currency);

      if (t.type === TransactionType.INCOME) {
        totalIncome += aoaValue;
      } else {
        totalExpense += aoaValue;
      }
    });

    return {
      income: totalIncome,
      expense: totalExpense,
      profit: totalIncome - totalExpense
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // Forecast (Previsão)
  const forecast = useMemo(() => {
    const today = new Date();
    const currentMonthKey = today.toISOString().slice(0, 7);

    const pastMonthsSet = new Set<string>();
    for (let i = 1; i <= 3; i++) {
        const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
        pastMonthsSet.add(d.toISOString().slice(0, 7));
    }

    const companyStats = new Map<string, {
      incomeSum: number;
      incomeMonths: Set<string>;
      fixedSum: number;
      variableSum: number;
      variableMonths: Set<string>;
    }>();

    activeCompanyMap.forEach((_, id) => {
      companyStats.set(id, {
        incomeSum: 0,
        incomeMonths: new Set(),
        fixedSum: 0,
        variableSum: 0,
        variableMonths: new Set()
      });
    });

    transactions.forEach(t => {
      const stats = companyStats.get(t.companyId);
      if (!stats) return;

      const monthKey = t.date.slice(0, 7);

      if (t.type === TransactionType.INCOME && pastMonthsSet.has(monthKey)) {
        stats.incomeSum += t.amount;
        stats.incomeMonths.add(monthKey);
      }

      if (t.type === TransactionType.EXPENSE) {
        if (t.isFixed && monthKey === currentMonthKey) {
          stats.fixedSum += t.amount;
        }
        if (!t.isFixed && pastMonthsSet.has(monthKey)) {
          stats.variableSum += t.amount;
          stats.variableMonths.add(monthKey);
        }
      }
    });

    let projectedIncome = 0;
    let projectedFixedExpense = 0;
    let projectedVariableExpense = 0;

    companyStats.forEach((stats, companyId) => {
      const company = activeCompanyMap.get(companyId)!;

      const avgIncome = stats.incomeMonths.size > 0 ? stats.incomeSum / stats.incomeMonths.size : 0;
      projectedIncome += getConvertedToAOA(avgIncome, company.currency);

      projectedFixedExpense += getConvertedToAOA(stats.fixedSum, company.currency);

      const avgVariable = stats.variableMonths.size > 0 ? stats.variableSum / stats.variableMonths.size : 0;
      projectedVariableExpense += getConvertedToAOA(avgVariable, company.currency);
    });

    const totalProjectedExpense = projectedFixedExpense + projectedVariableExpense;

    return {
        income: projectedIncome,
        expense: totalProjectedExpense,
        profit: projectedIncome - totalProjectedExpense,
        fixedShare: totalProjectedExpense > 0 ? (projectedFixedExpense / totalProjectedExpense) * 100 : 0
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // Chart Data
  const chartData = useMemo(() => {
    const last6Months = new Map<string, { name: string, income: number, expense: number }>();
    const today = new Date();

    for (let i = 5; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const key = d.toISOString().slice(0, 7);
      last6Months.set(key, {
        name: d.toLocaleDateString('pt-PT', { month: 'short' }),
        income: 0,
        expense: 0
      });
    }

    transactions.forEach(t => {
      const monthKey = t.date.slice(0, 7);
      const monthData = last6Months.get(monthKey);

      if (monthData) {
        const company = activeCompanyMap.get(t.companyId);
        if (company) {
           const val = getConvertedToAOA(t.amount, company.currency);
           if (t.type === TransactionType.INCOME) monthData.income += val;
           else monthData.expense += val;
        }
      }
    });

    return Array.from(last6Months.values()).map(d => ({
      name: d.name,
      Entradas: parseFloat(d.income.toFixed(2)),
      Saídas: parseFloat(d.expense.toFixed(2)),
      Lucro: parseFloat((d.income - d.expense).toFixed(2))
    }));

  }, [transactions, activeCompanyMap, activeRates]);

  // Pie Chart
  const pieData = useMemo(() => {
    const dataMap = new Map<string, number>();

    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(selectedMonth)) {
         const company = activeCompanyMap.get(t.companyId);
         if (company) {
             const val = getConvertedToAOA(t.amount, company.currency);
             const currentVal = dataMap.get(t.category) || 0;
             dataMap.set(t.category, currentVal + val);
         }
      }
    });

    return Array.from(dataMap.entries())
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
  }, [transactions, activeCompanyMap, activeRates, selectedMonth]);

  return (
    <div className="space-y-6 animate-fade-in relative">

      {/* Settings Modal */}
      {isRateModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl max-w-md w-full p-6 animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                <Settings className="text-brand-500" /> Configurar Taxas
              </h3>
              <button onClick={() => setIsRateModalOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                <X size={24} />
              </button>
            </div>

            <p className="text-sm text-slate-500 dark:text-slate-400 mb-4 bg-amber-50 dark:bg-amber-900/20 p-3 rounded-lg border border-amber-100 dark:border-amber-800 text-amber-800 dark:text-amber-200">
               Atenção: A aplicação usa o <b>Dólar (USD)</b> como base para cálculos. Defina quanto vale 1 USD na moeda local.
            </p>

            <div className="space-y-4">
              {Object.keys(currentRates).filter(k => k !== 'USD').map(currency => (
                <div key={currency}>
                  <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                    1 USD = ? {currency}
                  </label>
                  <input 
                    type="number" 
                    step="0.01"
                    value={currentRates[currency]}
                    onChange={(e) => setCurrentRates({...currentRates, [currency]: parseFloat(e.target.value)})}
                    className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                  />
                </div>
              ))}
            </div>

            <div className="mt-8 flex justify-end gap-3">
              <button onClick={() => setIsRateModalOpen(false)} className="px-4 py-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">Cancelar</button>
              <button onClick={handleSaveRates} className="px-4 py-2 bg-brand-600 text-white rounded-lg hover:bg-brand-700 flex items-center gap-2">
                <Save size={18} /> Salvar & Atualizar
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Visão Geral (Kwanzas)</h2>
           <div className="text-sm text-slate-500">Valores consolidados em AOA.</div>
        </div>
        <button 
          onClick={() => setIsRateModalOpen(true)}
          className="flex items-center gap-2 px-3 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg text-sm font-medium text-slate-600 dark:text-slate-300 transition-colors"
        >
          <Settings size={16} /> Configurar Câmbio
        </button>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Receita Total</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                Kz {formatAOA(totals.income)}
              </h3>
            </div>
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
