  NOTES: 'nrl_notes',
  RATES: 'nrl_rates',
  CATEGORIES: 'nrl_categories',
  DOCUMENTS: 'nrl_documents'
};

const DEFAULT_CATEGORIES: CategoryItem[] = [
  { id: '1', name: 'Vendas', type: TransactionType.INCOME },
  { id: '2', name: 'Serviços', type: TransactionType.INCOME },
  { id: '3', name: 'Fornecedores', type: TransactionType.EXPENSE },
  { id: '4', name: 'Salários', type: TransactionType.EXPENSE },
  { id: '5', name: 'Operacional', type: TransactionType.EXPENSE },
];

export const StorageService = {
  getCompanies: (): Company[] => {
    const data = localStorage.getItem(KEYS.COMPANIES);
    return data ? JSON.parse(data) : MOCK_COMPANIES;
  },

  saveCompanies: (companies: Company[]) => {
    localStorage.setItem(KEYS.COMPANIES, JSON.stringify(companies));
  },

  getTransactions: (): Transaction[] => {
    const data = localStorage.getItem(KEYS.TRANSACTIONS);
    return data ? JSON.parse(data) : MOCK_TRANSACTIONS;
  },

  saveTransactions: (transactions: Transaction[]) => {
    localStorage.setItem(KEYS.TRANSACTIONS, JSON.stringify(transactions));
  },

  getNotes: (): MonthlyNote[] => {
    const data = localStorage.getItem(KEYS.NOTES);
    return data ? JSON.parse(data) : [];
  },

  saveNotes: (notes: MonthlyNote[]) => {
    localStorage.setItem(KEYS.NOTES, JSON.stringify(notes));
  },

  getRates: (): ExchangeRates => {
    const data = localStorage.getItem(KEYS.RATES);
    return data ? JSON.parse(data) : INITIAL_RATES;
  },

  saveRates: (rates: ExchangeRates) => {
    localStorage.setItem(KEYS.RATES, JSON.stringify(rates));
  },

  getCategories: (): CategoryItem[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    return data ? JSON.parse(data) : DEFAULT_CATEGORIES;
  },

  saveCategories: (categories: CategoryItem[]) => {
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(categories));
  },

  getDocuments: (): FinancialDocument[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    return data ? JSON.parse(data) : [];
  },

  saveDocuments: (docs: FinancialDocument[]) => {
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
  }
};

import React, { useState, useEffect } from 'react';
import { Company, Transaction, MonthlyNote, ExchangeRates, ViewState, CategoryItem, TransactionType, FinancialDocument } from './types';
import { StorageService } from './services/storageService';
import { Dashboard } from './components/Dashboard';
import { CompanyManager } from './components/CompanyManager';
import { MonthDetail } from './components/MonthDetail';
import { Reports } from './components/Reports';
import { CategorySettings } from './components/CategorySettings';
import { Invoices } from './components/Invoices';
import { LayoutDashboard, Building2, Calendar, FileBarChart, Settings, Menu, X, Sun, Moon, Tag, Download, ScrollText } from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [companies, setCompanies] = useState<Company[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notes, setNotes] = useState<MonthlyNote[]>([]);
  const [rates, setRates] = useState<ExchangeRates>({});
  const [categories, setCategories] = useState<CategoryItem[]>([]);
  const [documents, setDocuments] = useState<FinancialDocument[]>([]);

  // UI State
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Initialization
  useEffect(() => {
    setCompanies(StorageService.getCompanies());
    setTransactions(StorageService.getTransactions());
    setNotes(StorageService.getNotes());
    setRates(StorageService.getRates());
    setCategories(StorageService.getCategories());
    setDocuments(StorageService.getDocuments());

    // Check system preference for dark mode
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setIsDarkMode(true);
    }

    // PWA Install Event Listener
    const handleBeforeInstallPrompt = (e: Event) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setDeferredPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    // Cleanup function
    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  // Theme Toggle Effect
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // PWA Install Handler
  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    // Show the install prompt
    deferredPrompt.prompt();
    // Wait for the user to respond to the prompt
    const { outcome } = await deferredPrompt.userChoice;
    console.log(`User response to the install prompt: ${outcome}`);
    // We've used the prompt, and can't use it again, throw it away
    setDeferredPrompt(null);
  };

  // Handlers
  const handleSaveCompany = (company: Company) => {
    const exists = companies.find(c => c.id === company.id);
    let newCompanies;
    if (exists) {
      newCompanies = companies.map(c => c.id === company.id ? company : c);
    } else {
      newCompanies = [...companies, company];
    }
    setCompanies(newCompanies);
    StorageService.saveCompanies(newCompanies);
  };

  const handleDeleteCompany = (id: string) => {
    if (confirm('Tem certeza? Todas as transações desta empresa serão ocultas.')) {
      const newCompanies = companies.filter(c => c.id !== id);
      setCompanies(newCompanies);
      StorageService.saveCompanies(newCompanies);
    }
  };

  const handleAddTransaction = (t: Transaction) => {
    const newTransactions = [...transactions, t];
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleDeleteTransaction = (id: string) => {
    const newTransactions = transactions.filter(t => t.id !== id);
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleSaveNote = (note: MonthlyNote) => {
    const filteredNotes = notes.filter(n => !(n.companyId === note.companyId && n.monthStr === note.monthStr));
    const newNotes = [...filteredNotes, note];
    setNotes(newNotes);
    StorageService.saveNotes(newNotes);
  };

  const handleSaveDocument = (doc: FinancialDocument) => {
    const exists = documents.find(d => d.id === doc.id);
    let newDocs;
    if (exists) {
      newDocs = documents.map(d => d.id === doc.id ? doc : d);
    } else {
      newDocs = [...documents, doc];
    }
    setDocuments(newDocs);
    StorageService.saveDocuments(newDocs);
  }

  const handleDeleteDocument = (id: string) => {
     if(confirm("Deseja apagar este documento permanentemente?")) {
        const newDocs = documents.filter(d => d.id !== id);
        setDocuments(newDocs);
        StorageService.saveDocuments(newDocs);
     }
  }

  // Category Handlers
  const handleAddCategory = (name: string, type: TransactionType) => {
    if (categories.some(c => c.name.toLowerCase() === name.toLowerCase() && c.type === type)) return;
    const newCategory: CategoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      type
    };
    const updatedCategories = [...categories, newCategory];
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);
  };

  const handleEditCategory = (id: string, newName: string) => {
    const oldCategory = categories.find(c => c.id === id);
    if (!oldCategory) return;
    const updatedCategories = categories.map(c => c.id === id ? { ...c, name: newName } : c);
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);
    const updatedTransactions = transactions.map(t => 
      (t.category === oldCategory.name && t.type === oldCategory.type) ? { ...t, category: newName } : t
    );
    setTransactions(updatedTransactions);
    StorageService.saveTransactions(updatedTransactions);
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('Ao eliminar a categoria, ela deixará de aparecer nas sugestões, mas as transações antigas serão mantidas. Continuar?')) {
      const updatedCategories = categories.filter(c => c.id !== id);
      setCategories(updatedCategories);
      StorageService.saveCategories(updatedCategories);
    }
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => (
    <button
      onClick={() => { setCurrentView(view); setIsSidebarOpen(false); }}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
        currentView === view 
          ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' 
          : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans">

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black/50 lg:hidden backdrop-blur-sm"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed lg:static inset-y-0 left-0 z-30 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transform transition-transform duration-300 ease-in-out flex flex-col
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3">
          <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">
            R
          </div>
          <h1 className="text-xl font-bold tracking-tight text-slate-800 dark:text-white">Rota do Lucro</h1>
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          <NavItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem view="invoices" icon={ScrollText} label="Orçamentos e Faturas" />
          <NavItem view="month-detail" icon={Calendar} label="Gestão Mensal" />
          <NavItem view="companies" icon={Building2} label="Empresas" />
          <NavItem view="categories" icon={Tag} label="Categorias" />
          <NavItem view="reports" icon={FileBarChart} label="Relatórios" />
        </nav>

        <div className="p-4 border-t border-slate-100 dark:border-slate-800 space-y-4">
           {deferredPrompt && (
             <button onClick={handleInstallClick} className="w-full flex items-center justify-center gap-2 p-3 rounded-lg bg-emerald-600 hover:bg-emerald-700 text-white font-medium shadow-md transition-colors animate-pulse">
               <Download size={18} /> Instalar App
             </button>
           )}
           <div className="bg-slate-50 dark:bg-slate-800 rounded-xl p-4">
              <p className="text-xs text-slate-500 dark:text-slate-400 mb-2">Modo Escuro</p>
              <button onClick={() => setIsDarkMode(!isDarkMode)} className="w-full flex items-center justify-between p-2 rounded-lg bg-white dark:bg-slate-700 shadow-sm border border-slate-200 dark:border-slate-600">
                 <span className="text-sm font-medium flex items-center gap-2">{isDarkMode ? <Moon size={14} /> : <Sun size={14} />} {isDarkMode ? 'Ativado' : 'Desativado'}</span>
                 <div className={`w-8 h-4 rounded-full relative transition-colors ${isDarkMode ? 'bg-brand-600' : 'bg-slate-300'}`}><div className={`absolute top-0.5 left-0.5 w-3 h-3 bg-white rounded-full transition-transform ${isDarkMode ? 'translate-x-4' : 'translate-x-0'}`} /></div>
              </button>
           </div>
           <div className="text-xs text-center text-slate-400">v1.3.0 (Docs)</div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        <header className="h-16 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 flex items-center justify-between px-6 sticky top-0 z-10">
          <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><Menu size={24} /></button>
          <div className="text-sm font-medium text-slate-500 dark:text-slate-400">
             {currentView === 'dashboard' && 'Visão Geral'}
             {currentView === 'companies' && 'Cadastro de Clientes'}
             {currentView === 'month-detail' && 'Lançamentos e Análise'}
             {currentView === 'categories' && 'Personalização de Categorias'}
             {currentView === 'reports' && 'Exportação'}
             {currentView === 'invoices' && 'Gerador de Documentos'}
          </div>
          <div className="flex items-center gap-4"><div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700 flex items-center justify-center text-slate-600 dark:text-slate-300 font-bold text-xs">AD</div></div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 scrollbar-hide">
          <div className="max-w-7xl mx-auto animate-fade-in">
            {currentView === 'dashboard' && <Dashboard companies={companies} transactions={transactions} rates={rates} onNavigate={setCurrentView} />}
            {currentView === 'companies' && <CompanyManager companies={companies} onSave={handleSaveCompany} onDelete={handleDeleteCompany} />}
            {currentView === 'month-detail' && <MonthDetail companies={companies} transactions={transactions} notes={notes} categories={categories} rates={rates} onAddTransaction={handleAddTransaction} onDeleteTransaction={handleDeleteTransaction} onSaveNote={handleSaveNote} onAutoAddCategory={handleAddCategory} />}
            {currentView === 'categories' && <CategorySettings categories={categories} onAdd={handleAddCategory} onEdit={handleEditCategory} onDelete={handleDeleteCategory} />}
            {currentView === 'reports' && <Reports companies={companies} transactions={transactions} rates={rates} />}
            {currentView === 'invoices' && <Invoices companies={companies} documents={documents} onSave={handleSaveDocument} onDelete={handleDeleteDocument} rates={rates} />}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Company, FinancialDocument, DocumentType, DocumentStatus, InvoiceItem, ExchangeRates } from '../types';
import { Plus, Printer, Share2, FileText, ArrowRight, Trash2, CheckCircle, X, Search, FileCheck } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface InvoicesProps {
  companies: Company[];
  documents: FinancialDocument[];
  onSave: (doc: FinancialDocument) => void;
  onDelete: (id: string) => void;
  rates: ExchangeRates;
}

export const Invoices: React.FC<InvoicesProps> = ({ companies, documents, onSave, onDelete, rates }) => {
  const [mode, setMode] = useState<'list' | 'create' | 'edit'>('list');
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [formData, setFormData] = useState<Partial<FinancialDocument>>({
    items: [],
    type: DocumentType.BUDGET,
    status: DocumentStatus.DRAFT,
    date: new Date().toISOString().split('T')[0]
  });

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // --- FILTROS & LISTAGEM ---
  const filteredDocs = useMemo(() => {
    return documents.filter(d => d.companyId === selectedCompanyId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [documents, selectedCompanyId]);

  // --- LÓGICA DE FORMULÁRIO ---
  const handleNewDoc = () => {
    if (!selectedCompany) {
      alert("Selecione uma empresa primeiro.");
      return;
    }

    // Auto number logic: Count docs of this type for this company
    const count = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.BUDGET).length;
    const nextNum = count + 1;
    const year = new Date().getFullYear();

    setFormData({
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: DocumentType.BUDGET,
      status: DocumentStatus.DRAFT,
      number: `ORC-${nextNum.toString().padStart(3, '0')}/${year}`,
      date: new Date().toISOString().split('T')[0],
      items: [{ id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }],
      clientName: '',
      clientPhone: '',
      clientTaxID: '',
      notes: 'Este orçamento é válido por 15 dias.'
    });
    setMode('create');
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...(prev.items || []), { id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (itemId: string) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).filter(i => i.id !== itemId)
    }));
  };

  const handleItemChange = (itemId: string, field: keyof InvoiceItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).map(i => i.id === itemId ? { ...i, [field]: value } : i)
    }));
  };

  const calculateTotal = (items: InvoiceItem[] = []) => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.clientName && formData.items && formData.items.length > 0) {
      onSave(formData as FinancialDocument);
      setMode('list');
    } else {
      alert("Preencha o nome do cliente e adicione pelo menos um item.");
    }
  };

  // --- LÓGICA DE AÇÕES ---

  const handleConvertToInvoice = (doc: FinancialDocument) => {
    if (confirm(`Converter orçamento ${doc.number} em Fatura Definitiva?`)) {
       // 1. Marcar orçamento como Aprovado
       onSave({ ...doc, status: DocumentStatus.APPROVED });

       // 2. Criar nova Fatura baseada no orçamento
       const countInv = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.INVOICE).length;
       const nextNum = countInv + 1;
       const year = new Date().getFullYear();

       const newInvoice: FinancialDocument = {
         ...doc,
         id: Math.random().toString(36).substr(2, 9),
         type: DocumentType.INVOICE,
         status: DocumentStatus.SENT,
         number: `FAT-${nextNum.toString().padStart(3, '0')}/${year}`,
         date: new Date().toISOString().split('T')[0],
         notes: 'Obrigado pela preferência.',
         createdAt: Date.now()
       };
       onSave(newInvoice);
       alert(`Fatura ${newInvoice.number} gerada com sucesso!`);
    }
  };

  const handleWhatsApp = (doc: FinancialDocument) => {
    if (!doc.clientPhone) {
      alert("Adicione o telefone do cliente para enviar por WhatsApp.");
      return;
    }
    const total = calculateTotal(doc.items);
    const currency = selectedCompany?.currency || 'AOA';
    const text = `Olá ${doc.clientName}, segue o ${doc.type} ${doc.number} no valor de ${total.toLocaleString()} ${currency}. Por favor verifique o PDF em anexo (se enviado) ou contacte-nos.`;
    const url = `https://wa.me/${doc.clientPhone.replace(/[^0-9]/g, '')}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const handlePDF = (doc: FinancialDocument) => {
    if (!selectedCompany) return;

    const pdf = new jsPDF();
    const pageWidth = pdf.internal.pageSize.width;
    const currency = selectedCompany.currency;

    // Header Color Stripe
    const primaryColor = doc.type === DocumentType.INVOICE ? [16, 185, 129] : [14, 165, 233]; // Green for Invoice, Blue for Budget
    pdf.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.rect(0, 0, pageWidth, 40, 'F');

    // Title & Company
    pdf.setTextColor(255, 255, 255);
    pdf.setFontSize(24);
    pdf.setFont("helvetica", "bold");
    pdf.text(doc.type.toUpperCase(), 14, 25);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "normal");
    pdf.text(`#${doc.number}`, pageWidth - 40, 25);

    pdf.setFontSize(14);
    pdf.text(selectedCompany.name, 14, 35);

    // Info Section
    pdf.setTextColor(60, 60, 60);
    let yPos = 55;

    // Client Info
    pdf.setFontSize(11);
    pdf.setFont("helvetica", "bold");
    pdf.text("CLIENTE:", 14, yPos);
    pdf.setFont("helvetica", "normal");
    pdf.text(doc.clientName, 14, yPos + 6);
    if(doc.clientTaxID) pdf.text(`NIF: ${doc.clientTaxID}`, 14, yPos + 12);
    if(doc.clientPhone) pdf.text(`Tel: ${doc.clientPhone}`, 14, yPos + 18);

    // Date Info
    pdf.setFont("helvetica", "bold");
    pdf.text("DETALHES:", pageWidth - 80, yPos);
    pdf.setFont("helvetica", "normal");
    pdf.text(`Data de Emissão: ${new Date(doc.date).toLocaleDateString()}`, pageWidth - 80, yPos + 6);
    pdf.text(`Status: ${doc.status}`, pageWidth - 80, yPos + 12);
    if (doc.dueDate) pdf.text(`Vencimento: ${new Date(doc.dueDate).toLocaleDateString()}`, pageWidth - 80, yPos + 18);

    yPos += 30;

    // Table
    const tableRows = doc.items.map(item => [
      item.description,
      item.quantity,
      `${item.unitPrice.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`,
      `${(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`
    ]);

    autoTable(pdf, {
      startY: yPos,
      head: [['Descrição', 'Qtd', `Preço Unit (${currency})`, `Total (${currency})`]],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: primaryColor, textColor: 255, fontStyle: 'bold' },
      columnStyles: {
        1: { halign: 'center' },
        2: { halign: 'right' },
        3: { halign: 'right', fontStyle: 'bold' }
      }
    });

    // @ts-ignore
    const finalY = pdf.lastAutoTable.finalY + 10;

    // Total
    const total = calculateTotal(doc.items);
    pdf.setFontSize(14);
    pdf.setFont("helvetica", "bold");
    pdf.text(`TOTAL: ${currency} ${total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`, pageWidth - 14, finalY, { align: 'right' });

    // Footer / Notes
    if (doc.notes) {
      pdf.setFontSize(10);
      pdf.setFont("helvetica", "italic");
      pdf.setTextColor(100, 100, 100);
      pdf.text(`Notas: ${doc.notes}`, 14, finalY + 20);
    }

    // Bottom Branding
    pdf.setFontSize(8);
    pdf.text("Gerado por Na Rota do Lucro", pageWidth / 2, 290, { align: 'center' });

    pdf.save(`${doc.type}_${doc.clientName.replace(/\s/g, '_')}_${doc.number}.pdf`);
  };

  // --- RENDER ---

  if (mode === 'create' || mode === 'edit') {
    return (
      <div className="max-w-4xl mx-auto animate-fade-in">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <FileText className="text-brand-500" />
            {mode === 'create' ? `Novo ${formData.type}` : `Editar ${formData.number}`}
          </h2>
          <button onClick={() => setMode('list')} className="text-slate-500 hover:text-slate-700 dark:text-slate-400">
             <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">

          {/* Header Data */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tipo de Doc</label>
               <select 
                 value={formData.type} 
                 onChange={e => setFormData({...formData, type: e.target.value as DocumentType})}
                 className="w-full p-2 rounded border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                 disabled={mode === 'edit'}
               >
                 <option value={DocumentType.BUDGET}>{DocumentType.BUDGET}</option>
                 <option value={DocumentType.INVOICE}>{DocumentType.INVOICE}</option>
               </select>
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Número</label>
               <input 
                 type="text" 
                 value={formData.number} 
                 readOnly 
                 className="w-full p-2 rounded border bg-slate-100 dark:bg-slate-900 text-slate-500 cursor-not-allowed" 
               />
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data</label>
               <input 
                 type="date" 
                 value={formData.date} 
                 onChange={e => setFormData({...formData, date: e.target.value})}
                 className="w-full p-2 rounded border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white" 
               />
             </div>
          </div>

          {/* Client Data */}
          <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg mb-6 border border-slate-200 dark:border-slate-700">
            <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-3">Dados do Cliente</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input 
                 placeholder="Nome do Cliente *" 
                 value={formData.clientName}
                 onChange={e => setFormData({...formData, clientName: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                 required
              />
              <input 
                 placeholder="Telefone (WhatsApp) Ex: 244923..." 
                 value={formData.clientPhone}
                 onChange={e => setFormData({...formData, clientPhone: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
              <input 
                 placeholder="NIF (Opcional)" 
                 value={formData.clientTaxID}
                 onChange={e => setFormData({...formData, clientTaxID: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
            </div>
          </div>

          {/* Items */}
          <div className="mb-6">
            <div className="flex justify-between items-center mb-2">
               <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300">Itens / Serviços</h3>
            </div>
            <table className="w-full text-sm">
              <thead className="bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300">
                <tr>
                  <th className="p-2 text-left">Descrição</th>
                  <th className="p-2 w-20 text-center">Qtd</th>
                  <th className="p-2 w-32 text-right">Preço Unit</th>
                  <th className="p-2 w-32 text-right">Total</th>
                  <th className="p-2 w-10"></th>
                </tr>
              </thead>
              <tbody>
                {formData.items?.map(item => (
                  <tr key={item.id} className="border-b dark:border-slate-700">
                    <td className="p-2">
                      <input 
                        value={item.description}
                        onChange={e => handleItemChange(item.id, 'description', e.target.value)}
                        placeholder="Ex: Consultoria"
                        className="w-full p-1 bg-transparent outline-none dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="1"
                        value={item.quantity}
                        onChange={e => handleItemChange(item.id, 'quantity', parseInt(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-center dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="0"
                        value={item.unitPrice}
                        onChange={e => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-right dark:text-white"
                      />
                    </td>
                    <td className="p-2 text-right font-medium dark:text-white">
                      {(item.quantity * item.unitPrice).toLocaleString()}
                    </td>
                    <td className="p-2 text-center">
                      <button type="button" onClick={() => handleRemoveItem(item.id)} className="text-rose-400 hover:text-rose-600"><Trash2 size={14} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button type="button" onClick={handleAddItem} className="mt-2 text-sm text-brand-600 font-medium flex items-center gap-1 hover:underline">
              <Plus size={14} /> Adicionar Item
            </button>
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start gap-6 border-t dark:border-slate-700 pt-6">
            <div className="w-full md:w-1/2">
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Notas / Termos</label>
               <textarea 
                 value={formData.notes}
                 onChange={e => setFormData({...formData, notes: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white text-sm h-24"
               />
            </div>
            <div className="w-full md:w-1/3 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg">
               <div className="flex justify-between items-center text-lg font-bold text-slate-800 dark:text-white">
                 <span>Total ({selectedCompany?.currency})</span>
                 <span>{calculateTotal(formData.items).toLocaleString()}</span>
               </div>
               <button type="submit" className="w-full mt-4 py-3 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg shadow-lg flex justify-center items-center gap-2">
                 <CheckCircle size={18} /> Salvar Documento
               </button>
            </div>
          </div>

        </form>
      </div>
    );
  }

  return (
    <div className="space-y-6">
       {/* Toolbar */}
       <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col md:flex-row justify-between items-center gap-4">
         <div>
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">Orçamentos & Faturas</h2>
            <p className="text-sm text-slate-500 dark:text-slate-400">Gira documentos profissionais em {selectedCompany?.currency || 'AOA'}</p>
         </div>
         <div className="flex items-center gap-3">
            <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="p-2 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
            >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <button 
              onClick={handleNewDoc}
              className="bg-brand-600 hover:bg-brand-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 shadow-md"
            >
              <Plus size={18} /> Novo Orçamento
            </button>
         </div>
       </div>

       {/* List */}
       <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
         {filteredDocs.length === 0 ? (
           <div className="p-12 text-center text-slate-400">
             <FileText className="mx-auto w-12 h-12 mb-3 opacity-30" />
             <p>Nenhum documento criado para esta empresa.</p>
           </div>
         ) : (
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-500 dark:text-slate-400 text-xs uppercase">
                 <tr>
                   <th className="p-4">Número</th>
                   <th className="p-4">Cliente</th>
                   <th className="p-4">Data</th>
                   <th className="p-4 text-center">Status</th>
                   <th className="p-4 text-right">Total</th>
                   <th className="p-4 text-center">Ações</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                 {filteredDocs.map(doc => (
                   <tr key={doc.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                     <td className="p-4 font-medium text-slate-700 dark:text-slate-200 flex items-center gap-2">
                       {doc.type === DocumentType.INVOICE ? <CheckCircle size={16} className="text-emerald-500" /> : <FileText size={16} className="text-brand-500" />}
                       {doc.number}
                     </td>
                     <td className="p-4 text-slate-600 dark:text-slate-300">
                       <div className="font-medium">{doc.clientName}</div>
                       <div className="text-xs text-slate-400">{doc.clientPhone || '-'}</div>
                     </td>
                     <td className="p-4 text-sm text-slate-500 dark:text-slate-400">
                       {new Date(doc.date).toLocaleDateString()}
                     </td>
                     <td className="p-4 text-center">
                       <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                         doc.status === DocumentStatus.DRAFT ? 'bg-slate-100 text-slate-600' :
                         doc.status === DocumentStatus.SENT ? 'bg-blue-100 text-blue-600' :
                         doc.status === DocumentStatus.APPROVED ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.PAUSED ? 'bg-amber-100 text-amber-600' : ''
                       }`}>
                         {doc.status}
                       </span>
                     </td>
                     <td className="p-4 text-right font-bold text-slate-700 dark:text-white">
                        {calculateTotal(doc.items).toLocaleString()} <span className="text-xs font-normal text-slate-400">{selectedCompany?.currency}</span>
                     </td>
                     <td className="p-4">
                       <div className="flex items-center justify-center gap-2">
                         <button onClick={() => handleWhatsApp(doc)} className="p-2 text-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg" title="Enviar WhatsApp">
                           <Share2 size={18} />
                         </button>
                         <button onClick={() => handlePDF(doc)} className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg" title="Baixar PDF">
                           <Printer size={18} />
                         </button>
                         {doc.type === DocumentType.BUDGET && (
                           <button onClick={() => handleConvertToInvoice(doc)} className="p-2 text-brand-600 hover:bg-brand-50 dark:hover:bg-brand-900/20 rounded-lg" title="Converter em Fatura">
                             <ArrowRight size={18} />
                           </button>
                         )}
                         <button onClick={() => onDelete(doc.id)} className="p-2 text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg" title="Apagar">
                           <Trash2 size={18} />
                         </button>
                       </div>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
           </div>
         )}
       </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Company, FinancialDocument, DocumentType, DocumentStatus, InvoiceItem, ExchangeRates } from '../types';
import { Plus, Printer, Share2, FileText, ArrowRight, Trash2, CheckCircle, X, Search, FileCheck } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface InvoicesProps {
  companies: Company[];
  documents: FinancialDocument[];
  onSave: (doc: FinancialDocument) => void;
  onDelete: (id: string) => void;
  rates: ExchangeRates;
}

export const Invoices: React.FC<InvoicesProps> = ({ companies, documents, onSave, onDelete, rates }) => {
  const [mode, setMode] = useState<'list' | 'create' | 'edit'>('list');
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [formData, setFormData] = useState<Partial<FinancialDocument>>({
    items: [],
    type: DocumentType.BUDGET,
    status: DocumentStatus.DRAFT,
    date: new Date().toISOString().split('T')[0]
  });

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // --- FILTROS & LISTAGEM ---
  const filteredDocs = useMemo(() => {
    return documents.filter(d => d.companyId === selectedCompanyId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [documents, selectedCompanyId]);

  // --- LÓGICA DE FORMULÁRIO ---
  const handleNewDoc = () => {
    if (!selectedCompany) {
      alert("Selecione uma empresa primeiro.");
      return;
    }

    // Auto number logic: Count docs of this type for this company
    const count = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.BUDGET).length;
    const nextNum = count + 1;
    const year = new Date().getFullYear();

    setFormData({
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: DocumentType.BUDGET,
      status: DocumentStatus.DRAFT,
      number: `ORC-${nextNum.toString().padStart(3, '0')}/${year}`,
      date: new Date().toISOString().split('T')[0],
      items: [{ id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }],
      clientName: '',
      clientPhone: '',
      clientTaxID: '',
      notes: 'Este orçamento é válido por 15 dias.'
    });
    setMode('create');
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...(prev.items || []), { id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (itemId: string) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).filter(i => i.id !== itemId)
    }));
  };

  const handleItemChange = (itemId: string, field: keyof InvoiceItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).map(i => i.id === itemId ? { ...i, [field]: value } : i)
    }));
  };

  const calculateTotal = (items: InvoiceItem[] = []) => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.clientName && formData.items && formData.items.length > 0) {
      onSave(formData as FinancialDocument);
      setMode('list');
    } else {
      alert("Preencha o nome do cliente e adicione pelo menos um item.");
    }
  };

  // --- LÓGICA DE AÇÕES ---

  const handleConvertToInvoice = (doc: FinancialDocument) => {
    if (confirm(`Converter orçamento ${doc.number} em Fatura Definitiva?`)) {
       // 1. Marcar orçamento como Aprovado
       onSave({ ...doc, status: DocumentStatus.APPROVED });

       // 2. Criar nova Fatura baseada no orçamento
       const countInv = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.INVOICE).length;
       const nextNum = countInv + 1;
       const year = new Date().getFullYear();

       const newInvoice: FinancialDocument = {
         ...doc,
         id: Math.random().toString(36).substr(2, 9),
         type: DocumentType.INVOICE,
         status: DocumentStatus.SENT,
         number: `FAT-${nextNum.toString().padStart(3, '0')}/${year}`,
         date: new Date().toISOString().split('T')[0],
         notes: 'Obrigado pela preferência.',
         createdAt: Date.now()
       };
       onSave(newInvoice);
       alert(`Fatura ${newInvoice.number} gerada com sucesso!`);
    }
  };

  const handleWhatsApp = (doc: FinancialDocument) => {
    if (!doc.clientPhone) {
      alert("Adicione o telefone do cliente para enviar por WhatsApp.");
      return;
    }
    const total = calculateTotal(doc.items);
    const currency = selectedCompany?.currency || 'AOA';
    const text = `Olá ${doc.clientName}, segue o ${doc.type} ${doc.number} no valor de ${total.toLocaleString()} ${currency}. Por favor verifique o PDF em anexo (se enviado) ou contacte-nos.`;
    const url = `https://wa.me/${doc.clientPhone.replace(/[^0-9]/g, '')}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const handlePDF = (doc: FinancialDocument) => {
    if (!selectedCompany) return;

    const pdf = new jsPDF();
    const pageWidth = pdf.internal.pageSize.width;
    const currency = selectedCompany.currency;

    // Header Color Stripe
    const primaryColor = doc.type === DocumentType.INVOICE ? [16, 185, 129] : [14, 165, 233]; // Green for Invoice, Blue for Budget
    pdf.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.rect(0, 0, pageWidth, 40, 'F');

    // Title & Company
    pdf.setTextColor(255, 255, 255);
    pdf.setFontSize(24);
    pdf.setFont("helvetica", "bold");
    pdf.text(doc.type.toUpperCase(), 14, 25);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "normal");
    pdf.text(`#${doc.number}`, pageWidth - 40, 25);

    pdf.setFontSize(14);
    pdf.text(selectedCompany.name, 14, 35);

    // Info Section
    pdf.setTextColor(60, 60, 60);
    let yPos = 55;

    // Client Info
    pdf.setFontSize(11);
    pdf.setFont("helvetica", "bold");
    pdf.text("CLIENTE:", 14, yPos);
    pdf.setFont("helvetica", "normal");
    pdf.text(doc.clientName, 14, yPos + 6);
    if(doc.clientTaxID) pdf.text(`NIF: ${doc.clientTaxID}`, 14, yPos + 12);
    if(doc.clientPhone) pdf.text(`Tel: ${doc.clientPhone}`, 14, yPos + 18);

    // Date Info
    pdf.setFont("helvetica", "bold");
    pdf.text("DETALHES:", pageWidth - 80, yPos);
    pdf.setFont("helvetica", "normal");
    pdf.text(`Data de Emissão: ${new Date(doc.date).toLocaleDateString()}`, pageWidth - 80, yPos + 6);
    pdf.text(`Status: ${doc.status}`, pageWidth - 80, yPos + 12);
    if (doc.dueDate) pdf.text(`Vencimento: ${new Date(doc.dueDate).toLocaleDateString()}`, pageWidth - 80, yPos + 18);

    yPos += 30;

    // Table
    const tableRows = doc.items.map(item => [
      item.description,
      item.quantity,
      `${item.unitPrice.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`,
      `${(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`
    ]);

    autoTable(pdf, {
      startY: yPos,
      head: [['Descrição', 'Qtd', `Preço Unit (${currency})`, `Total (${currency})`]],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: primaryColor, textColor: 255, fontStyle: 'bold' },
      columnStyles: {
        1: { halign: 'center' },
        2: { halign: 'right' },
        3: { halign: 'right', fontStyle: 'bold' }
      }
    });

    // @ts-ignore
    const finalY = pdf.lastAutoTable.finalY + 10;

    // Total
    const total = calculateTotal(doc.items);
    pdf.setFontSize(14);
    pdf.setFont("helvetica", "bold");
    pdf.text(`TOTAL: ${currency} ${total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`, pageWidth - 14, finalY, { align: 'right' });

    // Footer / Notes
    if (doc.notes) {
      pdf.setFontSize(10);
      pdf.setFont("helvetica", "italic");
      pdf.setTextColor(100, 100, 100);
      pdf.text(`Notas: ${doc.notes}`, 14, finalY + 20);
    }

    // Bottom Branding
    pdf.setFontSize(8);
    pdf.text("Gerado por Na Rota do Lucro", pageWidth / 2, 290, { align: 'center' });

    pdf.save(`${doc.type}_${doc.clientName.replace(/\s/g, '_')}_${doc.number}.pdf`);
  };

  // --- RENDER ---

  if (mode === 'create' || mode === 'edit') {
    return (
      <div className="max-w-4xl mx-auto animate-fade-in">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <FileText className="text-brand-500" />
            {mode === 'create' ? `Novo ${formData.type}` : `Editar ${formData.number}`}
          </h2>
          <button onClick={() => setMode('list')} className="text-slate-500 hover:text-slate-700 dark:text-slate-400">
             <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">

          {/* Header Data */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tipo de Doc</label>
               <select 
                 value={formData.type} 
                 onChange={e => setFormData({...formData, type: e.target.value as DocumentType})}
                 className="w-full p-2 rounded border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                 disabled={mode === 'edit'}
               >
                 <option value={DocumentType.BUDGET}>{DocumentType.BUDGET}</option>
                 <option value={DocumentType.INVOICE}>{DocumentType.INVOICE}</option>
               </select>
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Número</label>
               <input 
                 type="text" 
                 value={formData.number} 
                 readOnly 
                 className="w-full p-2 rounded border bg-slate-100 dark:bg-slate-900 text-slate-500 cursor-not-allowed" 
               />
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data</label>
               <input 
                 type="date" 
                 value={formData.date} 
                 onChange={e => setFormData({...formData, date: e.target.value})}
                 className="w-full p-2 rounded border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white" 
               />
             </div>
          </div>

          {/* Client Data */}
          <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg mb-6 border border-slate-200 dark:border-slate-700">
            <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-3">Dados do Cliente</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input 
                 placeholder="Nome do Cliente *" 
                 value={formData.clientName}
                 onChange={e => setFormData({...formData, clientName: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                 required
              />
              <input 
                 placeholder="Telefone (WhatsApp) Ex: 244923..." 
                 value={formData.clientPhone}
                 onChange={e => setFormData({...formData, clientPhone: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
              <input 
                 placeholder="NIF (Opcional)" 
                 value={formData.clientTaxID}
                 onChange={e => setFormData({...formData, clientTaxID: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
            </div>
          </div>

          {/* Items */}
          <div className="mb-6">
            <div className="flex justify-between items-center mb-2">
               <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300">Itens / Serviços</h3>
            </div>
            <table className="w-full text-sm">
              <thead className="bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300">
                <tr>
                  <th className="p-2 text-left">Descrição</th>
                  <th className="p-2 w-20 text-center">Qtd</th>
                  <th className="p-2 w-32 text-right">Preço Unit</th>
                  <th className="p-2 w-32 text-right">Total</th>
                  <th className="p-2 w-10"></th>
                </tr>
              </thead>
              <tbody>
                {formData.items?.map(item => (
                  <tr key={item.id} className="border-b dark:border-slate-700">
                    <td className="p-2">
                      <input 
                        value={item.description}
                        onChange={e => handleItemChange(item.id, 'description', e.target.value)}
                        placeholder="Ex: Consultoria"
                        className="w-full p-1 bg-transparent outline-none dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="1"
                        value={item.quantity}
                        onChange={e => handleItemChange(item.id, 'quantity', parseInt(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-center dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="0"
                        value={item.unitPrice}
                        onChange={e => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-right dark:text-white"
                      />
                    </td>
                    <td className="p-2 text-right font-medium dark:text-white">
                      {(item.quantity * item.unitPrice).toLocaleString()}
                    </td>
                    <td className="p-2 text-center">
                      <button type="button" onClick={() => handleRemoveItem(item.id)} className="text-rose-400 hover:text-rose-600"><Trash2 size={14} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button type="button" onClick={handleAddItem} className="mt-2 text-sm text-brand-600 font-medium flex items-center gap-1 hover:underline">
              <Plus size={14} /> Adicionar Item
            </button>
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start gap-6 border-t dark:border-slate-700 pt-6">
            <div className="w-full md:w-1/2">
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Notas / Termos</label>
               <textarea 
                 value={formData.notes}
                 onChange={e => setFormData({...formData, notes: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white text-sm h-24"
               />
            </div>
            <div className="w-full md:w-1/3 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg">
               <div className="flex justify-between items-center text-lg font-bold text-slate-800 dark:text-white">
                 <span>Total ({selectedCompany?.currency})</span>
                 <span>{calculateTotal(formData.items).toLocaleString()}</span>
               </div>
               <button type="submit" className="w-full mt-4 py-3 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg shadow-lg flex justify-center items-center gap-2">
                 <CheckCircle size={18} /> Salvar Documento
               </button>
            </div>
          </div>

        </form>
      </div>
    );
  }

  return (
    <div className="space-y-6">
       {/* Toolbar */}
       <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col md:flex-row justify-between items-center gap-4">
         <div>
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">Orçamentos & Faturas</h2>
            <p className="text-sm text-slate-500 dark:text-slate-400">Gira documentos profissionais em {selectedCompany?.currency || 'AOA'}</p>
         </div>
         <div className="flex items-center gap-3">
            <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="p-2 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
            >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <button 
              onClick={handleNewDoc}
              className="bg-brand-600 hover:bg-brand-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 shadow-md"
            >
              <Plus size={18} /> Novo Orçamento
            </button>
         </div>
       </div>

       {/* List */}
       <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
         {filteredDocs.length === 0 ? (
           <div className="p-12 text-center text-slate-400">
             <FileText className="mx-auto w-12 h-12 mb-3 opacity-30" />
             <p>Nenhum documento criado para esta empresa.</p>
           </div>
         ) : (
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-500 dark:text-slate-400 text-xs uppercase">
                 <tr>
                   <th className="p-4">Número</th>
                   <th className="p-4">Cliente</th>
                   <th className="p-4">Data</th>
                   <th className="p-4 text-center">Status</th>
                   <th className="p-4 text-right">Total</th>
                   <th className="p-4 text-center">Ações</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                 {filteredDocs.map(doc => (
                   <tr key={doc.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                     <td className="p-4 font-medium text-slate-700 dark:text-slate-200 flex items-center gap-2">
                       {doc.type === DocumentType.INVOICE ? <CheckCircle size={16} className="text-emerald-500" /> : <FileText size={16} className="text-brand-500" />}
                       {doc.number}
                     </td>
                     <td className="p-4 text-slate-600 dark:text-slate-300">
                       <div className="font-medium">{doc.clientName}</div>
                       <div className="text-xs text-slate-400">{doc.clientPhone || '-'}</div>
                     </td>
                     <td className="p-4 text-sm text-slate-500 dark:text-slate-400">
                       {new Date(doc.date).toLocaleDateString()}
                     </td>
                     <td className="p-4 text-center">
                       <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                         doc.status === DocumentStatus.DRAFT ? 'bg-slate-100 text-slate-600' :
                         doc.status === DocumentStatus.SENT ? 'bg-blue-100 text-blue-600' :
                         doc.status === DocumentStatus.APPROVED ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.PAID ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.CANCELLED ? 'bg-rose-100 text-rose-600' : ''
                       }`}>
                         {doc.status}
                       </span>
                     </td>
                     <td className="p-4 text-right font-bold text-slate-700 dark:text-white">
                        {calculateTotal(doc.items).toLocaleString()} <span className="text-xs font-normal text-slate-400">{selectedCompany?.currency}</span>
                     </td>
                     <td className="p-4">
                       <div className="flex items-center justify-center gap-2">
                         <button onClick={() => handleWhatsApp(doc)} className="p-2 text-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg" title="Enviar WhatsApp">
                           <Share2 size={18} />
                         </button>
                         <button onClick={() => handlePDF(doc)} className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg" title="Baixar PDF">
                           <Printer size={18} />
                         </button>
                         {doc.type === DocumentType.BUDGET && (
                           <button onClick={() => handleConvertToInvoice(doc)} className="p-2 text-brand-600 hover:bg-brand-50 dark:hover:bg-brand-900/20 rounded-lg" title="Converter em Fatura">
                             <ArrowRight size={18} />
                           </button>
                         )}
                         <button onClick={() => onDelete(doc.id)} className="p-2 text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg" title="Apagar">
                           <Trash2 size={18} />
                         </button>
                       </div>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
           </div>
         )}
       </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Company, FinancialDocument, DocumentType, DocumentStatus, InvoiceItem, ExchangeRates } from '../types';
import { Plus, Printer, Share2, FileText, ArrowRight, Trash2, CheckCircle, X, Search, FileCheck } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface InvoicesProps {
  companies: Company[];
  documents: FinancialDocument[];
  onSave: (doc: FinancialDocument) => void;
  onDelete: (id: string) => void;
  rates: ExchangeRates;
}

export const Invoices: React.FC<InvoicesProps> = ({ companies, documents, onSave, onDelete, rates }) => {
  const [mode, setMode] = useState<'list' | 'create' | 'edit'>('list');
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [formData, setFormData] = useState<Partial<FinancialDocument>>({
    items: [],
    type: DocumentType.BUDGET,
    status: DocumentStatus.DRAFT,
    date: new Date().toISOString().split('T')[0]
  });

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // --- FILTROS & LISTAGEM ---
  const filteredDocs = useMemo(() => {
    return documents.filter(d => d.companyId === selectedCompanyId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [documents, selectedCompanyId]);

  // --- LÓGICA DE FORMULÁRIO ---
  const handleNewDoc = () => {
    if (!selectedCompany) {
      alert("Selecione uma empresa primeiro.");
      return;
    }

    // Auto number logic: Count docs of this type for this company
    const count = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.BUDGET).length;
    const nextNum = count + 1;
    const year = new Date().getFullYear();

    setFormData({
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: DocumentType.BUDGET,
      status: DocumentStatus.DRAFT,
      number: `ORC-${nextNum.toString().padStart(3, '0')}/${year}`,
      date: new Date().toISOString().split('T')[0],
      items: [{ id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }],
      clientName: '',
      clientPhone: '',
      clientTaxID: '',
      notes: 'Este orçamento é válido por 15 dias.'
    });
    setMode('create');
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...(prev.items || []), { id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (itemId: string) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).filter(i => i.id !== itemId)
    }));
  };

  const handleItemChange = (itemId: string, field: keyof InvoiceItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).map(i => i.id === itemId ? { ...i, [field]: value } : i)
    }));
  };

  const calculateTotal = (items: InvoiceItem[] = []) => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.clientName && formData.items && formData.items.length > 0) {
      onSave(formData as FinancialDocument);
      setMode('list');
    } else {
      alert("Preencha o nome do cliente e adicione pelo menos um item.");
    }
  };

  // --- LÓGICA DE AÇÕES ---

  const handleConvertToInvoice = (doc: FinancialDocument) => {
    if (confirm(`Converter orçamento ${doc.number} em Fatura Definitiva?`)) {
       // 1. Marcar orçamento como Aprovado
       onSave({ ...doc, status: DocumentStatus.APPROVED });

       // 2. Criar nova Fatura baseada no orçamento
       const countInv = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.INVOICE).length;
       const nextNum = countInv + 1;
       const year = new Date().getFullYear();

       const newInvoice: FinancialDocument = {
         ...doc,
         id: Math.random().toString(36).substr(2, 9),
         type: DocumentType.INVOICE,
         status: DocumentStatus.SENT,
         number: `FAT-${nextNum.toString().padStart(3, '0')}/${year}`,
         date: new Date().toISOString().split('T')[0],
         notes: 'Obrigado pela preferência.',
         createdAt: Date.now()
       };
       onSave(newInvoice);
       alert(`Fatura ${newInvoice.number} gerada com sucesso!`);
    }
  };

  const handleWhatsApp = (doc: FinancialDocument) => {
    if (!doc.clientPhone) {
      alert("Adicione o telefone do cliente para enviar por WhatsApp.");
      return;
    }

    const total = calculateTotal(doc.items);
    const currency = selectedCompany?.currency || 'AOA';

    // Formatar moeda corretamente para PT-AO
    const formattedTotal = total.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

    const text = `Olá ${doc.clientName}, segue o documento ${doc.number} (${doc.type}) no valor de ${currency} ${formattedTotal}. \n\nPor favor, verifique o PDF enviado. \nObrigado, ${selectedCompany?.name || 'Na Rota do Lucro'}.`;

    // Limpar e tratar telefone
    let phone = doc.clientPhone.replace(/[^0-9]/g, '');

    // Se for número angolano (9 dígitos começando com 9), adiciona 244 se não tiver
    if (phone.length === 9 && phone.startsWith('9')) {
      phone = '244' + phone;
    }

    const url = `https://wa.me/${phone}?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const handlePDF = (doc: FinancialDocument) => {
    if (!selectedCompany) return;

    const pdf = new jsPDF();
    const pageWidth = pdf.internal.pageSize.width;
    const currency = selectedCompany.currency;

    // Header Color Stripe
    const primaryColor = doc.type === DocumentType.INVOICE ? [16, 185, 129] : [14, 165, 233]; // Green for Invoice, Blue for Budget
    pdf.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.rect(0, 0, pageWidth, 40, 'F');

    // Title & Company
    pdf.setTextColor(255, 255, 255);
    pdf.setFontSize(24);
    pdf.setFont("helvetica", "bold");
    pdf.text(doc.type.toUpperCase(), 14, 25);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "normal");
    pdf.text(`#${doc.number}`, pageWidth - 40, 25);

    pdf.setFontSize(14);
    pdf.text(selectedCompany.name, 14, 35);

    // Info Section
    pdf.setTextColor(60, 60, 60);
    let yPos = 55;

    // Client Info
    pdf.setFontSize(11);
    pdf.setFont("helvetica", "bold");
    pdf.text("CLIENTE:", 14, yPos);
    pdf.setFont("helvetica", "normal");
    pdf.text(doc.clientName, 14, yPos + 6);
    if(doc.clientTaxID) pdf.text(`NIF: ${doc.clientTaxID}`, 14, yPos + 12);
    if(doc.clientPhone) pdf.text(`Tel: ${doc.clientPhone}`, 14, yPos + 18);

    // Date Info
    pdf.setFont("helvetica", "bold");
    pdf.text("DETALHES:", pageWidth - 80, yPos);
    pdf.setFont("helvetica", "normal");
    pdf.text(`Data de Emissão: ${new Date(doc.date).toLocaleDateString()}`, pageWidth - 80, yPos + 6);
    pdf.text(`Status: ${doc.status}`, pageWidth - 80, yPos + 12);
    if (doc.dueDate) pdf.text(`Vencimento: ${new Date(doc.dueDate).toLocaleDateString()}`, pageWidth - 80, yPos + 18);

    yPos += 30;

    // Table
    const tableRows = doc.items.map(item => [
      item.description,
      item.quantity,
      `${item.unitPrice.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`,
      `${(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`
    ]);

    autoTable(pdf, {
      startY: yPos,
      head: [['Descrição', 'Qtd', `Preço Unit (${currency})`, `Total (${currency})`]],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: primaryColor, textColor: 255, fontStyle: 'bold' },
      columnStyles: {
        1: { halign: 'center' },
        2: { halign: 'right' },
        3: { halign: 'right', fontStyle: 'bold' }
      }
    });

    // @ts-ignore
    const finalY = pdf.lastAutoTable.finalY + 10;

    // Total
    const total = calculateTotal(doc.items);
    pdf.setFontSize(14);
    pdf.setFont("helvetica", "bold");
    pdf.text(`TOTAL: ${currency} ${total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`, pageWidth - 14, finalY, { align: 'right' });

    // Footer / Notes
    if (doc.notes) {
      pdf.setFontSize(10);
      pdf.setFont("helvetica", "italic");
      pdf.setTextColor(100, 100, 100);
      pdf.text(`Notas: ${doc.notes}`, 14, finalY + 20);
    }

    // Bottom Branding
    pdf.setFontSize(8);
    pdf.text("Gerado por Na Rota do Lucro", pageWidth / 2, 290, { align: 'center' });

    pdf.save(`${doc.type}_${doc.clientName.replace(/\s/g, '_')}_${doc.number}.pdf`);
  };

  // --- RENDER ---

  if (mode === 'create' || mode === 'edit') {
    return (
      <div className="max-w-4xl mx-auto animate-fade-in">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <FileText className="text-brand-500" />
            {mode === 'create' ? `Novo ${formData.type}` : `Editar ${formData.number}`}
          </h2>
          <button onClick={() => setMode('list')} className="text-slate-500 hover:text-slate-700 dark:text-slate-400">
             <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">

          {/* Header Data */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tipo de Doc</label>
               <select 
                 value={formData.type} 
                 onChange={e => setFormData({...formData, type: e.target.value as DocumentType})}
                 className="w-full p-2 rounded border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                 disabled={mode === 'edit'}
               >
                 <option value={DocumentType.BUDGET}>{DocumentType.BUDGET}</option>
                 <option value={DocumentType.INVOICE}>{DocumentType.INVOICE}</option>
               </select>
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Número</label>
               <input 
                 type="text" 
                 value={formData.number} 
                 readOnly 
                 className="w-full p-2 rounded border bg-slate-100 dark:bg-slate-900 text-slate-500 cursor-not-allowed" 
               />
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data</label>
               <input 
                 type="date" 
                 value={formData.date} 
                 onChange={e => setFormData({...formData, date: e.target.value})}
                 className="w-full p-2 rounded border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white" 
               />
             </div>
          </div>

          {/* Client Data */}
          <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg mb-6 border border-slate-200 dark:border-slate-700">
            <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-3">Dados do Cliente</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input 
                 placeholder="Nome do Cliente *" 
                 value={formData.clientName}
                 onChange={e => setFormData({...formData, clientName: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                 required
              />
              <input 
                 placeholder="Telefone (WhatsApp) Ex: 923..." 
                 value={formData.clientPhone}
                 onChange={e => setFormData({...formData, clientPhone: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
              <input 
                 placeholder="NIF (Opcional)" 
                 value={formData.clientTaxID}
                 onChange={e => setFormData({...formData, clientTaxID: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
            </div>
            <p className="text-xs text-slate-500 mt-2">O telefone é usado para enviar o documento via WhatsApp.</p>
          </div>

          {/* Items */}
          <div className="mb-6">
            <div className="flex justify-between items-center mb-2">
               <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300">Itens / Serviços</h3>
            </div>
            <table className="w-full text-sm">
              <thead className="bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300">
                <tr>
                  <th className="p-2 text-left">Descrição</th>
                  <th className="p-2 w-20 text-center">Qtd</th>
                  <th className="p-2 w-32 text-right">Preço Unit</th>
                  <th className="p-2 w-32 text-right">Total</th>
                  <th className="p-2 w-10"></th>
                </tr>
              </thead>
              <tbody>
                {formData.items?.map(item => (
                  <tr key={item.id} className="border-b dark:border-slate-700">
                    <td className="p-2">
                      <input 
                        value={item.description}
                        onChange={e => handleItemChange(item.id, 'description', e.target.value)}
                        placeholder="Ex: Consultoria"
                        className="w-full p-1 bg-transparent outline-none dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="1"
                        value={item.quantity}
                        onChange={e => handleItemChange(item.id, 'quantity', parseInt(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-center dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="0"
                        value={item.unitPrice}
                        onChange={e => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-right dark:text-white"
                      />
                    </td>
                    <td className="p-2 text-right font-medium dark:text-white">
                      {(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}
                    </td>
                    <td className="p-2 text-center">
                      <button type="button" onClick={() => handleRemoveItem(item.id)} className="text-rose-400 hover:text-rose-600"><Trash2 size={14} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button type="button" onClick={handleAddItem} className="mt-2 text-sm text-brand-600 font-medium flex items-center gap-1 hover:underline">
              <Plus size={14} /> Adicionar Item
            </button>
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start gap-6 border-t dark:border-slate-700 pt-6">
            <div className="w-full md:w-1/2">
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Notas / Termos</label>
               <textarea 
                 value={formData.notes}
                 onChange={e => setFormData({...formData, notes: e.target.value})}
                 className="w-full p-2 rounded border dark:bg-slate-700 dark:border-slate-600 dark:text-white text-sm h-24"
               />
            </div>
            <div className="w-full md:w-1/3 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg">
               <div className="flex justify-between items-center text-lg font-bold text-slate-800 dark:text-white">
                 <span>Total ({selectedCompany?.currency})</span>
                 <span>{calculateTotal(formData.items).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</span>
               </div>
               <button type="submit" className="w-full mt-4 py-3 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg shadow-lg flex justify-center items-center gap-2">
                 <CheckCircle size={18} /> Salvar Documento
               </button>
            </div>
          </div>

        </form>
      </div>
    );
  }

  return (
    <div className="space-y-6">
       {/* Toolbar */}
       <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col md:flex-row justify-between items-center gap-4">
         <div>
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">Orçamentos & Faturas</h2>
            <p className="text-sm text-slate-500 dark:text-slate-400">Gira documentos profissionais em {selectedCompany?.currency || 'AOA'}</p>
         </div>
         <div className="flex items-center gap-3">
            <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="p-2 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
            >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <button 
              onClick={handleNewDoc}
              className="bg-brand-600 hover:bg-brand-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 shadow-md"
            >
              <Plus size={18} /> Novo Orçamento
            </button>
         </div>
       </div>

       {/* List */}
       <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
         {filteredDocs.length === 0 ? (
           <div className="p-12 text-center text-slate-400">
             <FileText className="mx-auto w-12 h-12 mb-3 opacity-30" />
             <p>Nenhum documento criado para esta empresa.</p>
           </div>
         ) : (
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-500 dark:text-slate-400 text-xs uppercase">
                 <tr>
                   <th className="p-4">Número</th>
                   <th className="p-4">Cliente</th>
                   <th className="p-4">Data</th>
                   <th className="p-4 text-center">Status</th>
                   <th className="p-4 text-right">Total</th>
                   <th className="p-4 text-center">Ações</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                 {filteredDocs.map(doc => (
                   <tr key={doc.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                     <td className="p-4 font-medium text-slate-700 dark:text-slate-200 flex items-center gap-2">
                       {doc.type === DocumentType.INVOICE ? <CheckCircle size={16} className="text-emerald-500" /> : <FileText size={16} className="text-brand-500" />}
                       {doc.number}
                     </td>
                     <td className="p-4 text-slate-600 dark:text-slate-300">
                       <div className="font-medium">{doc.clientName}</div>
                       <div className="text-xs text-slate-400">{doc.clientPhone || '-'}</div>
                     </td>
                     <td className="p-4 text-sm text-slate-500 dark:text-slate-400">
                       {new Date(doc.date).toLocaleDateString()}
                     </td>
                     <td className="p-4 text-center">
                       <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                         doc.status === DocumentStatus.DRAFT ? 'bg-slate-100 text-slate-600' :
                         doc.status === DocumentStatus.SENT ? 'bg-blue-100 text-blue-600' :
                         doc.status === DocumentStatus.APPROVED ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.PAID ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.CANCELLED ? 'bg-rose-100 text-rose-600' : ''
                       }`}>
                         {doc.status}
                       </span>
                     </td>
                     <td className="p-4 text-right font-bold text-slate-700 dark:text-white">
                        {calculateTotal(doc.items).toLocaleString('pt-AO', { minimumFractionDigits: 2 })} <span className="text-xs font-normal text-slate-400">{selectedCompany?.currency}</span>
                     </td>
                     <td className="p-4">
                       <div className="flex items-center justify-center gap-2">
                         <button onClick={() => handleWhatsApp(doc)} className="p-2 text-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg" title="Enviar WhatsApp">
                           <Share2 size={18} />
                         </button>
                         <button onClick={() => handlePDF(doc)} className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg" title="Baixar PDF">
                           <Printer size={18} />
                         </button>
                         {doc.type === DocumentType.BUDGET && (
                           <button onClick={() => handleConvertToInvoice(doc)} className="p-2 text-brand-600 hover:bg-brand-50 dark:hover:bg-brand-900/20 rounded-lg" title="Converter em Fatura">
                             <ArrowRight size={18} />
                           </button>
                         )}
                         <button onClick={() => onDelete(doc.id)} className="p-2 text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg" title="Apagar">
                           <Trash2 size={18} />
                         </button>
                       </div>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
           </div>
         )}
       </div>
    </div>
  );
};

export enum Currency {
  AOA = 'AOA', // Kwanza
  USD = 'USD', // Dólar
  EUR = 'EUR', // Euro
  BRL = 'BRL'  // Real (opcional)
}

export enum CompanyStatus {
  ACTIVE = 'Ativo',
  PAUSED = 'Pausado',
  CLOSED = 'Encerrado'
}

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE'
}

export interface AppSettings {
  appName: string;
  logo?: string; // Base64 string
}

export interface Company {
  id: string;
  name: string;
  industry: string;
  currency: Currency;
  status: CompanyStatus;
  taxRate?: number; // Porcentagem estimada de impostos/custos sobre o lucro
  createdAt: number;
}

export interface Transaction {
  id: string;
  companyId: string;
  type: TransactionType;
  amount: number;
  category: string;
  date: string; // ISO Date string YYYY-MM-DD
