                  className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                >
                  {ZONES.map(z => (
                    <option key={z.id} value={z.id}>{z.name} (+ Kz {z.transportPrice})</option>
                  ))}
                </select>
              </div>

            </div>
          </div>

          {/* RIGHT COLUMN: RESULTS */}
          <div className="lg:col-span-5">
            <div className="sticky top-6">

              {/* Receipt Card */}
              <div className="bg-gradient-to-br from-slate-800 to-slate-900 text-white rounded-2xl p-6 shadow-2xl relative overflow-hidden border border-slate-700">
                {/* Decorative circles */}
                <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-500 rounded-full opacity-20 blur-3xl"></div>
