import React, { useState, useMemo } from 'react';
import { Calculator, Clock, MapPin, DollarSign, Sofa, Droplets, TrendingUp, AlertCircle, Check, Navigation, ExternalLink } from 'lucide-react';

// --- CONFIGURAÇÃO DE PRECIFICAÇÃO (JF HIGIENIZAÇÕES) ---
const SERVICE_TYPES = [
  // SOFÁS
  { id: 'sofa1', name: 'Sofá 1 Lugar', basePrice: 7000, baseCost: 1000, baseTime: 40 },
  { id: 'sofa2', name: 'Sofá 2 Lugares', basePrice: 10000, baseCost: 1500, baseTime: 60 },
  { id: 'sofa3', name: 'Sofá 3 Lugares', basePrice: 12000, baseCost: 1800, baseTime: 80 },
  { id: 'sofa4', name: 'Sofá 4 Lugares', basePrice: 14000, baseCost: 2100, baseTime: 100 },
  { id: 'sofa5', name: 'Sofá 5 Lugares', basePrice: 16000, baseCost: 2400, baseTime: 120 },
  { id: 'sofa6', name: 'Sofá 6 Lugares', basePrice: 18000, baseCost: 2700, baseTime: 140 },
  { id: 'sofa7', name: 'Sofá 7 Lugares', basePrice: 20000, baseCost: 3000, baseTime: 160 },
  { id: 'sofa8', name: 'Sofá 8 Lugares', basePrice: 22000, baseCost: 3300, baseTime: 180 },

  // CADEIRAS & POLTRONAS
  { id: 'cadeira', name: 'Cadeira', basePrice: 2000, baseCost: 300, baseTime: 15 },
  { id: 'puf', name: 'Puf', basePrice: 3000, baseCost: 450, baseTime: 20 },
  { id: 'poltrona', name: 'Poltrona', basePrice: 4000, baseCost: 600, baseTime: 30 },

  // COLCHÕES
  { id: 'col_solteiro', name: 'Colchão Solteiro', basePrice: 12000, baseCost: 1800, baseTime: 45 },
  { id: 'col_casal', name: 'Colchão Casal', basePrice: 14000, baseCost: 2100, baseTime: 60 },
  { id: 'col_king', name: 'Colchão King', basePrice: 16000, baseCost: 2400, baseTime: 80 },
  { id: 'col_king_single', name: 'Colchão King Single', basePrice: 20000, baseCost: 3000, baseTime: 90 },

  // OUTROS
  { id: 'tapete', name: 'Tapetes (por Metro)', basePrice: 2000, baseCost: 300, baseTime: 20 },
];

const DIRT_LEVELS = [
  { id: 'low', name: 'Leve (Manutenção)', priceMult: 1.0, costMult: 1.0, timeMult: 1.0 },
  { id: 'medium', name: 'Médio (Uso diário)', priceMult: 1.2, costMult: 1.1, timeMult: 1.2 },
  { id: 'high', name: 'Intenso (Manchas/Odores)', priceMult: 1.5, costMult: 1.3, timeMult: 1.5 },
  { id: 'extreme', name: 'Extremo (Pós-obra/Mofo)', priceMult: 2.0, costMult: 1.6, timeMult: 2.0 },
];

export const PriceCalculator: React.FC = () => {
  const [selectedServiceId, setSelectedServiceId] = useState(SERVICE_TYPES[0].id);
  const [quantity, setQuantity] = useState(1);
  const [dirtLevelId, setDirtLevelId] = useState(DIRT_LEVELS[1].id);

  // Transport Config
  const [distanceKm, setDistanceKm] = useState(5); // Default distance
  const [taxiRate, setTaxiRate] = useState(300); // Kz per Km/Unit based on Taxi price
  const [locating, setLocating] = useState(false);

  const calculate = useMemo(() => {
    const service = SERVICE_TYPES.find(s => s.id === selectedServiceId)!;
    const dirt = DIRT_LEVELS.find(d => d.id === dirtLevelId)!;

    // Cálculos Serviço
    const unitPrice = service.basePrice * dirt.priceMult;
    const unitCost = service.baseCost * dirt.costMult;
    const unitTime = service.baseTime * dirt.timeMult;

    const totalServicePrice = unitPrice * quantity;
    const totalServiceCost = unitCost * quantity;

    // Cálculos Transporte (Baseado em Táxi 300kz)
    // Lógica: Cobramos o valor do táxi por Km (ida e volta implícita ou margem de lucro no transporte)
    const transportPrice = distanceKm * taxiRate;

    // Custo estimado do transporte (Gasolina/Manutenção é menor que o preço cobrado)
    // Estimativa: 30% do valor cobrado é custo real (combustível), o resto é depreciação/tempo.
    const transportCost = transportPrice * 0.3; 

    const finalPrice = totalServicePrice + transportPrice;
    const finalCost = totalServiceCost + transportCost; 

    const profit = finalPrice - finalCost;
    const margin = finalPrice > 0 ? (profit / finalPrice) * 100 : 0;
    const totalTime = unitTime * quantity;

    return {
      finalPrice,
      finalCost,
      profit,
      margin,
      totalTime,
      serviceName: service.name,
      dirtName: dirt.name,
      transportPrice,
      distance: distanceKm
    };
  }, [selectedServiceId, quantity, dirtLevelId, distanceKm, taxiRate]);

  const handleOpenMaps = () => {
    setLocating(true);
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocating(false);
          const { latitude, longitude } = position.coords;
          // Abre o Google Maps com a origem definida, usuário só precisa por o destino para ver os KM
          const url = `https://www.google.com/maps/dir/?api=1&origin=${latitude},${longitude}&destination=&travelmode=driving`;
          window.open(url, '_blank');
        },
        (error) => {
          setLocating(false);
          alert("Não foi possível obter sua localização. Por favor, abra o mapa manualmente.");
          window.open('https://www.google.com/maps', '_blank');
        }
      );
    } else {
      setLocating(false);
      alert("Geolocalização não suportada neste navegador.");
    }
  };

  const formatTime = (minutes: number) => {
    const h = Math.floor(minutes / 60);
    const m = Math.round(minutes % 60);
    if (h > 0) return `${h}h ${m}min`;
    return `${m}min`;
  };

  const formatMoney = (val: number) => {
    return val.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-fade-in pb-20">
      <div className="bg-white dark:bg-slate-800 p-8 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-12 h-12 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-xl flex items-center justify-center shadow-sm">
            <Calculator size={28} />
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Calculadora Inteligente</h2>
            <p className="text-sm text-slate-500 dark:text-slate-400">Orçamento Dinâmico • Baseado em GPS</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* LEFT COLUMN: INPUTS */}
          <div className="lg:col-span-7 space-y-6">

            <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-xl border border-slate-200 dark:border-slate-700 space-y-5">

              {/* Service Type */}
              <div>
                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
                  <Sofa size={16} /> Item a Higienizar
                </label>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                  {SERVICE_TYPES.map(s => (
                    <button
                      key={s.id}
                      onClick={() => setSelectedServiceId(s.id)}
                      className={`text-left p-3 rounded-lg border text-sm transition-all ${
                        selectedServiceId === s.id 
                        ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300 ring-1 ring-indigo-500' 
                        : 'border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'
                      }`}
                    >
                      <div className="font-semibold">{s.name}</div>
                      <div className="text-xs opacity-70">Base: Kz {s.basePrice.toLocaleString()}</div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Quantity */}
              <div>
                 <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">
                   {selectedServiceId === 'tapete' ? 'Quantidade (Metros)' : 'Quantidade (Unidades)'}
                 </label>
                 <div className="flex items-center gap-4">
                    <input 
                      type="range" 
                      min="1" 
                      max="20" 
                      value={quantity} 
                      onChange={(e) => setQuantity(parseInt(e.target.value))}
                      className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                    />
                    <span className="text-xl font-bold text-indigo-600 w-12 text-center">{quantity}</span>
                 </div>
              </div>

              {/* Dirt Level */}
              <div>
                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
                  <Droplets size={16} /> Grau de Sujidade
                </label>
                <div className="grid grid-cols-2 gap-3">
                  {DIRT_LEVELS.map(d => (
                    <button
                      key={d.id}
                      onClick={() => setDirtLevelId(d.id)}
                      className={`text-left p-3 rounded-lg border text-sm transition-all relative overflow-hidden ${
                        dirtLevelId === d.id 
                        ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 ring-1 ring-blue-500' 
                        : 'border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'
                      }`}
                    >
                      <div className="font-semibold relative z-10">{d.name}</div>
                      {/* Visual indicator of dirt level */}
                      <div className="flex gap-0.5 mt-1 relative z-10">
                        <div className={`h-1 w-4 rounded-full ${d.id === 'low' ? 'bg-emerald-400' : 'bg-slate-300'}`}></div>
                        <div className={`h-1 w-4 rounded-full ${d.id === 'medium' ? 'bg-amber-400' : (d.id === 'high' || d.id === 'extreme' ? 'bg-amber-400' : 'bg-slate-300')}`}></div>
                        <div className={`h-1 w-4 rounded-full ${d.id === 'high' ? 'bg-orange-500' : (d.id === 'extreme' ? 'bg-orange-500' : 'bg-slate-300')}`}></div>
                        <div className={`h-1 w-4 rounded-full ${d.id === 'extreme' ? 'bg-red-600' : 'bg-slate-300'}`}></div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Transport / Distance */}
              <div className="bg-white dark:bg-slate-800 p-4 rounded-lg border border-slate-200 dark:border-slate-600">
                <div className="flex justify-between items-center mb-2">
                  <label className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                    <MapPin size={16} className="text-red-500" /> Deslocamento (Km)
                  </label>
                  <button 
                    onClick={handleOpenMaps}
                    className="text-xs flex items-center gap-1 text-blue-600 dark:text-blue-400 hover:underline"
                  >
                    {locating ? 'Localizando...' : 'Ver no Mapa'} <ExternalLink size={12} />
                  </button>
                </div>

                <div className="grid grid-cols-2 gap-4">
                   <div>
                      <span className="text-xs text-slate-500 mb-1 block">Distância Total (Km)</span>
                      <div className="relative">
                        <input 
                          type="number" 
                          min="0"
                          value={distanceKm} 
                          onChange={(e) => setDistanceKm(parseFloat(e.target.value) || 0)}
                          className="w-full p-2.5 pl-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white font-bold outline-none focus:ring-2 focus:ring-indigo-500"
                        />
                        <span className="absolute right-3 top-2.5 text-slate-400 text-sm">km</span>
                      </div>
                   </div>
                   <div>
                      <span className="text-xs text-slate-500 mb-1 block">Ref. Custo Táxi (Kz/Km)</span>
                      <div className="relative">
                        <input 
                          type="number" 
                          min="0"
                          value={taxiRate} 
                          onChange={(e) => setTaxiRate(parseFloat(e.target.value) || 0)}
                          className="w-full p-2.5 pl-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                        />
                        <span className="absolute right-3 top-2.5 text-slate-400 text-sm">Kz</span>
                      </div>
                   </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2">
                   <Navigation size={10} className="inline mr-1" />
                   O cálculo assume que o custo de deslocamento é baseado na tarifa média de táxi ({taxiRate} Kz) multiplicada pela distância.
                </p>
              </div>

            </div>
          </div>

          {/* RIGHT COLUMN: RESULTS */}
          <div className="lg:col-span-5">
            <div className="sticky top-6">

              {/* Receipt Card */}
              <div className="bg-gradient-to-br from-slate-800 to-slate-900 text-white rounded-2xl p-6 shadow-2xl relative overflow-hidden border border-slate-700">
                {/* Decorative circles */}
                <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-500 rounded-full opacity-20 blur-3xl"></div>
                <div className="absolute -bottom-10 -left-10 w-40 h-40 bg-emerald-500 rounded-full opacity-20 blur-3xl"></div>

                <h3 className="text-lg font-bold mb-6 flex items-center gap-2 border-b border-white/10 pb-4">
                  <Check className="text-emerald-400" /> Resultado Estimado
                </h3>

                <div className="space-y-4 mb-6">
                  <div className="flex justify-between text-slate-300 text-sm">
                    <span>Item ({quantity}x)</span>
                    <span>{calculate.serviceName}</span>
                  </div>
                   <div className="flex justify-between text-slate-300 text-sm">
                    <span>Sujidade</span>
                    <span>{calculate.dirtName}</span>
                  </div>
                  <div className="flex justify-between text-slate-300 text-sm">
                    <span>Deslocamento ({calculate.distance} km)</span>
                    <span>Kz {calculate.transportPrice.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-slate-300 text-sm border-t border-white/10 pt-2">
                    <span className="flex items-center gap-2"><Clock size={14} /> Tempo Estimado</span>
                    <span className="text-white font-medium">{formatTime(calculate.totalTime)}</span>
                  </div>
                </div>

                <div className="bg-white/10 rounded-xl p-4 mb-4 backdrop-blur-sm">
                   <p className="text-slate-300 text-xs uppercase tracking-wider mb-1">Preço Final Sugerido</p>
                   <div className="text-4xl font-bold text-white tracking-tight">
                     <span className="text-2xl text-slate-400 mr-1">Kz</span>
                     {formatMoney(calculate.finalPrice)}
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="bg-emerald-500/20 rounded-lg p-3 border border-emerald-500/30">
                     <p className="text-emerald-300 text-[10px] uppercase font-bold mb-1 flex items-center gap-1">
                       <TrendingUp size={12} /> Lucro Previsto
                     </p>
                     <p className="text-lg font-bold text-emerald-100">
                       Kz {formatMoney(calculate.profit)}
                     </p>
                  </div>
                  <div className="bg-rose-500/20 rounded-lg p-3 border border-rose-500/30">
                     <p className="text-rose-300 text-[10px] uppercase font-bold mb-1 flex items-center gap-1">
                       <DollarSign size={12} /> Custo Total
                     </p>
                     <p className="text-lg font-bold text-rose-100">
                       Kz {formatMoney(calculate.finalCost)}
                     </p>
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="mt-4 flex gap-3">
                 <button 
                  onClick={() => {
                     const text = `*ORÇAMENTO OFICIAL - JF HIGIENIZAÇÕES*\n\n` +
                                  `🛋️ *Serviço:* ${calculate.serviceName} (x${quantity})\n` +
                                  `🧼 *Nível:* ${calculate.dirtName}\n` +
                                  `🚚 *Deslocamento:* ${calculate.distance}km\n` +
                                  `⏱️ *Tempo Estimado:* ${formatTime(calculate.totalTime)}\n\n` +
                                  `💰 *VALOR TOTAL:* Kz ${formatMoney(calculate.finalPrice)}`;

                     if (navigator.share) {
                        navigator.share({
                           title: 'Orçamento JF Higienizações',
                           text: text
                        }).catch(console.error);
                     } else {
                        navigator.clipboard.writeText(text);
                        alert("Orçamento copiado para a área de transferência!");
                     }
                  }}
                  className="flex-1 py-3 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-xl text-slate-700 dark:text-white font-medium shadow-sm hover:bg-slate-50 dark:hover:bg-slate-600 transition-colors flex items-center justify-center gap-2"
                 >
                   <Check size={18} /> Copiar / Partilhar
                 </button>
              </div>
              <div className="mt-2 text-center">
                   <span className="text-[10px] text-slate-400">
                     <AlertCircle size={10} className="mr-1 inline" /> 
                     Valores calculados com base na tabela oficial e taxa de táxi de {taxiRate}kz/km.
                   </span>
              </div>

            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export enum Currency {
  AOA = 'AOA', // Kwanza
  USD = 'USD', // Dólar
  EUR = 'EUR', // Euro
  BRL = 'BRL'  // Real (opcional)
}

export enum CompanyStatus {
  ACTIVE = 'Ativo',
  PAUSED = 'Pausado',
  CLOSED = 'Encerrado'
}

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE'
}

export interface AppSettings {
  appName: string;
  logo?: string; // Base64 string
}

export interface Company {
  id: string;
  name: string;
  industry: string;
  currency: Currency;
  status: CompanyStatus;
  taxRate?: number; // Porcentagem estimada de impostos/custos sobre o lucro
  createdAt: number;
}

export interface Transaction {
  id: string;
  companyId: string;
  type: TransactionType;
  amount: number;
  category: string;
  date: string; // ISO Date string YYYY-MM-DD
  description?: string;
  isFixed?: boolean; // Para despesas
}

export interface MonthlyNote {
  id: string;
  companyId: string;
  monthStr: string; // YYYY-MM format
  note: string;
  aiAnalysis?: string;
}

export interface ExchangeRates {
  [key: string]: number; // Base is USD. e.g. { AOA: 900, EUR: 0.92, USD: 1 }
}

export interface CategoryItem {
  id: string;
  name: string;
  type: TransactionType;
}

// Novos Tipos para Documentos (Faturas/Orçamentos)
export enum DocumentType {
  BUDGET = 'Orçamento',
  INVOICE = 'Fatura'
}

export enum DocumentStatus {
  DRAFT = 'Rascunho',
  SENT = 'Enviado',
  APPROVED = 'Aprovado', // Para orçamentos
  PAID = 'Pago',         // Para faturas
  CANCELLED = 'Anulado'
}

export interface InvoiceItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface FinancialDocument {
  id: string;
  companyId: string;
  number: string; // Ex: ORC-001/2024
  type: DocumentType;
  status: DocumentStatus;
  clientName: string;
  clientTaxID?: string; // NIF
  clientPhone?: string; // Para WhatsApp
  date: string;
  dueDate?: string;
  items: InvoiceItem[];
  notes?: string;
  createdAt: number;
}

export type ViewState = 'daily' | 'dashboard' | 'companies' | 'month-detail' | 'reports' | 'categories' | 'invoices' | 'calculator';

import React, { useMemo } from 'react';
import { Company, FinancialDocument, ExchangeRates, DocumentStatus, DocumentType } from '../types';
import { Calendar, CheckCircle, Clock, DollarSign, MapPin, Briefcase, ArrowRight, Sun, User } from 'lucide-react';

interface DailyPanelProps {
  companies: Company[];
  documents: FinancialDocument[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

export const DailyPanel: React.FC<DailyPanelProps> = ({ companies, documents, rates, onNavigate }) => {
  const todayDate = new Date().toISOString().split('T')[0];

  // Helper de conversão
  const getConvertedToAOA = (amount: number, currency: string) => {
    const rateToUSD = rates[currency] || 1;
    const rateUSDToAOA = rates['AOA'] || 900;
    return (amount / rateToUSD) * rateUSDToAOA;
  };

  const dailyStats = useMemo(() => {
    const todayDocs = documents.filter(d => d.date === todayDate && d.status !== DocumentStatus.CANCELLED);

    let totalExpectedAOA = 0;
    let totalReceivedAOA = 0;
    let pendingCount = 0;
    let completedCount = 0;

    todayDocs.forEach(doc => {
      const company = companies.find(c => c.id === doc.companyId);
      const currency = company?.currency || 'USD';

      const docTotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
      const valAOA = getConvertedToAOA(docTotal, currency);

      if (doc.type === DocumentType.INVOICE) {
         totalExpectedAOA += valAOA;
         if (doc.status === DocumentStatus.PAID) {
           totalReceivedAOA += valAOA;
           completedCount++;
         } else {
           pendingCount++;
         }
      } else {
         // Se for orçamento, conta como pendente/serviço do dia se estiver aprovado
         if (doc.status === DocumentStatus.APPROVED) {
            totalExpectedAOA += valAOA;
            pendingCount++;
         }
      }
    });

    return {
      docs: todayDocs,
      totalExpectedAOA,
      totalReceivedAOA,
      pendingCount,
      completedCount,
      progress: totalExpectedAOA > 0 ? (totalReceivedAOA / totalExpectedAOA) * 100 : 0
    };
  }, [documents, todayDate, companies, rates]);

  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Bom dia';
    if (hour < 18) return 'Boa tarde';
    return 'Boa noite';
  }, []);

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-20">

      {/* Header Section */}
      <div className="flex justify-between items-center mb-2">
        <div>
           <h1 className="text-3xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
             <Sun className="text-amber-500" /> {greeting}, Líder!
           </h1>
           <p className="text-slate-500 dark:text-slate-400 font-medium">
             <Calendar className="inline w-4 h-4 mr-1" />
             Hoje, {new Date().toLocaleDateString('pt-PT', { weekday: 'long', day: 'numeric', month: 'long' })}
           </p>
        </div>
      </div>

      {/* Main Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {/* Card 1: Total do Dia */}
        <div className="bg-gradient-to-br from-brand-600 to-brand-700 rounded-2xl p-6 text-white shadow-lg relative overflow-hidden">
           <div className="absolute top-0 right-0 p-4 opacity-10">
             <DollarSign size={80} />
           </div>
           <p className="text-brand-100 font-medium mb-1 text-sm">Previsão de Faturação Hoje</p>
           <h2 className="text-3xl font-bold tracking-tight">
             Kz {dailyStats.totalExpectedAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 0 })}
           </h2>
           <div className="mt-4 bg-black/20 rounded-full h-1.5 w-full overflow-hidden">
             <div 
               className="bg-white/90 h-full rounded-full transition-all duration-1000" 
               style={{ width: `${dailyStats.progress}%` }}
             ></div>
           </div>
           <p className="text-xs mt-2 text-brand-100">
             {dailyStats.completedCount} pagos de {dailyStats.docs.length} serviços
           </p>
        </div>

        {/* Card 2: Status Rapido */}
        <div className="bg-white dark:bg-slate-800 rounded-2xl p-6 border border-slate-100 dark:border-slate-700 shadow-sm flex flex-col justify-center">
           <div className="flex items-center justify-between mb-4">
              <div>
                <p className="text-slate-500 dark:text-slate-400 text-sm font-bold uppercase">A Receber</p>
                <p className="text-2xl font-bold text-slate-800 dark:text-white">
                  {(dailyStats.totalExpectedAOA - dailyStats.totalReceivedAOA).toLocaleString('pt-AO', { maximumFractionDigits: 0 })} <span className="text-sm font-normal text-slate-400">Kz</span>
                </p>
              </div>
              <div className="p-3 rounded-full bg-amber-50 dark:bg-amber-900/20 text-amber-500">
                <Clock size={24} />
              </div>
           </div>
           <div className="text-xs text-slate-400">
             {dailyStats.pendingCount} serviços pendentes de pagamento ou execução.
           </div>
        </div>

        {/* Card 3: Caixa Realizado */}
        <div className="bg-white dark:bg-slate-800 rounded-2xl p-6 border border-slate-100 dark:border-slate-700 shadow-sm flex flex-col justify-center">
           <div className="flex items-center justify-between mb-4">
              <div>
                <p className="text-slate-500 dark:text-slate-400 text-sm font-bold uppercase">Entrou em Caixa</p>
                <p className="text-2xl font-bold text-emerald-600 dark:text-emerald-400">
                  {dailyStats.totalReceivedAOA.toLocaleString('pt-AO', { maximumFractionDigits: 0 })} <span className="text-sm font-normal text-slate-400">Kz</span>
                </p>
              </div>
              <div className="p-3 rounded-full bg-emerald-50 dark:bg-emerald-900/20 text-emerald-500">
                <CheckCircle size={24} />
              </div>
           </div>
           <div className="text-xs text-slate-400">
             Valores confirmados como "Pago" no sistema.
           </div>
        </div>
      </div>

      {/* Agenda Section */}
      <div>
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <Briefcase className="text-slate-500" size={20} />
            Agenda de Hoje
          </h3>
          <button 
             onClick={() => onNavigate('invoices')}
             className="text-sm text-brand-600 font-medium hover:underline flex items-center gap-1"
          >
            Ver todos <ArrowRight size={14} />
          </button>
        </div>

        {dailyStats.docs.length === 0 ? (
          <div className="bg-slate-50 dark:bg-slate-800/50 rounded-xl p-8 text-center border-2 border-dashed border-slate-200 dark:border-slate-700">
             <div className="w-12 h-12 bg-slate-200 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-3 text-slate-400">
               <Calendar size={24} />
             </div>
             <p className="text-slate-500 dark:text-slate-400 font-medium">Agenda livre hoje!</p>
             <p className="text-xs text-slate-400 mt-1">Aproveite para organizar o financeiro ou captar clientes.</p>
             <button onClick={() => onNavigate('invoices')} className="mt-4 px-4 py-2 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-lg text-sm font-medium text-slate-700 dark:text-white shadow-sm hover:bg-slate-50">
               Agendar Serviço
             </button>
          </div>
        ) : (
          <div className="space-y-3">
             {dailyStats.docs.map(doc => {
               const company = companies.find(c => c.id === doc.companyId);
               const total = calculateTotal(doc.items);

               return (
                 <div key={doc.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm flex items-center justify-between group hover:border-brand-200 dark:hover:border-brand-900 transition-all">
                    <div className="flex items-start gap-4">
                       <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-lg font-bold shrink-0 ${
                         doc.status === DocumentStatus.PAID 
                          ? 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400' 
                          : 'bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300'
                       }`}>
                          {doc.clientName.charAt(0)}
                       </div>
                       <div>
                          <h4 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
                             {doc.clientName}
                             <span className={`text-[10px] px-1.5 py-0.5 rounded uppercase ${
                               doc.status === DocumentStatus.PAID ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                             }`}>
                               {doc.status}
                             </span>
                          </h4>
                          <div className="flex items-center gap-1 text-sm text-slate-500 dark:text-slate-400 mt-0.5">
                            <span className="font-medium">{doc.items[0]?.description}</span>
                            {doc.items.length > 1 && <span className="text-xs bg-slate-100 dark:bg-slate-700 px-1 rounded">+{doc.items.length - 1}</span>}
                          </div>
                          <div className="text-xs text-slate-400 mt-1 flex items-center gap-1">
                             <MapPin size={10} /> {doc.companyId === company?.id ? company?.name : 'Empresa'}
                          </div>
                       </div>
                    </div>

                    <div className="text-right">
                       <p className="font-bold text-slate-800 dark:text-white">
                         {total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })} <span className="text-xs font-normal text-slate-400">{company?.currency}</span>
                       </p>
                       <button onClick={() => onNavigate('invoices')} className="text-xs text-brand-600 hover:underline mt-1">Ver Detalhes</button>
                    </div>
                 </div>
               );
             })}
          </div>
        )}
      </div>

      {/* Quick Actions Footer */}
      <div className="grid grid-cols-2 gap-4 mt-6">
         <button onClick={() => onNavigate('calculator')} className="p-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl flex flex-col items-center justify-center gap-2 hover:bg-slate-100 dark:hover:bg-slate-700/80 transition-colors">
            <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-full">
               <DollarSign size={20} />
            </div>
            <span className="text-sm font-medium text-slate-700 dark:text-slate-200">Novo Orçamento</span>
         </button>
         <button onClick={() => onNavigate('month-detail')} className="p-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl flex flex-col items-center justify-center gap-2 hover:bg-slate-100 dark:hover:bg-slate-700/80 transition-colors">
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 rounded-full">
               <CheckCircle size={20} />
            </div>
            <span className="text-sm font-medium text-slate-700 dark:text-slate-200">Lançar Receita</span>
         </button>
      </div>

    </div>
  );
};

// Helper internal function
const calculateTotal = (items: any[]) => items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);

import React, { useState, useEffect } from 'react';
import { Company, Transaction, MonthlyNote, ExchangeRates, ViewState, CategoryItem, TransactionType, FinancialDocument, AppSettings } from './types';
import { StorageService } from './services/storageService';
import { Dashboard } from './components/Dashboard';
import { CompanyManager } from './components/CompanyManager';
import { MonthDetail } from './components/MonthDetail';
import { Reports } from './components/Reports';
import { CategorySettings } from './components/CategorySettings';
import { Invoices } from './components/Invoices';
import { PriceCalculator } from './components/PriceCalculator';
import { DailyPanel } from './components/DailyPanel';
import { LayoutDashboard, Building2, Calendar, FileBarChart, Settings, Menu, X, Sun, Moon, Tag, Download, ScrollText, Calculator, Zap } from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [companies, setCompanies] = useState<Company[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notes, setNotes] = useState<MonthlyNote[]>([]);
  const [rates, setRates] = useState<ExchangeRates>({});
  const [categories, setCategories] = useState<CategoryItem[]>([]);
  const [documents, setDocuments] = useState<FinancialDocument[]>([]);
  const [appSettings, setAppSettings] = useState<AppSettings>({ appName: 'Na Rota do Lucro' });

  // UI State - Default View agora é 'daily'
  const [currentView, setCurrentView] = useState<ViewState>('daily');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Initialization
  useEffect(() => {
    setCompanies(StorageService.getCompanies());
    setTransactions(StorageService.getTransactions());
    setNotes(StorageService.getNotes());
    setRates(StorageService.getRates());
    setCategories(StorageService.getCategories());
    setDocuments(StorageService.getDocuments());
    setAppSettings(StorageService.getSettings());

    // Check system preference for dark mode
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setIsDarkMode(true);
    }

    // PWA Install Event Listener
    const handleBeforeInstallPrompt = (e: Event) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setDeferredPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    // Cleanup function
    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  // Theme Toggle Effect
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // PWA Install Handler
  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    // Show the install prompt
    deferredPrompt.prompt();
    // Wait for the user to respond to the prompt
    const { outcome } = await deferredPrompt.userChoice;
    console.log(`User response to the install prompt: ${outcome}`);
    // We've used the prompt, and can't use it again, throw it away
    setDeferredPrompt(null);
  };

  // Handlers
  const handleSaveCompany = (company: Company) => {
    const exists = companies.find(c => c.id === company.id);
    let newCompanies;
    if (exists) {
      newCompanies = companies.map(c => c.id === company.id ? company : c);
    } else {
      newCompanies = [...companies, company];
    }
    setCompanies(newCompanies);
    StorageService.saveCompanies(newCompanies);
  };

  const handleDeleteCompany = (id: string) => {
    if (confirm('Tem certeza? Todas as transações desta empresa serão ocultas.')) {
      const newCompanies = companies.filter(c => c.id !== id);
      setCompanies(newCompanies);
      StorageService.saveCompanies(newCompanies);
    }
  };

  const handleAddTransaction = (t: Transaction) => {
    const newTransactions = [...transactions, t];
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleDeleteTransaction = (id: string) => {
    const newTransactions = transactions.filter(t => t.id !== id);
    setTransactions(newTransactions);
    StorageService.saveTransactions(newTransactions);
  };

  const handleSaveNote = (note: MonthlyNote) => {
    const filteredNotes = notes.filter(n => !(n.companyId === note.companyId && n.monthStr === note.monthStr));
    const newNotes = [...filteredNotes, note];
    setNotes(newNotes);
    StorageService.saveNotes(newNotes);
  };

  const handleSaveDocument = (doc: FinancialDocument) => {
    const exists = documents.find(d => d.id === doc.id);
    let newDocs;
    if (exists) {
      newDocs = documents.map(d => d.id === doc.id ? doc : d);
    } else {
      newDocs = [...documents, doc];
    }
    setDocuments(newDocs);
    StorageService.saveDocuments(newDocs);
  }

  const handleDeleteDocument = (id: string) => {
     if(confirm("Deseja apagar este documento permanentemente?")) {
        const newDocs = documents.filter(d => d.id !== id);
        setDocuments(newDocs);
        StorageService.saveDocuments(newDocs);
     }
  }

  const handleUpdateSettings = (newSettings: AppSettings) => {
    setAppSettings(newSettings);
    StorageService.saveSettings(newSettings);
  };

  // Category Handlers
  const handleAddCategory = (name: string, type: TransactionType) => {
    if (categories.some(c => c.name.toLowerCase() === name.toLowerCase() && c.type === type)) return;
    const newCategory: CategoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      type
    };
    const updatedCategories = [...categories, newCategory];
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);
  };

  const handleEditCategory = (id: string, newName: string) => {
    const oldCategory = categories.find(c => c.id === id);
    if (!oldCategory) return;
    const updatedCategories = categories.map(c => c.id === id ? { ...c, name: newName } : c);
    setCategories(updatedCategories);
    StorageService.saveCategories(updatedCategories);
    const updatedTransactions = transactions.map(t => 
      (t.category === oldCategory.name && t.type === oldCategory.type) ? { ...t, category: newName } : t
    );
    setTransactions(updatedTransactions);
    StorageService.saveTransactions(updatedTransactions);
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('Ao eliminar a categoria, ela deixará de aparecer nas sugestões, mas as transações antigas serão mantidas. Continuar?')) {
      const updatedCategories = categories.filter(c => c.id !== id);
      setCategories(updatedCategories);
      StorageService.saveCategories(updatedCategories);
    }
  };

  const NavItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => (
    <button
      onClick={() => { setCurrentView(view); setIsSidebarOpen(false); }}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
        currentView === view 
          ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' 
          : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans">

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black/50 lg:hidden backdrop-blur-sm"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed lg:static inset-y-0 left-0 z-30 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transform transition-transform duration-300 ease-in-out flex flex-col
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3 overflow-hidden">
          {appSettings.logo ? (
             <img src={appSettings.logo} alt="Logo" className="w-8 h-8 rounded object-cover bg-slate-100" />
          ) : (
            <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shrink-0">
               {appSettings.appName.charAt(0)}
            </div>
          )}
          <h1 className="text-lg font-bold tracking-tight text-slate-800 dark:text-white truncate" title={appSettings.appName}>
            {appSettings.appName}
          </h1>
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          <NavItem view="daily" icon={Zap} label="Painel Diário" />
          <NavItem view="dashboard" icon={LayoutDashboard} label="Visão Mensal" />
          <NavItem view="calculator" icon={Calculator} label="Calculadora de Preço" />
          <NavItem view="invoices" icon={ScrollText} label="Orçamentos e Faturas" />
          <NavItem view="month-detail" icon={Calendar} label="Lançamentos" />
          <NavItem view="companies" icon={Building2} label="Empresas" />
          <NavItem view="categories" icon={Tag} label="Categorias" />
          <NavItem view="reports" icon={FileBarChart} label="Relatórios" />
        </nav>

        <div className="p-4 border-t border-slate-100 dark:border-slate-800 space-y-4">
           {deferredPrompt && (
             <button onClick={handleInstallClick} className="w-full flex items-center justify-center gap-2 p-3 rounded-lg bg-emerald-600 hover:bg-emerald-700 text-white font-medium shadow-md transition-colors animate-pulse">
               <Download size={18} /> Instalar App
             </button>
           )}
           <div className="bg-slate-50 dark:bg-slate-800 rounded-xl p-4">
              <p className="text-xs text-slate-500 dark:text-slate-400 mb-2">Modo Escuro</p>
              <button onClick={() => setIsDarkMode(!isDarkMode)} className="w-full flex items-center justify-between p-2 rounded-lg bg-white dark:bg-slate-700 shadow-sm border border-slate-200 dark:border-slate-600">
                 <span className="text-sm font-medium flex items-center gap-2">{isDarkMode ? <Moon size={14} /> : <Sun size={14} />} {isDarkMode ? 'Ativado' : 'Desativado'}</span>
                 <div className={`w-8 h-4 rounded-full relative transition-colors ${isDarkMode ? 'bg-brand-600' : 'bg-slate-300'}`}><div className={`absolute top-0.5 left-0.5 w-3 h-3 bg-white rounded-full transition-transform ${isDarkMode ? 'translate-x-4' : 'translate-x-0'}`} /></div>
              </button>
           </div>
           <div className="text-xs text-center text-slate-400">v1.6.0 (Painel Diário)</div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
