import React, { useMemo } from 'react';
import { Company, FinancialDocument, ExchangeRates, DocumentStatus, DocumentType } from '../types';
import { Calendar, CheckCircle, Clock, DollarSign, MapPin, Briefcase, ArrowRight, Sun, User } from 'lucide-react';

interface DailyPanelProps {
  companies: Company[];
  documents: FinancialDocument[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

export const DailyPanel: React.FC<DailyPanelProps> = ({ companies, documents, rates, onNavigate }) => {
  const todayDate = new Date().toISOString().split('T')[0];

  // Helper de conversão
  const getConvertedToAOA = (amount: number, currency: string) => {
    const rateToUSD = rates[currency] || 1;
    const rateUSDToAOA = rates['AOA'] || 900;
    return (amount / rateToUSD) * rateUSDToAOA;
  };

  const dailyStats = useMemo(() => {
    const todayDocs = documents.filter(d => d.date === todayDate && d.status !== DocumentStatus.CANCELLED);

    let totalExpectedAOA = 0;
    let totalReceivedAOA = 0;
    let pendingCount = 0;
    let completedCount = 0;

    todayDocs.forEach(doc => {
      const company = companies.find(c => c.id === doc.companyId);
      const currency = company?.currency || 'USD';

      const docTotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
      const valAOA = getConvertedToAOA(docTotal, currency);

      if (doc.type === DocumentType.INVOICE) {
         totalExpectedAOA += valAOA;
         if (doc.status === DocumentStatus.PAID) {
           totalReceivedAOA += valAOA;
           completedCount++;
         } else {
           pendingCount++;
         }
      } else {
         // Se for orçamento, conta como pendente/serviço do dia se estiver aprovado
         if (doc.status === DocumentStatus.APPROVED) {
            totalExpectedAOA += valAOA;
            pendingCount++;
         }
      }
    });

    return {
      docs: todayDocs,
      totalExpectedAOA,
      totalReceivedAOA,
      pendingCount,
      completedCount,
      progress: totalExpectedAOA > 0 ? (totalReceivedAOA / totalExpectedAOA) * 100 : 0
    };
  }, [documents, todayDate, companies, rates]);

  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Bom dia';
    if (hour < 18) return 'Boa tarde';
    return 'Boa noite';
  }, []);

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-20">

      {/* Header Section */}
      <div className="flex justify-between items-center mb-2">
        <div>
           <h1 className="text-3xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
             <Sun className="text-amber-500" /> {greeting}, Líder!
           </h1>
           <p className="text-slate-500 dark:text-slate-400 font-medium">
             <Calendar className="inline w-4 h-4 mr-1" />
             Hoje, {new Date().toLocaleDateString('pt-PT', { weekday: 'long', day: 'numeric', month: 'long' })}
           </p>
        </div>
      </div>

      {/* Main Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {/* Card 1: Total do Dia */}
        <div className="bg-gradient-to-br from-brand-600 to-brand-700 rounded-2xl p-6 text-white shadow-lg relative overflow-hidden">
           <div className="absolute top-0 right-0 p-4 opacity-10">
             <DollarSign size={80} />
           </div>
           <p className="text-brand-100 font-medium mb-1 text-sm">Previsão de Faturação Hoje</p>
           <h2 className="text-3xl font-bold tracking-tight">
             Kz {dailyStats.totalExpectedAOA.toLocaleString('pt-AO', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}
           </h2>
           <div className="mt-4 bg-black/20 rounded-full h-1.5 w-full overflow-hidden">
             <div 
               className="bg-white/90 h-full rounded-full transition-all duration-1000" 
               style={{ width: `${dailyStats.progress}%` }}
             ></div>
           </div>
           <p className="text-xs mt-2 text-brand-100">
             {dailyStats.completedCount} pagos de {dailyStats.docs.length} serviços
           </p>
        </div>

        {/* Card 2: Status Rapido */}
        <div className="bg-white dark:bg-slate-800 rounded-2xl p-6 border border-slate-100 dark:border-slate-700 shadow-sm flex flex-col justify-center">
           <div className="flex items-center justify-between mb-4">
              <div>
                <p className="text-slate-500 dark:text-slate-400 text-sm font-bold uppercase">A Receber</p>
                <p className="text-2xl font-bold text-slate-800 dark:text-white">
                  {(dailyStats.totalExpectedAOA - dailyStats.totalReceivedAOA).toLocaleString('pt-AO', { maximumFractionDigits: 0 })} <span className="text-sm font-normal text-slate-400">Kz</span>
                </p>
              </div>
              <div className="p-3 rounded-full bg-amber-50 dark:bg-amber-900/20 text-amber-500">
                <Clock size={24} />
              </div>
           </div>
           <div className="text-xs text-slate-400">
             {dailyStats.pendingCount} serviços pendentes de pagamento ou execução.
           </div>
        </div>

        {/* Card 3: Caixa Realizado */}
        <div className="bg-white dark:bg-slate-800 rounded-2xl p-6 border border-slate-100 dark:border-slate-700 shadow-sm flex flex-col justify-center">
           <div className="flex items-center justify-between mb-4">
              <div>
                <p className="text-slate-500 dark:text-slate-400 text-sm font-bold uppercase">Entrou em Caixa</p>
                <p className="text-2xl font-bold text-emerald-600 dark:text-emerald-400">
                  {dailyStats.totalReceivedAOA.toLocaleString('pt-AO', { maximumFractionDigits: 0 })} <span className="text-sm font-normal text-slate-400">Kz</span>
                </p>
              </div>
              <div className="p-3 rounded-full bg-emerald-50 dark:bg-emerald-900/20 text-emerald-500">
                <CheckCircle size={24} />
              </div>
           </div>
           <div className="text-xs text-slate-400">
             Valores confirmados como "Pago" no sistema.
           </div>
        </div>
      </div>

      {/* Agenda Section */}
      <div>
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <Briefcase className="text-slate-500" size={20} />
            Agenda de Hoje
          </h3>
          <button 
             onClick={() => onNavigate('invoices')}
             className="text-sm text-brand-600 font-medium hover:underline flex items-center gap-1"
          >
            Ver todos <ArrowRight size={14} />
          </button>
        </div>

        {dailyStats.docs.length === 0 ? (
          <div className="bg-slate-50 dark:bg-slate-800/50 rounded-xl p-8 text-center border-2 border-dashed border-slate-200 dark:border-slate-700">
             <div className="w-12 h-12 bg-slate-200 dark:bg-slate-700 rounded-full flex items-center justify-center mx-auto mb-3 text-slate-400">
               <Calendar size={24} />
             </div>
             <p className="text-slate-500 dark:text-slate-400 font-medium">Agenda livre hoje!</p>
             <p className="text-xs text-slate-400 mt-1">Aproveite para organizar o financeiro ou captar clientes.</p>
             <button onClick={() => onNavigate('invoices')} className="mt-4 px-4 py-2 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-lg text-sm font-medium text-slate-700 dark:text-white shadow-sm hover:bg-slate-50">
               Agendar Serviço
             </button>
          </div>
        ) : (
          <div className="space-y-3">
             {dailyStats.docs.map(doc => {
               const company = companies.find(c => c.id === doc.companyId);
               const total = calculateTotal(doc.items);

               return (
                 <div key={doc.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm flex items-center justify-between group hover:border-brand-200 dark:hover:border-brand-900 transition-all">
                    <div className="flex items-start gap-4">
                       <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-lg font-bold shrink-0 ${
                         doc.status === DocumentStatus.PAID 
                          ? 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400' 
                          : 'bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300'
                       }`}>
                          {doc.clientName.charAt(0)}
                       </div>
                       <div>
                          <h4 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
                             {doc.clientName}
                             <span className={`text-[10px] px-1.5 py-0.5 rounded uppercase ${
                               doc.status === DocumentStatus.PAID ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                             }`}>
                               {doc.status}
                             </span>
                          </h4>
                          <div className="flex items-center gap-1 text-sm text-slate-500 dark:text-slate-400 mt-0.5">
                            <span className="font-medium">{doc.items[0]?.description}</span>
                            {doc.items.length > 1 && <span className="text-xs bg-slate-100 dark:bg-slate-700 px-1 rounded">+{doc.items.length - 1}</span>}
                          </div>
                          <div className="text-xs text-slate-400 mt-1 flex items-center gap-1">
                             <MapPin size={10} /> {doc.companyId === company?.id ? company?.name : 'Empresa'}
                          </div>
                       </div>
                    </div>

                    <div className="text-right">
                       <p className="font-bold text-slate-800 dark:text-white">
                         {total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })} <span className="text-xs font-normal text-slate-400">{company?.currency}</span>
                       </p>
                       <button onClick={() => onNavigate('invoices')} className="text-xs text-brand-600 hover:underline mt-1">Ver Detalhes</button>
                    </div>
                 </div>
               );
             })}
          </div>
        )}
      </div>

      {/* Quick Actions Footer */}
      <div className="grid grid-cols-2 gap-4 mt-6">
         <button onClick={() => onNavigate('calculator')} className="p-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl flex flex-col items-center justify-center gap-2 hover:bg-slate-100 dark:hover:bg-slate-700/80 transition-colors">
            <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-full">
               <DollarSign size={20} />
