import React, { useState, useMemo } from 'react';
import { Calculator, Clock, MapPin, DollarSign, Sofa, Droplets, TrendingUp, AlertCircle, Check, Navigation, ExternalLink } from 'lucide-react';
import { SERVICE_TYPES, DIRT_LEVELS } from '../constants';

export const PriceCalculator: React.FC = () => {
  const [selectedServiceId, setSelectedServiceId] = useState(SERVICE_TYPES[0].id);
  const [quantity, setQuantity] = useState(1);
  const [dirtLevelId, setDirtLevelId] = useState(DIRT_LEVELS[1].id);

  // Transport Config
  const [distanceKm, setDistanceKm] = useState(5); // Default distance
  const [taxiRate, setTaxiRate] = useState(300); // Kz per Km/Unit based on Taxi price
  const [locating, setLocating] = useState(false);

  const calculate = useMemo(() => {
    const service = SERVICE_TYPES.find(s => s.id === selectedServiceId)!;
    const dirt = DIRT_LEVELS.find(d => d.id === dirtLevelId)!;

    // Cálculos Serviço
    const unitPrice = service.basePrice * dirt.priceMult;
    const unitCost = service.baseCost * dirt.costMult;
    const unitTime = service.baseTime * dirt.timeMult;

    const totalServicePrice = unitPrice * quantity;
    const totalServiceCost = unitCost * quantity;

    // Cálculos Transporte (Baseado em Táxi 300kz)
    // Lógica: Cobramos o valor do táxi por Km (ida e volta implícita ou margem de lucro no transporte)
    const transportPrice = distanceKm * taxiRate;

    // Custo estimado do transporte (Gasolina/Manutenção é menor que o preço cobrado)
    // Estimativa: 30% do valor cobrado é custo real (combustível), o resto é depreciação/tempo.
    const transportCost = transportPrice * 0.3; 

    const finalPrice = totalServicePrice + transportPrice;
    const finalCost = totalServiceCost + transportCost; 

    const profit = finalPrice - finalCost;
    const margin = finalPrice > 0 ? (profit / finalPrice) * 100 : 0;
    const totalTime = unitTime * quantity;

    return {
      finalPrice,
      finalCost,
      profit,
      margin,
      totalTime,
      serviceName: service.name,
      dirtName: dirt.name,
      transportPrice,
      distance: distanceKm
    };
  }, [selectedServiceId, quantity, dirtLevelId, distanceKm, taxiRate]);

  const handleOpenMaps = () => {
    setLocating(true);
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocating(false);
          const { latitude, longitude } = position.coords;
          // Abre o Google Maps com a origem definida, usuário só precisa por o destino para ver os KM
          const url = `https://www.google.com/maps/dir/?api=1&origin=${latitude},${longitude}&destination=&travelmode=driving`;
          window.open(url, '_blank');
        },
        (error) => {
          setLocating(false);
          alert("Não foi possível obter sua localização. Por favor, abra o mapa manualmente.");
          window.open('https://www.google.com/maps', '_blank');
        }
      );
    } else {
      setLocating(false);
      alert("Geolocalização não suportada neste navegador.");
    }
  };

  const formatTime = (minutes: number) => {
    const h = Math.floor(minutes / 60);
    const m = Math.round(minutes % 60);
    if (h > 0) return `${h}h ${m}min`;
    return `${m}min`;
  };

  const formatMoney = (val: number) => {
    return val.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-fade-in pb-20">
