import React, { useState, useMemo } from 'react';
import { Company, FinancialDocument, ExchangeRates, DocumentStatus, DocumentType } from '../types';
import { SERVICE_TYPES } from '../constants';
import { Calendar, Clock, DollarSign, BatteryCharging, AlertTriangle, TrendingUp, CheckCircle } from 'lucide-react';

interface ScheduleSimulatorProps {
  companies: Company[];
  documents: FinancialDocument[];
  rates: ExchangeRates;
}

export const ScheduleSimulator: React.FC<ScheduleSimulatorProps> = ({ companies, documents, rates }) => {
  const [simulationDate, setSimulationDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedServiceId, setSelectedServiceId] = useState(SERVICE_TYPES[0].id);
  const [newServicePrice, setNewServicePrice] = useState(SERVICE_TYPES[0].basePrice);

  // Configuração de horas de trabalho (padrão 8h)
  const WORK_DAY_MINUTES = 8 * 60; 

  const getConvertedToAOA = (amount: number, currency: string) => {
    const rateToUSD = rates[currency] || 1;
    const rateUSDToAOA = rates['AOA'] || 900;
    return (amount / rateToUSD) * rateUSDToAOA;
  };

  const simulation = useMemo(() => {
    // 1. Encontrar documentos do dia
    const dayDocs = documents.filter(d => 
      d.date === simulationDate && 
      d.status !== DocumentStatus.CANCELLED
    );

    let currentLoadMinutes = 0;
    let currentRevenueAOA = 0;

    // 2. Calcular Carga Atual
    dayDocs.forEach(doc => {
      const company = companies.find(c => c.id === doc.companyId);
      const currency = company?.currency || 'USD';

      // Receita
      const docTotal = doc.items.reduce((acc, i) => acc + (i.quantity * i.unitPrice), 0);
      currentRevenueAOA += getConvertedToAOA(docTotal, currency);

      // Tempo Estimado (Heurística: tentar achar o serviço pelo nome ou assumir 60min)
      doc.items.forEach(item => {
        // Tenta encontrar correspondência flexível no nome
        const matchedService = SERVICE_TYPES.find(s => 
          item.description.toLowerCase().includes(s.name.toLowerCase().split(' ')[0])
        );
        const time = matchedService ? matchedService.baseTime : 60; // 60min default
        currentLoadMinutes += (time * item.quantity);
      });
    });

    // 3. Simular Novo Serviço
    const newService = SERVICE_TYPES.find(s => s.id === selectedServiceId)!;
    const newServiceTime = newService.baseTime;
    const projectedLoadMinutes = currentLoadMinutes + newServiceTime;
    const projectedRevenueAOA = currentRevenueAOA + newServicePrice;

    return {
      currentLoadMinutes,
      currentRevenueAOA,
      newServiceTime,
      projectedLoadMinutes,
      projectedRevenueAOA,
      isOverload: projectedLoadMinutes > WORK_DAY_MINUTES,
      percentOccupied: (currentLoadMinutes / WORK_DAY_MINUTES) * 100,
      percentProjected: (projectedLoadMinutes / WORK_DAY_MINUTES) * 100,
      freeTimeMinutes: Math.max(0, WORK_DAY_MINUTES - currentLoadMinutes)
    };
  }, [documents, companies, rates, simulationDate, selectedServiceId, newServicePrice]);

  const formatTime = (mins: number) => {
    const h = Math.floor(mins / 60);
    const m = mins % 60;
    return `${h}h ${m}m`;
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-20">

      <div className="bg-gradient-to-r from-slate-800 to-slate-900 rounded-xl p-8 text-white shadow-xl">
        <div className="flex items-center gap-4 mb-2">
          <div className="p-3 bg-indigo-500 rounded-lg">
             <BatteryCharging size={24} className="text-white" />
          </div>
          <div>
            <h2 className="text-2xl font-bold">Simulador de Agenda</h2>
            <p className="text-indigo-200">Evite sobrecarga. Maximize o lucro.</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {/* Painel de Controle */}
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm space-y-6">
           <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
             <Calendar size={18} /> Configurar Simulação
           </h3>

           <div>
             <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Data Alvo</label>
             <input 
               type="date" 
               value={simulationDate}
               onChange={(e) => setSimulationDate(e.target.value)}
               className="w-full p-3 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
             />
           </div>

           <div>
             <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Serviço a Adicionar</label>
             <select 
               value={selectedServiceId}
               onChange={(e) => {
                 const s = SERVICE_TYPES.find(x => x.id === e.target.value);
                 setSelectedServiceId(e.target.value);
                 if(s) setNewServicePrice(s.basePrice);
               }}
               className="w-full p-3 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
             >
               {SERVICE_TYPES.map(s => (
                 <option key={s.id} value={s.id}>{s.name} ({s.baseTime} min)</option>
               ))}
             </select>
           </div>

           <div>
             <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Valor Cobrado (Kz)</label>
             <input 
               type="number" 
               value={newServicePrice}
               onChange={(e) => setNewServicePrice(parseFloat(e.target.value))}
               className="w-full p-3 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white font-bold text-emerald-600"
             />
           </div>
        </div>

        {/* Painel de Resultados */}
        <div className="space-y-4">

          {/* Carga Horária */}
          <div className="bg-white dark:bg-slate-800 p-6 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
             <div className="flex justify-between items-center mb-4">
                <span className="text-sm font-bold text-slate-600 dark:text-slate-300">Capacidade Diária (8h)</span>
                <span className={`text-xs font-bold px-2 py-1 rounded ${simulation.isOverload ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>
                  {simulation.isOverload ? 'SOBRECARGA' : 'DISPONÍVEL'}
                </span>
             </div>

             {/* Progress Bar */}
             <div className="h-6 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden relative mb-2">
                {/* Current Load */}
                <div 
                  className="h-full bg-blue-500 absolute left-0 top-0 transition-all duration-500"
                  style={{ width: `${Math.min(simulation.percentOccupied, 100)}%` }}
                ></div>
                {/* Simulated Load */}
                <div 
                  className={`h-full absolute top-0 transition-all duration-500 ${simulation.isOverload ? 'bg-red-400' : 'bg-emerald-400'}`}
                  style={{ 
                    left: `${Math.min(simulation.percentOccupied, 100)}%`,
                    width: `${Math.min(simulation.percentProjected - simulation.percentOccupied, 100 - simulation.percentOccupied)}%` 
                  }}
                ></div>
             </div>

             <div className="flex justify-between text-xs text-slate-500 mt-2">
                <span>Ocupado: {formatTime(simulation.currentLoadMinutes)}</span>
                <span className="font-bold text-emerald-600">+ {formatTime(simulation.newServiceTime)}</span>
                <span>Livre: {formatTime(simulation.freeTimeMinutes)}</span>
             </div>
          </div>

          {/* Impacto Financeiro */}
          <div className="bg-white dark:bg-slate-800 p-6 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
             <h4 className="text-sm font-bold text-slate-600 dark:text-slate-300 mb-4 flex items-center gap-2">
               <TrendingUp size={16} /> Impacto no Faturamento
             </h4>

             <div className="flex items-center justify-between">
                <div>
                   <p className="text-xs text-slate-400">Atual</p>
                   <p className="text-xl font-bold text-slate-700 dark:text-slate-300">
                     Kz {simulation.currentRevenueAOA.toLocaleString('pt-AO', { maximumFractionDigits: 0 })}
                   </p>
                </div>
                <div className="text-emerald-500">
                   <ArrowRightIcon />
                </div>
                <div className="text-right">
                   <p className="text-xs text-emerald-500 font-bold">Projetado</p>
                   <p className="text-2xl font-bold text-emerald-600 dark:text-emerald-400">
                     Kz {simulation.projectedRevenueAOA.toLocaleString('pt-AO', { maximumFractionDigits: 0 })}
                   </p>
                </div>
             </div>
          </div>

          {simulation.isOverload && (
            <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-xl border border-red-200 dark:border-red-900/50 flex items-start gap-3">
               <AlertTriangle className="text-red-500 shrink-0" />
               <p className="text-sm text-red-700 dark:text-red-300">
                 <b>Atenção:</b> Adicionar este serviço ultrapassará as 8h de trabalho diárias. Considere agendar para outro dia ou cobrar taxa de urgência.
               </p>
            </div>
          )}

           {!simulation.isOverload && simulation.projectedRevenueAOA > 0 && (
            <div className="bg-emerald-50 dark:bg-emerald-900/20 p-4 rounded-xl border border-emerald-200 dark:border-emerald-900/50 flex items-start gap-3">
               <CheckCircle className="text-emerald-500 shrink-0" />
               <p className="text-sm text-emerald-700 dark:text-emerald-300">
                 <b>Luz Verde:</b> Este serviço cabe na agenda e aumenta seu faturamento diário em Kz {newServicePrice.toLocaleString()}.
               </p>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

const ArrowRightIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
);

