import React, { useMemo } from 'react';
import { Company, FinancialDocument, ExchangeRates, DocumentStatus, DocumentType } from '../types';
import { Calendar, CheckCircle, Clock, TrendingUp, MapPin, ArrowRight, Sun, Moon, Briefcase, Wallet } from 'lucide-react';

interface DailyPanelProps {
  companies: Company[];
  documents: FinancialDocument[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
}

export const DailyPanel: React.FC<DailyPanelProps> = ({ companies, documents, rates, onNavigate }) => {
  const todayDate = new Date().toISOString().split('T')[0];

  const getConvertedToAOA = (amount: number, currency: string) => {
    const rateToUSD = rates[currency] || 1;
    const rateUSDToAOA = rates['AOA'] || 900;
    return (amount / rateToUSD) * rateUSDToAOA;
  };

  const dailyStats = useMemo(() => {
    const todayDocs = documents.filter(d => d.date === todayDate && d.status !== DocumentStatus.CANCELLED);
    let totalExpectedAOA = 0;
    let totalReceivedAOA = 0;
    let pendingCount = 0;
    let completedCount = 0;

    todayDocs.forEach(doc => {
      const company = companies.find(c => c.id === doc.companyId);
      const currency = company?.currency || 'USD';
      const docTotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
      const valAOA = getConvertedToAOA(docTotal, currency);

      if (doc.type === DocumentType.INVOICE) {
         totalExpectedAOA += valAOA;
         if (doc.status === DocumentStatus.PAID) {
           totalReceivedAOA += valAOA;
           completedCount++;
         } else {
           pendingCount++;
         }
      } else {
         if (doc.status === DocumentStatus.APPROVED) {
            totalExpectedAOA += valAOA;
            pendingCount++;
         }
      }
    });

    return {
      docs: todayDocs,
      totalExpectedAOA,
      totalReceivedAOA,
      pendingCount,
      completedCount,
      progress: totalExpectedAOA > 0 ? (totalReceivedAOA / totalExpectedAOA) * 100 : 0
    };
  }, [documents, todayDate, companies, rates]);

  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Bom dia';
    if (hour < 18) return 'Boa tarde';
    return 'Boa noite';
  }, []);

  return (
    <div className="space-y-8 animate-fade-in">

      {/* Hero Section */}
      <div className="flex justify-between items-end">
        <div>
           <div className="flex items-center gap-2 mb-1">
             {new Date().getHours() < 18 ? <Sun className="text-amber-500 w-5 h-5" /> : <Moon className="text-indigo-400 w-5 h-5" />}
             <span className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">{greeting}</span>
           </div>
           <h1 className="text-3xl lg:text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight">
             Resumo de Hoje
           </h1>
        </div>
        <div className="text-right hidden sm:block">
           <p className="text-3xl font-bold text-slate-900 dark:text-white">
             {new Date().getDate()}
           </p>
           <p className="text-sm font-medium text-slate-500 uppercase">
             {new Date().toLocaleDateString('pt-PT', { month: 'short' })}
           </p>
        </div>
      </div>

      {/* Main Feature Card */}
      <div className="bg-slate-900 dark:bg-brand-600 rounded-3xl p-6 sm:p-8 text-white shadow-xl shadow-slate-200 dark:shadow-none relative overflow-hidden group">
         <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:opacity-20 transition-opacity">
           <Wallet size={120} />
         </div>
         <div className="relative z-10">
           <p className="text-slate-400 dark:text-blue-200 font-medium mb-2">Previsão de Faturação</p>
           <h2 className="text-4xl sm:text-5xl font-bold tracking-tighter mb-6">
             Kz {dailyStats.totalExpectedAOA.toLocaleString('pt-AO', { maximumFractionDigits: 0 })}
           </h2>

           <div className="flex items-center gap-4">
              <div className="flex-1">
                <div className="flex justify-between text-xs font-semibold uppercase tracking-wider mb-2 text-slate-400 dark:text-blue-200">
                  <span>Progresso do Dia</span>
                  <span>{dailyStats.progress.toFixed(0)}%</span>
                </div>
                <div className="h-2 bg-slate-800 dark:bg-blue-800 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-500 dark:bg-white rounded-full transition-all duration-1000" style={{ width: `${dailyStats.progress}%` }}></div>
                </div>
              </div>
              <div className="bg-slate-800 dark:bg-blue-700 px-4 py-2 rounded-xl text-center">
                 <span className="block text-xl font-bold">{dailyStats.completedCount}/{dailyStats.docs.length}</span>
                 <span className="text-[10px] text-slate-400 dark:text-blue-200 uppercase">Serviços</span>
              </div>
           </div>
         </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 flex flex-col justify-between h-32">
           <div className="flex justify-between items-start">
             <div className="p-2.5 bg-amber-50 dark:bg-amber-900/20 text-amber-500 rounded-xl w-fit">
               <Clock size={20} />
             </div>
             <span className="text-xs font-bold text-slate-400 uppercase">A Receber</span>
           </div>
           <div>
             <span className="text-2xl font-bold text-slate-900 dark:text-white">
               {(dailyStats.totalExpectedAOA - dailyStats.totalReceivedAOA).toLocaleString('pt-AO', { maximumFractionDigits: 0 })}
             </span>
             <span className="text-xs text-slate-400 ml-1">Kz</span>
           </div>
        </div>

        <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 flex flex-col justify-between h-32">
           <div className="flex justify-between items-start">
             <div className="p-2.5 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-500 rounded-xl w-fit">
               <CheckCircle size={20} />
             </div>
             <span className="text-xs font-bold text-slate-400 uppercase">Realizado</span>
           </div>
           <div>
             <span className="text-2xl font-bold text-slate-900 dark:text-white">
               {dailyStats.totalReceivedAOA.toLocaleString('pt-AO', { maximumFractionDigits: 0 })}
             </span>
             <span className="text-xs text-slate-400 ml-1">Kz</span>
           </div>
        </div>
      </div>

      {/* Timeline / Agenda */}
      <div>
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-bold text-slate-900 dark:text-white">Agenda</h3>
          <button onClick={() => onNavigate('invoices')} className="text-sm font-semibold text-brand-600 dark:text-brand-400 flex items-center gap-1">
            Ver tudo <ArrowRight size={14} />
          </button>
        </div>

        {dailyStats.docs.length === 0 ? (
          <div className="bg-white dark:bg-slate-900 rounded-3xl p-10 text-center border border-dashed border-slate-200 dark:border-slate-800">
             <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
               <Calendar size={28} />
             </div>
             <p className="text-slate-900 dark:text-white font-semibold">Sem serviços agendados</p>
             <p className="text-sm text-slate-500 mb-6">Aproveite para prospectar clientes!</p>
             <button onClick={() => onNavigate('invoices')} className="px-6 py-3 bg-slate-900 dark:bg-slate-800 text-white rounded-xl text-sm font-semibold shadow-lg shadow-slate-200 dark:shadow-none">
               Agendar Agora
             </button>
          </div>
        ) : (
          <div className="space-y-4">
             {dailyStats.docs.map((doc, idx) => {
               const company = companies.find(c => c.id === doc.companyId);
               const total = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
               const isLast = idx === dailyStats.docs.length - 1;

               return (
                 <div key={doc.id} className="relative flex gap-4">
                    {/* Timeline Line */}
                    {!isLast && <div className="absolute left-[26px] top-12 bottom-[-16px] w-0.5 bg-slate-100 dark:bg-slate-800"></div>}

                    <div className={`shrink-0 w-14 h-14 rounded-2xl flex items-center justify-center text-xl font-bold border-4 border-slate-50 dark:border-slate-950 z-10 ${
                         doc.status === DocumentStatus.PAID 
                          ? 'bg-emerald-500 text-white' 
                          : 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 shadow-sm'
                       }`}>
                       {doc.clientName.charAt(0)}
                    </div>

                    <div className="flex-1 bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-soft">
                        <div className="flex justify-between items-start mb-2">
                           <div>
                              <h4 className="font-bold text-slate-900 dark:text-white text-lg">{doc.clientName}</h4>
                              <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-md ${
                                 doc.status === DocumentStatus.PAID ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400' : 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400'
                              }`}>
                                {doc.status}
                              </span>
                           </div>
                           <div className="text-right">
                              <p className="font-bold text-slate-900 dark:text-white">
                                {total.toLocaleString('pt-AO', { minimumFractionDigits: 0 })} <span className="text-xs text-slate-400 font-normal">{company?.currency}</span>
                              </p>
                           </div>
                        </div>

                        <div className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400 bg-slate-50 dark:bg-slate-950/50 p-3 rounded-xl">
                           <Briefcase size={14} className="text-brand-500" />
                           <span className="truncate">{doc.items[0]?.description} {doc.items.length > 1 && `+ ${doc.items.length - 1} itens`}</span>
                        </div>

                        <div className="mt-3 flex items-center gap-1 text-xs text-slate-400">
                           <MapPin size={10} /> {doc.companyId === company?.id ? company?.name : 'Serviço'}
                        </div>
                    </div>
                 </div>
               );
             })}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
