                 <div className="p-8 pt-10 space-y-4">
                    <div className="flex justify-between items-center text-sm border-b border-dashed border-slate-200 dark:border-slate-800 pb-3">
                       <span className="text-slate-500 dark:text-slate-400">{quantity}x {calculate.serviceName}</span>
                       <span className="font-bold text-slate-900 dark:text-white">Kz {(calculate.finalPrice - calculate.transportPrice).toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center text-sm border-b border-dashed border-slate-200 dark:border-slate-800 pb-3">
                       <span className="text-slate-500 dark:text-slate-400">Taxa Deslocamento ({calculate.distance}km)</span>
                       <span className="font-bold text-slate-900 dark:text-white">Kz {calculate.transportPrice.toLocaleString()}</span>
                    </div>

                    <div className="py-4">
                       <div className="flex justify-between items-end">
                          <span className="text-sm font-bold text-slate-500 uppercase">Total Final</span>
                          <span className="text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight">
                            {formatMoney(calculate.finalPrice)}<span className="text-lg text-slate-400 ml-1 font-normal">Kz</span>
                          </span>
                       </div>
                       <div className="flex gap-2 mt-4">
                          <div className="bg-emerald-50 dark:bg-emerald-900/20 px-3 py-1 rounded-lg text-xs font-bold text-emerald-600">
                             Lucro: {formatMoney(calculate.profit)}
                          </div>
                          <div className="bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-lg text-xs font-bold text-slate-500 flex items-center gap-1">
                             <Clock size={12}/> {formatTime(calculate.totalTime)}
                          </div>
                       </div>
                    </div>
                 </div>

                 <div className="p-4 bg-slate-50 dark:bg-black/20">
                    <button 
                      onClick={() => {
                        const text = `Orçamento: ${calculate.serviceName} x${quantity} + Deslocamento. Total: ${formatMoney(calculate.finalPrice)} Kz`;
                        if(navigator.share) navigator.share({title: 'Orçamento', text});
                        else { navigator.clipboard.writeText(text); alert('Copiado!'); }
                      }}
                      className="w-full py-4 bg-slate-900 dark:bg-indigo-600 text-white font-bold rounded-2xl shadow-lg active:scale-95 transition-transform flex items-center justify-center gap-2"
                    >
                       <Share2 size={20} /> Partilhar Orçamento
                    </button>
                 </div>
              </div>

            </div>
          </div>
      </div>
    </div>
  );
};

const CACHE_NAME = 'nrl-finance-v2.1';
const urlsToCache = [
  './',
  './index.html',
  './manifest.json',
  // Cache External Libraries for Offline Mode
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap',
  'https://esm.sh/react@^19.2.3/',
  'https://esm.sh/react@^19.2.3',
  'https://esm.sh/react-dom@^19.2.3/',
  'https://esm.sh/@google/genai@^1.34.0',
  'https://esm.sh/recharts@^3.6.0',
  'https://esm.sh/lucide-react@^0.562.0',
  'https://esm.sh/jspdf@2.5.1',
  'https://esm.sh/jspdf-autotable@3.8.2',
  'https://cdn-icons-png.flaticon.com/512/2534/2534182.png'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then((cache) => {
        return cache.addAll(urlsToCache);
      })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request)
      .then((response) => {
        // Cache hit - return response
        if (response) {
          return response;
        }
        return fetch(event.request);
      })
  );
});

self.addEventListener('activate', (event) => {
  const cacheWhitelist = [CACHE_NAME];
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheWhitelist.indexOf(cacheName) === -1) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
});

