import React, { useMemo, useState, useEffect } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates, Currency, AppSettings } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { ArrowUpCircle, ArrowDownCircle, DollarSign, Briefcase, PieChart as PieChartIcon, TrendingUp, CalendarClock, Calculator, Settings, X, Save, Upload, Image as ImageIcon } from 'lucide-react';
import { StorageService } from '../services/storageService';

interface DashboardProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
  onNavigate: (view: any) => void;
  appSettings: AppSettings;
  onUpdateSettings: (settings: AppSettings) => void;
}

const COLORS = ['#0ea5e9', '#10b981', '#ef4444', '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ 
  companies, 
  transactions, 
  rates: initialRates, 
  onNavigate,
  appSettings,
  onUpdateSettings
}) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
  const [currentRates, setCurrentRates] = useState<ExchangeRates>(initialRates);
  const [settingsTab, setSettingsTab] = useState<'general' | 'rates'>('general');
  const [tempSettings, setTempSettings] = useState<AppSettings>(appSettings);

  // Sync state when props change
  useEffect(() => {
    if (Object.keys(initialRates).length > 0) setCurrentRates(initialRates);
  }, [initialRates]);

  useEffect(() => {
    setTempSettings(appSettings);
  }, [appSettings]);

  const handleSaveAll = () => {
    // 1. Save Rates to Storage
    StorageService.saveRates(currentRates);

    // 2. Save App Settings to Storage via prop callback (which handles StorageService.saveSettings)
    onUpdateSettings(tempSettings);

    setIsSettingsModalOpen(false);

    // Optional: Add visual feedback toast here
    alert("Configurações salvas com sucesso!");
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempSettings(prev => ({ ...prev, logo: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const activeRates = currentRates;

  // Mapa de Empresas Ativas
  const activeCompanyMap = useMemo(() => {
    const map = new Map<string, Company>();
    companies.forEach(c => {
      if (c.status !== 'Encerrado') {
        map.set(c.id, c);
      }
    });
    return map;
  }, [companies]);

  // Helper para conversão para AOA (Kwanza)
  const getConvertedToAOA = (amount: number, currency: Currency) => {
    const rateToUSD = activeRates[currency]; 
    const rateUSDToAOA = activeRates[Currency.AOA] || 900; 
    const safeRateToUSD = (rateToUSD !== undefined && rateToUSD > 0) ? rateToUSD : 1;
    const amountInUSD = amount / safeRateToUSD;
    return amountInUSD * rateUSDToAOA;
  };

  // Helper de formatação
  const formatAOA = (val: number) => {
    return val.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  // Cálculo de Totais (O(N))
  const totals = useMemo(() => {
    let totalIncome = 0;
    let totalExpense = 0;

    transactions.forEach(t => {
      const company = activeCompanyMap.get(t.companyId);
      if (!company) return; 

      const aoaValue = getConvertedToAOA(t.amount, company.currency);

      if (t.type === TransactionType.INCOME) {
        totalIncome += aoaValue;
      } else {
        totalExpense += aoaValue;
      }
    });

    return {
      income: totalIncome,
      expense: totalExpense,
      profit: totalIncome - totalExpense
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // Forecast (Previsão)
  const forecast = useMemo(() => {
    const today = new Date();
    const currentMonthKey = today.toISOString().slice(0, 7);

    const pastMonthsSet = new Set<string>();
    for (let i = 1; i <= 3; i++) {
        const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
        pastMonthsSet.add(d.toISOString().slice(0, 7));
    }

    const companyStats = new Map<string, {
      incomeSum: number;
      incomeMonths: Set<string>;
      fixedSum: number;
      variableSum: number;
      variableMonths: Set<string>;
    }>();

    activeCompanyMap.forEach((_, id) => {
      companyStats.set(id, {
        incomeSum: 0,
        incomeMonths: new Set(),
        fixedSum: 0,
        variableSum: 0,
        variableMonths: new Set()
      });
    });

    transactions.forEach(t => {
      const stats = companyStats.get(t.companyId);
      if (!stats) return;

      const monthKey = t.date.slice(0, 7);

      if (t.type === TransactionType.INCOME && pastMonthsSet.has(monthKey)) {
        stats.incomeSum += t.amount;
        stats.incomeMonths.add(monthKey);
      }

      if (t.type === TransactionType.EXPENSE) {
        if (t.isFixed && monthKey === currentMonthKey) {
          stats.fixedSum += t.amount;
        }
        if (!t.isFixed && pastMonthsSet.has(monthKey)) {
          stats.variableSum += t.amount;
          stats.variableMonths.add(monthKey);
        }
      }
    });

    let projectedIncome = 0;
    let projectedFixedExpense = 0;
    let projectedVariableExpense = 0;

    companyStats.forEach((stats, companyId) => {
      const company = activeCompanyMap.get(companyId)!;

      const avgIncome = stats.incomeMonths.size > 0 ? stats.incomeSum / stats.incomeMonths.size : 0;
      projectedIncome += getConvertedToAOA(avgIncome, company.currency);

      projectedFixedExpense += getConvertedToAOA(stats.fixedSum, company.currency);

      const avgVariable = stats.variableMonths.size > 0 ? stats.variableSum / stats.variableMonths.size : 0;
      projectedVariableExpense += getConvertedToAOA(avgVariable, company.currency);
    });

    const totalProjectedExpense = projectedFixedExpense + projectedVariableExpense;

    return {
        income: projectedIncome,
        expense: totalProjectedExpense,
        profit: projectedIncome - totalProjectedExpense,
        fixedShare: totalProjectedExpense > 0 ? (projectedFixedExpense / totalProjectedExpense) * 100 : 0
    };
  }, [transactions, activeCompanyMap, activeRates]);

  // Chart Data
  const chartData = useMemo(() => {
    const last6Months = new Map<string, { name: string, income: number, expense: number }>();
    const today = new Date();

    for (let i = 5; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const key = d.toISOString().slice(0, 7);
      last6Months.set(key, {
        name: d.toLocaleDateString('pt-PT', { month: 'short' }),
        income: 0,
        expense: 0
      });
    }

    transactions.forEach(t => {
      const monthKey = t.date.slice(0, 7);
      const monthData = last6Months.get(monthKey);

      if (monthData) {
        const company = activeCompanyMap.get(t.companyId);
        if (company) {
           const val = getConvertedToAOA(t.amount, company.currency);
           if (t.type === TransactionType.INCOME) monthData.income += val;
           else monthData.expense += val;
        }
      }
    });

    return Array.from(last6Months.values()).map(d => ({
      name: d.name,
      Entradas: parseFloat(d.income.toFixed(2)),
      Saídas: parseFloat(d.expense.toFixed(2)),
      Lucro: parseFloat((d.income - d.expense).toFixed(2))
    }));

  }, [transactions, activeCompanyMap, activeRates]);

  // Pie Chart
  const pieData = useMemo(() => {
    const dataMap = new Map<string, number>();

    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(selectedMonth)) {
         const company = activeCompanyMap.get(t.companyId);
         if (company) {
             const val = getConvertedToAOA(t.amount, company.currency);
             const currentVal = dataMap.get(t.category) || 0;
             dataMap.set(t.category, currentVal + val);
         }
      }
    });

    return Array.from(dataMap.entries())
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
  }, [transactions, activeCompanyMap, activeRates, selectedMonth]);

  return (
    <div className="space-y-6 animate-fade-in relative">

      {/* Settings Modal */}
      {isSettingsModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl max-w-md w-full p-6 animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                <Settings className="text-brand-500" /> Configurações
              </h3>
              <button onClick={() => setIsSettingsModalOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                <X size={24} />
              </button>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-slate-200 dark:border-slate-700 mb-4">
               <button 
                 onClick={() => setSettingsTab('general')}
                 className={`flex-1 py-2 text-sm font-medium border-b-2 transition-colors ${settingsTab === 'general' ? 'border-brand-500 text-brand-600' : 'border-transparent text-slate-500'}`}
               >
                 Geral & Marca
               </button>
               <button 
                 onClick={() => setSettingsTab('rates')}
                 className={`flex-1 py-2 text-sm font-medium border-b-2 transition-colors ${settingsTab === 'rates' ? 'border-brand-500 text-brand-600' : 'border-transparent text-slate-500'}`}
               >
                 Taxas de Câmbio
               </button>
            </div>

            {settingsTab === 'general' ? (
              <div className="space-y-4">
                 <div>
                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1">Nome da Aplicação</label>
                    <p className="text-xs text-slate-500 mb-2">Este nome aparecerá no topo do menu lateral e no cabeçalho.</p>
                    <input 
                      type="text" 
                      value={tempSettings.appName}
                      onChange={(e) => setTempSettings({...tempSettings, appName: e.target.value})}
                      className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                      placeholder="Ex: Minha Gestão"
                      required
                    />
                 </div>
                 <div>
                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1">Logo do App (Documentos e Menu)</label>
                    <div className="flex items-center gap-4">
                       <div className="w-16 h-16 rounded-lg border-2 border-dashed border-slate-300 dark:border-slate-600 flex items-center justify-center overflow-hidden bg-slate-50 dark:bg-slate-900 shrink-0">
                          {tempSettings.logo ? (
                            <img src={tempSettings.logo} alt="Logo" className="w-full h-full object-cover" />
                          ) : (
                            <ImageIcon className="text-slate-400" />
                          )}
                       </div>
                       <label className="cursor-pointer bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 text-slate-600 dark:text-slate-200 px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors w-full justify-center">
                          <Upload size={16} /> Alterar Imagem
                          <input type="file" accept="image/*" className="hidden" onChange={handleLogoUpload} />
                       </label>
                    </div>
                    <p className="text-xs text-slate-400 mt-2">Aparecerá no menu lateral e no topo dos PDFs gerados.</p>
                 </div>
              </div>
            ) : (
              <>
                 <p className="text-sm text-slate-500 dark:text-slate-400 mb-4 bg-amber-50 dark:bg-amber-900/20 p-3 rounded-lg border border-amber-100 dark:border-amber-800 text-amber-800 dark:text-amber-200">
                   Base de cálculo: 1 USD. Defina quanto vale 1 USD na moeda local.
                </p>
                <div className="space-y-4">
                  {Object.keys(currentRates).filter(k => k !== 'USD').map(currency => (
                    <div key={currency}>
                      <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                        1 USD = ? {currency}
                      </label>
                      <input 
                        type="number" 
                        step="0.01"
                        value={currentRates[currency]}
                        onChange={(e) => setCurrentRates({...currentRates, [currency]: parseFloat(e.target.value)})}
                        className="w-full p-2.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                      />
                    </div>
                  ))}
                </div>
              </>
            )}

            <div className="mt-8 flex justify-end gap-3">
              <button onClick={() => setIsSettingsModalOpen(false)} className="px-4 py-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">Cancelar</button>
              <button onClick={handleSaveAll} className="px-4 py-2 bg-brand-600 text-white rounded-lg hover:bg-brand-700 flex items-center gap-2 font-medium">
                <Save size={18} /> Salvar Alterações
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Visão Geral (Kwanzas)</h2>
           <div className="text-sm text-slate-500">Valores consolidados em AOA.</div>
        </div>
        <button 
          onClick={() => setIsSettingsModalOpen(true)}
          className="flex items-center gap-2 px-3 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg text-sm font-medium text-slate-600 dark:text-slate-300 transition-colors"
        >
          <Settings size={16} /> Configurar
        </button>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Receita Total</p>
              <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                Kz {formatAOA(totals.income)}
              </h3>
            </div>
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
              <ArrowUpCircle className="w-6 h-6 text-emerald-600 dark:text-emerald-400" />
