  quantity: number;
  dirtLevelId: string;
  dirtLevelName: string;
  unitPrice: number;
  totalPrice: number;
  totalCost: number;
  totalTime: number;
}

export const PriceCalculator: React.FC = () => {
  // Configuração do Item Atual
  const [selectedServiceId, setSelectedServiceId] = useState(SERVICE_TYPES[0].id);
  const [quantity, setQuantity] = useState(1);
  const [dirtLevelId, setDirtLevelId] = useState(DIRT_LEVELS[1].id);

  // Lista de Itens Adicionados
  const [items, setItems] = useState<CalculatorItem[]>([]);

  // Configurações Globais (Transporte)
  const [distanceKm, setDistanceKm] = useState(5);
  const [taxiRate, setTaxiRate] = useState(300);
  const [locating, setLocating] = useState(false);

  // Calcula os valores da SELEÇÃO ATUAL (para mostrar no botão de adicionar)
  const currentSelectionPreview = useMemo(() => {
    const service = SERVICE_TYPES.find(s => s.id === selectedServiceId)!;
    const dirt = DIRT_LEVELS.find(d => d.id === dirtLevelId)!;

    const unitPrice = service.basePrice * dirt.priceMult;
    const currentPrice = unitPrice * quantity;

    return { currentPrice, unitPrice, service, dirt };
  }, [selectedServiceId, dirtLevelId, quantity]);

  // Calcula o TOTAL GERAL (Itens + Transporte)
  const grandTotal = useMemo(() => {
    const servicesPrice = items.reduce((acc, item) => acc + item.totalPrice, 0);
    const servicesCost = items.reduce((acc, item) => acc + item.totalCost, 0);
    const servicesTime = items.reduce((acc, item) => acc + item.totalTime, 0);

    const transportPrice = distanceKm * taxiRate;
    const transportCost = transportPrice * 0.3; // Estimativa de custo de combustível/tempo

    const finalPrice = servicesPrice + transportPrice;
    const finalCost = servicesCost + transportCost;
    const profit = finalPrice - finalCost;

    return {
      servicesPrice,
      transportPrice,
      finalPrice,
      finalCost,
      profit,
      totalTime: servicesTime
    };
  }, [items, distanceKm, taxiRate]);

  const handleAddItem = () => {
    const { service, dirt, unitPrice, currentPrice } = currentSelectionPreview;

    const unitCost = service.baseCost * dirt.costMult;
    const unitTime = service.baseTime * dirt.timeMult;

    const newItem: CalculatorItem = {
      id: Math.random().toString(36).substr(2, 9),
      serviceId: service.id,
      serviceName: service.name,
      quantity: quantity,
      dirtLevelId: dirt.id,
      dirtLevelName: dirt.name,
      unitPrice: unitPrice,
      totalPrice: currentPrice,
      totalCost: unitCost * quantity,
      totalTime: unitTime * quantity
    };

    setItems([...items, newItem]);
    // Resetar quantidade para facilitar nova adição
    setQuantity(1);
  };

  const handleRemoveItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  const handleOpenMaps = () => {
    setLocating(true);
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocating(false);
          const { latitude, longitude } = position.coords;
          const url = `https://www.google.com/maps/dir/?api=1&origin=${latitude},${longitude}&destination=&travelmode=driving`;
          window.open(url, '_blank');
        },
        () => {
          setLocating(false);
          window.open('https://www.google.com/maps', '_blank');
        }
      );
    } else {
      setLocating(false);
    }
  };

  const formatTime = (minutes: number) => {
    const h = Math.floor(minutes / 60);
    const m = Math.round(minutes % 60);
    if (h > 0) return `${h}h ${m}m`;
    return `${m}m`;
  };

  const formatMoney = (val: number) => val.toLocaleString('pt-AO', { minimumFractionDigits: 0, maximumFractionDigits: 0 });

  const handleShare = () => {
    const itemsList = items.map(i => `- ${i.quantity}x ${i.serviceName} (${i.dirtLevelName})`).join('\n');
    const text = `Orçamento Estimado:\n\n${itemsList}\n\n+ Deslocamento (${distanceKm}km)\n\nTOTAL: Kz ${formatMoney(grandTotal.finalPrice)}`;

    if (navigator.share) {
      navigator.share({ title: 'Orçamento de Limpeza', text });
    } else {
      navigator.clipboard.writeText(text);
      alert('Orçamento copiado para a área de transferência!');
    }
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">

      {/* Title */}
      <div className="flex items-center gap-3 mb-6">
        <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-indigo-200 dark:shadow-none">
           <Calculator size={24} />
        </div>
        <div>
           <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Calculadora Inteligente</h2>
           <p className="text-sm text-slate-500">Adicione múltiplos itens e calcule o lucro exato.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Controls Column */}
          <div className="lg:col-span-7 space-y-8">

            {/* 1. Select Service */}
            <div>
               <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 block px-1">1. Escolha o Serviço</label>
               <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide snap-x">
                  {SERVICE_TYPES.map(s => (
                    <button
                      key={s.id}
                      onClick={() => setSelectedServiceId(s.id)}
                      className={`shrink-0 w-40 p-4 rounded-3xl border text-left transition-all snap-start ${
                        selectedServiceId === s.id 
                        ? 'border-indigo-600 bg-indigo-600 text-white shadow-lg shadow-indigo-200 dark:shadow-none' 
                        : 'border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-400'
                      }`}
                    >
                      <Sofa size={24} className="mb-3 opacity-80" />
                      <div className="font-bold leading-tight">{s.name}</div>
                      <div className="text-[10px] mt-1 opacity-70">Base: {s.basePrice}</div>
                    </button>
                  ))}
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* 2. Quantity */}
                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm">
                   <div className="flex justify-between mb-4">
                      <span className="font-bold text-slate-900 dark:text-white">2. Quantidade</span>
                      <span className="font-bold text-indigo-600 text-xl">{quantity}</span>
                   </div>
                   <input 
                      type="range" min="1" max="20" 
                      value={quantity} 
                      onChange={(e) => setQuantity(parseInt(e.target.value))}
                      className="w-full h-4 bg-slate-100 dark:bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-600"
                   />
                </div>

                {/* 3. Dirt Level */}
                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm">
                   <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 block">3. Estado / Sujidade</label>
                   <div className="grid grid-cols-1 gap-2">
                      {DIRT_LEVELS.map(d => (
                        <button
                          key={d.id}
                          onClick={() => setDirtLevelId(d.id)}
                          className={`px-4 py-3 rounded-xl border text-left transition-all flex justify-between items-center text-sm ${
                            dirtLevelId === d.id 
                            ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 ring-1 ring-blue-500 font-bold' 
                            : 'border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-400'
                          }`}
                        >
                          <span>{d.name}</span>
                        </button>
                      ))}
                   </div>
                </div>
            </div>

            {/* ADD BUTTON */}
            <button 
                onClick={handleAddItem}
                className="w-full py-4 bg-slate-900 dark:bg-indigo-600 text-white rounded-2xl shadow-lg hover:shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
            >
                <Plus size={24} />
                <div className="text-left leading-tight">
                    <span className="block font-bold">Adicionar ao Orçamento</span>
                    <span className="text-xs opacity-80">
                        {quantity}x {currentSelectionPreview.service.name} (+ Kz {formatMoney(currentSelectionPreview.currentPrice)})
                    </span>
                </div>
            </button>

            {/* Global Settings: Location */}
            <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 mt-8">
                <div className="flex justify-between items-center mb-4">
                  <span className="font-bold text-slate-700 dark:text-slate-200 flex items-center gap-2"><MapPin size={18}/> Deslocamento (Global)</span>
                  <button onClick={handleOpenMaps} className="text-xs font-bold text-blue-600 bg-blue-100 dark:bg-blue-900/30 px-3 py-1.5 rounded-full hover:bg-blue-200 transition-colors">
                    {locating ? '...' : 'Abrir Mapa'}
                  </button>
                </div>
                <div className="flex gap-4">
                   <div className="flex-1">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">KM (Ida e Volta)</label>
                      <input 
                        type="number" value={distanceKm} 
                        onChange={(e) => setDistanceKm(parseFloat(e.target.value) || 0)}
                        className="w-full bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-200 dark:border-slate-700 font-bold text-lg dark:text-white mt-1"
                      />
                   </div>
                   <div className="flex-1">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Taxa (Kz/Km)</label>
                      <input 
                        type="number" value={taxiRate} 
                        onChange={(e) => setTaxiRate(parseFloat(e.target.value) || 0)}
                        className="w-full bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-200 dark:border-slate-700 font-bold text-lg dark:text-white mt-1"
                      />
                   </div>
                </div>
            </div>

          </div>

          {/* Receipt Column (Sticky) */}
          <div className="lg:col-span-5">
            <div className="sticky top-6">

              <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl shadow-slate-200 dark:shadow-black/50 overflow-hidden border border-slate-100 dark:border-slate-800 relative flex flex-col min-h-[500px]">
                 {/* Receipt Header */}
                 <div className="bg-slate-900 dark:bg-black p-6 text-center text-white relative shrink-0">
                    <div className="w-12 h-1 bg-slate-700 rounded-full mx-auto mb-4"></div>
                    <h3 className="text-lg font-bold">Resumo do Orçamento</h3>
                    <p className="text-slate-400 text-sm">{new Date().toLocaleDateString()}</p>
                    <div className="absolute bottom-[-6px] left-0 right-0 h-3 bg-white dark:bg-slate-900" style={{maskImage: 'radial-gradient(circle, transparent 6px, black 7px)', maskSize: '20px 20px', maskPosition: 'center bottom'}}></div>
                 </div>

                 {/* Receipt List */}
                 <div className="p-6 pt-8 flex-1 overflow-y-auto max-h-[400px]">
                    {items.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 py-10 opacity-60">
                            <ShoppingCart size={48} className="mb-4" />
                            <p className="text-sm font-medium">O carrinho está vazio</p>
                            <p className="text-xs">Configure e clique em adicionar.</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {items.map(item => (
                                <div key={item.id} className="flex justify-between items-start border-b border-dashed border-slate-100 dark:border-slate-800 pb-3 group">
                                    <div className="flex-1">
                                        <div className="font-bold text-slate-800 dark:text-slate-200 text-sm">
                                            {item.quantity}x {item.serviceName}
                                        </div>
                                        <div className="text-xs text-slate-500">
                                            {item.dirtLevelName}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="font-bold text-slate-900 dark:text-white text-sm">
                                            Kz {formatMoney(item.totalPrice)}
                                        </div>
                                        <button 
                                            onClick={() => handleRemoveItem(item.id)}
                                            className="text-xs text-rose-500 hover:text-rose-700 opacity-0 group-hover:opacity-100 transition-opacity mt-1 flex items-center gap-1 ml-auto"
                                        >
                                            <Trash2 size={10} /> Remover
                                        </button>
                                    </div>
                                </div>
                            ))}

                            {/* Transport Line */}
                            <div className="flex justify-between items-center text-sm pt-2 text-slate-500 dark:text-slate-400 font-medium">
                                <span className="flex items-center gap-1"><MapPin size={12}/> Deslocamento ({distanceKm}km)</span>
                                <span>Kz {formatMoney(grandTotal.transportPrice)}</span>
                            </div>
                        </div>
                    )}
                 </div>

                 {/* Receipt Footer (Total) */}
                 <div className="p-6 bg-slate-50 dark:bg-black/20 mt-auto border-t border-slate-100 dark:border-slate-800">
                    <div className="flex justify-between items-end mb-4">
                       <span className="text-sm font-bold text-slate-500 uppercase">Total Final</span>
                       <span className="text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight">
                         {formatMoney(grandTotal.finalPrice)}<span className="text-lg text-slate-400 ml-1 font-normal">Kz</span>
                       </span>
                    </div>

                    <div className="flex gap-2 mb-4">
                        <div className="bg-emerald-50 dark:bg-emerald-900/20 px-3 py-1.5 rounded-lg text-xs font-bold text-emerald-600 border border-emerald-100 dark:border-emerald-800/30">
                            Lucro: {formatMoney(grandTotal.profit)}
                        </div>
                        <div className="bg-slate-100 dark:bg-slate-800 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-500 flex items-center gap-1">
                            <Clock size={12}/> {formatTime(grandTotal.totalTime)}
                        </div>
                    </div>

                    <button 
                      onClick={handleShare}
                      disabled={items.length === 0}
                      className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-2xl shadow-lg active:scale-95 transition-transform flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                       <Share2 size={20} /> Copiar / Partilhar
                    </button>
                 </div>
              </div>

              <div className="mt-4 flex gap-2 text-xs text-slate-400 justify-center">
                 <Info size={14} />
                 <span>O lucro desconta 30% para custos operacionais.</span>
              </div>

            </div>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Company, Transaction, MonthlyNote, ExchangeRates, ViewState, CategoryItem, TransactionType, FinancialDocument, AppSettings } from './types';
import { StorageService } from './services/storageService';
import { Dashboard } from './components/Dashboard';
import { CompanyManager } from './components/CompanyManager';
import { MonthDetail } from './components/MonthDetail';
import { Reports } from './components/Reports';
import { CategorySettings } from './components/CategorySettings';
import { Invoices } from './components/Invoices';
import { PriceCalculator } from './components/PriceCalculator';
import { DailyPanel } from './components/DailyPanel';
import { ScheduleSimulator } from './components/ScheduleSimulator';
import { LayoutDashboard, Building2, Calendar, FileBarChart, Settings, Home, Sun, Moon, PlusCircle, MoreHorizontal, Calculator, Zap, BatteryCharging, WifiOff, FileText, ChevronRight, Download } from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [companies, setCompanies] = useState<Company[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notes, setNotes] = useState<MonthlyNote[]>([]);
  const [rates, setRates] = useState<ExchangeRates>({});
  const [categories, setCategories] = useState<CategoryItem[]>([]);
  const [documents, setDocuments] = useState<FinancialDocument[]>([]);
  const [appSettings, setAppSettings] = useState<AppSettings>({ appName: 'Rota do Lucro', logo: '' });

  // UI State
  const [currentView, setCurrentView] = useState<ViewState>('daily');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [showMobileMenu, setShowMobileMenu] = useState(false); // For "More" tab

  // PWA Install State
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  // Initialization
  useEffect(() => {
    setCompanies(StorageService.getCompanies());
    setTransactions(StorageService.getTransactions());
    setNotes(StorageService.getNotes());
    setRates(StorageService.getRates());
    setCategories(StorageService.getCategories());
    setDocuments(StorageService.getDocuments());
    setAppSettings(StorageService.getSettings());

    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setIsDarkMode(true);
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    // Capture Install Prompt
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // Update document title when appName changes
  useEffect(() => {
    document.title = appSettings.appName;
  }, [appSettings.appName]);

  // Handlers
  const handleSaveCompany = (c: Company) => {
    const updated = companies.some(x => x.id === c.id) ? companies.map(x => x.id === c.id ? c : x) : [...companies, c];
    setCompanies(updated); StorageService.saveCompanies(updated);
  };
  const handleDeleteCompany = (id: string) => {
    if (confirm('Apagar empresa?')) {
        const updated = companies.filter(c => c.id !== id);
        setCompanies(updated); StorageService.saveCompanies(updated);
    }
  };
  const handleAddTransaction = (t: Transaction) => {
    const updated = [...transactions, t];
    setTransactions(updated); StorageService.saveTransactions(updated);
  };
  const handleDeleteTransaction = (id: string) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated); StorageService.saveTransactions(updated);
  };
  const handleSaveNote = (n: MonthlyNote) => {
    const updated = [...notes.filter(x => !(x.companyId === n.companyId && x.monthStr === n.monthStr)), n];
    setNotes(updated); StorageService.saveNotes(updated);
  };
  const handleSaveDocument = (d: FinancialDocument) => {
    const updated = documents.some(x => x.id === d.id) ? documents.map(x => x.id === d.id ? d : x) : [...documents, d];
    setDocuments(updated); StorageService.saveDocuments(updated);
  };
  const handleDeleteDocument = (id: string) => {
     if(confirm("Apagar documento?")) {
        const updated = documents.filter(d => d.id !== id);
        setDocuments(updated); StorageService.saveDocuments(updated);
     }
  };
  const handleUpdateSettings = (s: AppSettings) => { 
    setAppSettings(s); 
    StorageService.saveSettings(s); 
  };
  const handleAddCategory = (name: string, type: TransactionType) => {
     if (categories.some(c => c.name.toLowerCase() === name.toLowerCase() && c.type === type)) return;
     const updated = [...categories, { id: Math.random().toString(36).substr(2, 9), name, type }];
     setCategories(updated); StorageService.saveCategories(updated);
  };
  const handleEditCategory = (id: string, newName: string) => {
    const updated = categories.map(c => c.id === id ? { ...c, name: newName } : c);
    setCategories(updated); StorageService.saveCategories(updated);
  };
  const handleDeleteCategory = (id: string) => {
      const updated = categories.filter(c => c.id !== id);
      setCategories(updated); StorageService.saveCategories(updated);
  };

  const handleInstallApp = () => {
    if (installPrompt) {
      installPrompt.prompt();
      installPrompt.userChoice.then((choiceResult: any) => {
        if (choiceResult.outcome === 'accepted') {
          console.log('User accepted the install prompt');
        }
        setInstallPrompt(null);
      });
    }
  };

  // --- Components ---

  const DesktopSidebarItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => (
    <button
      onClick={() => setCurrentView(view)}
      className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 group ${
        currentView === view 
          ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' 
          : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
      }`}
    >
      <Icon size={20} className={currentView === view ? 'animate-pulse' : 'group-hover:scale-110 transition-transform'} />
      <span className="font-semibold">{label}</span>
      {currentView === view && <ChevronRight size={16} className="ml-auto opacity-50" />}
    </button>
  );

  const MobileTabItem = ({ view, icon: Icon, label }: { view: ViewState | 'more', icon: any, label: string }) => {
    const isActive = currentView === view || (view === 'more' && showMobileMenu);
    return (
      <button 
        onClick={() => {
            if (view === 'more') setShowMobileMenu(true);
            else { setCurrentView(view as ViewState); setShowMobileMenu(false); }
        }}
        className={`flex flex-col items-center justify-center w-full h-full gap-1 ${
           isActive ? 'text-brand-600 dark:text-brand-400' : 'text-slate-400 dark:text-slate-500'
        }`}
      >
        <div className={`p-1.5 rounded-xl transition-all ${isActive ? 'bg-brand-50 dark:bg-brand-900/20' : ''}`}>
           <Icon size={22} strokeWidth={isActive ? 2.5 : 2} />
        </div>
        <span className="text-[10px] font-semibold">{label}</span>
      </button>
    )
  };

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-white overflow-hidden selection:bg-brand-500 selection:text-white">

      {/* DESKTOP SIDEBAR */}
      <aside className="hidden lg:flex flex-col w-72 h-full bg-white dark:bg-slate-900 border-r border-slate-100 dark:border-slate-800/50 relative z-20">
        <div className="p-8 flex items-center gap-3">
          {appSettings.logo ? (
             <img src={appSettings.logo} alt="Logo" className="w-10 h-10 rounded-xl object-cover shadow-lg" />
          ) : (
             <div className="w-10 h-10 bg-gradient-to-br from-brand-500 to-brand-700 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-brand-500/30">
                {appSettings.appName.charAt(0)}
             </div>
          )}
          <h1 className="text-lg font-bold tracking-tight text-slate-900 dark:text-white leading-tight">
            {appSettings.appName}
          </h1>
        </div>

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto custom-scrollbar">
          <p className="px-4 text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 mt-2">Principal</p>
          <DesktopSidebarItem view="daily" icon={Home} label="Início" />
          <DesktopSidebarItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <DesktopSidebarItem view="simulator" icon={BatteryCharging} label="Simulador" />

          <p className="px-4 text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 mt-6">Gestão</p>
          <DesktopSidebarItem view="invoices" icon={FileText} label="Orçamentos" />
          <DesktopSidebarItem view="month-detail" icon={Calendar} label="Lançamentos" />
          <DesktopSidebarItem view="companies" icon={Building2} label="Empresas" />

          <p className="px-4 text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 mt-6">Ferramentas</p>
          <DesktopSidebarItem view="calculator" icon={Calculator} label="Calculadora" />
          <DesktopSidebarItem view="reports" icon={FileBarChart} label="Relatórios" />
        </nav>

