        const isOldName = !parsed.appName || parsed.appName === "Na Rota do Lucro" || parsed.appName === "RotaDoLucro";
        const isOldLogo = parsed.logo && parsed.logo.startsWith('data:image/svg');

        if (isOldName || isOldLogo) {
