import React, { useState, useEffect } from 'react';
import { Company, Transaction, MonthlyNote, ExchangeRates, ViewState, CategoryItem, TransactionType, FinancialDocument, AppSettings } from './types';
import { StorageService } from './services/storageService';
import { Dashboard } from './components/Dashboard';
import { CompanyManager } from './components/CompanyManager';
import { MonthDetail } from './components/MonthDetail';
import { Reports } from './components/Reports';
import { CategorySettings } from './components/CategorySettings';
import { Invoices } from './components/Invoices';
import { PriceCalculator } from './components/PriceCalculator';
import { DailyPanel } from './components/DailyPanel';
import { ScheduleSimulator } from './components/ScheduleSimulator';
import { LayoutDashboard, Building2, Calendar, FileBarChart, Settings, Home, Sun, Moon, PlusCircle, MoreHorizontal, Calculator, Zap, BatteryCharging, WifiOff, FileText, ChevronRight, Download } from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [companies, setCompanies] = useState<Company[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notes, setNotes] = useState<MonthlyNote[]>([]);
  const [rates, setRates] = useState<ExchangeRates>({});
  const [categories, setCategories] = useState<CategoryItem[]>([]);
  const [documents, setDocuments] = useState<FinancialDocument[]>([]);
  const [appSettings, setAppSettings] = useState<AppSettings>({ appName: 'Rota do Lucro', logo: '' });

  // UI State
  const [currentView, setCurrentView] = useState<ViewState>('daily');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [showMobileMenu, setShowMobileMenu] = useState(false); // For "More" tab

  // PWA Install State
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  // Initialization
  useEffect(() => {
    setCompanies(StorageService.getCompanies());
    setTransactions(StorageService.getTransactions());
    setNotes(StorageService.getNotes());
    setRates(StorageService.getRates());
    setCategories(StorageService.getCategories());
    setDocuments(StorageService.getDocuments());
    setAppSettings(StorageService.getSettings());

    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setIsDarkMode(true);
    }

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    // Capture Install Prompt
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // Update document title, favicon and Apple Touch Icon when appName or logo changes
  useEffect(() => {
    // 1. Title
    document.title = appSettings.appName;

    // 2. Icons
    if (appSettings.logo) {
      // Favicon
      const link = document.querySelector("link[rel~='icon']") as HTMLLinkElement;
      if (link) {
        link.href = appSettings.logo;
      } else {
        const newLink = document.createElement('link');
        newLink.rel = 'icon';
        newLink.href = appSettings.logo;
        document.head.appendChild(newLink);
      }

      // Apple Touch Icon
      const appleLink = document.querySelector("link[rel='apple-touch-icon']") as HTMLLinkElement;
      if (appleLink) {
        appleLink.href = appSettings.logo;
      } else {
        const newAppleLink = document.createElement('link');
        newAppleLink.rel = 'apple-touch-icon';
        newAppleLink.href = appSettings.logo;
        document.head.appendChild(newAppleLink);
      }
    }
  }, [appSettings]);

  // Handlers
  const handleSaveCompany = (c: Company) => {
    const updated = companies.some(x => x.id === c.id) ? companies.map(x => x.id === c.id ? c : x) : [...companies, c];
    setCompanies(updated); StorageService.saveCompanies(updated);
  };
  const handleDeleteCompany = (id: string) => {
    if (confirm('Apagar empresa?')) {
        const updated = companies.filter(c => c.id !== id);
        setCompanies(updated); StorageService.saveCompanies(updated);
    }
  };
  const handleAddTransaction = (t: Transaction) => {
    const updated = [...transactions, t];
    setTransactions(updated); StorageService.saveTransactions(updated);
  };
  const handleDeleteTransaction = (id: string) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated); StorageService.saveTransactions(updated);
  };
  const handleSaveNote = (n: MonthlyNote) => {
    const updated = [...notes.filter(x => !(x.companyId === n.companyId && x.monthStr === n.monthStr)), n];
    setNotes(updated); StorageService.saveNotes(updated);
  };
  const handleSaveDocument = (d: FinancialDocument) => {
    const updated = documents.some(x => x.id === d.id) ? documents.map(x => x.id === d.id ? d : x) : [...documents, d];
    setDocuments(updated); StorageService.saveDocuments(updated);
  };
  const handleDeleteDocument = (id: string) => {
     if(confirm("Apagar documento?")) {
        const updated = documents.filter(d => d.id !== id);
        setDocuments(updated); StorageService.saveDocuments(updated);
     }
  };
  const handleUpdateSettings = (s: AppSettings) => { 
    setAppSettings(s); 
    StorageService.saveSettings(s); 
  };
  const handleAddCategory = (name: string, type: TransactionType) => {
     if (categories.some(c => c.name.toLowerCase() === name.toLowerCase() && c.type === type)) return;
     const updated = [...categories, { id: Math.random().toString(36).substr(2, 9), name, type }];
     setCategories(updated); StorageService.saveCategories(updated);
  };
  const handleEditCategory = (id: string, newName: string) => {
    const updated = categories.map(c => c.id === id ? { ...c, name: newName } : c);
    setCategories(updated); StorageService.saveCategories(updated);
  };
  const handleDeleteCategory = (id: string) => {
      const updated = categories.filter(c => c.id !== id);
      setCategories(updated); StorageService.saveCategories(updated);
  };

  const handleInstallApp = () => {
    if (installPrompt) {
      installPrompt.prompt();
      installPrompt.userChoice.then((choiceResult: any) => {
        if (choiceResult.outcome === 'accepted') {
          console.log('User accepted the install prompt');
        }
        setInstallPrompt(null);
      });
    }
  };

  // --- Components ---

  const DesktopSidebarItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => (
    <button
      onClick={() => setCurrentView(view)}
      className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 group ${
        currentView === view 
          ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/30' 
          : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
      }`}
    >
      <Icon size={20} className={currentView === view ? 'animate-pulse' : 'group-hover:scale-110 transition-transform'} />
      <span className="font-semibold">{label}</span>
      {currentView === view && <ChevronRight size={16} className="ml-auto opacity-50" />}
    </button>
  );

  const MobileTabItem = ({ view, icon: Icon, label }: { view: ViewState | 'more', icon: any, label: string }) => {
    const isActive = currentView === view || (view === 'more' && showMobileMenu);
    return (
      <button 
        onClick={() => {
            if (view === 'more') setShowMobileMenu(true);
            else { setCurrentView(view as ViewState); setShowMobileMenu(false); }
        }}
        className={`flex flex-col items-center justify-center w-full h-full gap-1 ${
           isActive ? 'text-brand-600 dark:text-brand-400' : 'text-slate-400 dark:text-slate-500'
        }`}
      >
        <div className={`p-1.5 rounded-xl transition-all ${isActive ? 'bg-brand-50 dark:bg-brand-900/20' : ''}`}>
           <Icon size={22} strokeWidth={isActive ? 2.5 : 2} />
        </div>
        <span className="text-[10px] font-semibold">{label}</span>
      </button>
    )
  };

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-white overflow-hidden selection:bg-brand-500 selection:text-white">

      {/* DESKTOP SIDEBAR */}
      <aside className="hidden lg:flex flex-col w-72 h-full bg-white dark:bg-slate-900 border-r border-slate-100 dark:border-slate-800/50 relative z-20">
        <div className="p-8 flex items-center gap-3">
          {appSettings.logo ? (
             <img src={appSettings.logo} alt="Logo" className="w-10 h-10 rounded-xl object-cover shadow-lg" />
          ) : (
             <div className="w-10 h-10 bg-gradient-to-br from-brand-500 to-brand-700 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-brand-500/30">
                {appSettings.appName.charAt(0)}
             </div>
          )}
          <h1 className="text-lg font-bold tracking-tight text-slate-900 dark:text-white leading-tight">
            {appSettings.appName}
          </h1>
        </div>

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto custom-scrollbar">
          <p className="px-4 text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 mt-2">Principal</p>
          <DesktopSidebarItem view="daily" icon={Home} label="Início" />
          <DesktopSidebarItem view="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <DesktopSidebarItem view="simulator" icon={BatteryCharging} label="Simulador" />

          <p className="px-4 text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 mt-6">Gestão</p>
          <DesktopSidebarItem view="invoices" icon={FileText} label="Orçamentos" />
          <DesktopSidebarItem view="month-detail" icon={Calendar} label="Lançamentos" />
