  { id: '2', name: 'Serviços de Limpeza', type: TransactionType.INCOME },
  { id: '3', name: 'Impermeabilização', type: TransactionType.INCOME },
  { id: '4', name: 'Produtos Químicos', type: TransactionType.EXPENSE },
  { id: '5', name: 'Equipamentos', type: TransactionType.EXPENSE },
  { id: '6', name: 'Marketing', type: TransactionType.EXPENSE },
  { id: '7', name: 'Transporte', type: TransactionType.EXPENSE },
];

// Logo ESTOFLOW (Nova identidade)
const DEFAULT_LOGO = "https://i.supaimg.com/f9eaf628-913f-4c44-b9ef-e14c3a89a6ca.jpg";
// Previous Logos for migration checks
const PREVIOUS_LOGO_1 = "https://i.postimg.cc/8PmMGtkZ/1767271472374.png";
const PREVIOUS_LOGO_2 = "https://cdn-icons-png.flaticon.com/512/2534/2534182.png"; // Old icon

const DEFAULT_SETTINGS: AppSettings = {
  appName: 'ESTOFLOW',
  logo: DEFAULT_LOGO
};

export const StorageService = {
  getCompanies: (): Company[] => {
    const data = localStorage.getItem(KEYS.COMPANIES);
    return data ? JSON.parse(data) : MOCK_COMPANIES;
  },

  saveCompanies: (companies: Company[]) => {
    localStorage.setItem(KEYS.COMPANIES, JSON.stringify(companies));
  },

  getTransactions: (): Transaction[] => {
    const data = localStorage.getItem(KEYS.TRANSACTIONS);
    return data ? JSON.parse(data) : MOCK_TRANSACTIONS;
  },

  saveTransactions: (transactions: Transaction[]) => {
    localStorage.setItem(KEYS.TRANSACTIONS, JSON.stringify(transactions));
  },

  getNotes: (): MonthlyNote[] => {
    const data = localStorage.getItem(KEYS.NOTES);
    return data ? JSON.parse(data) : [];
  },

  saveNotes: (notes: MonthlyNote[]) => {
    localStorage.setItem(KEYS.NOTES, JSON.stringify(notes));
  },

  getRates: (): ExchangeRates => {
    const data = localStorage.getItem(KEYS.RATES);
    return data ? JSON.parse(data) : INITIAL_RATES;
  },

  saveRates: (rates: ExchangeRates) => {
    localStorage.setItem(KEYS.RATES, JSON.stringify(rates));
  },

  getCategories: (): CategoryItem[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    return data ? JSON.parse(data) : DEFAULT_CATEGORIES;
  },

  saveCategories: (categories: CategoryItem[]) => {
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(categories));
  },

  getDocuments: (): FinancialDocument[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    return data ? JSON.parse(data) : [];
  },

  saveDocuments: (docs: FinancialDocument[]) => {
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
  },

  getServiceOrders: (): ServiceOrder[] => {
    const data = localStorage.getItem(KEYS.SERVICE_ORDERS);
    return data ? JSON.parse(data) : [];
  },

  saveServiceOrders: (orders: ServiceOrder[]) => {
    localStorage.setItem(KEYS.SERVICE_ORDERS, JSON.stringify(orders));
  },

  getSettings: (): AppSettings => {
    const data = localStorage.getItem(KEYS.SETTINGS);
    if (data) {
        const parsed = JSON.parse(data);
        // FORCE MIGRATION LOGIC
        const isOldName = !parsed.appName || parsed.appName === "Na Rota do Lucro" || parsed.appName === "RotaDoLucro";
        // Verifica se a logo é alguma das antigas ou SVG genérico
        const isOldLogo = parsed.logo && (
            parsed.logo.startsWith('data:image/svg') || 
            parsed.logo === PREVIOUS_LOGO_1 || 
            parsed.logo === PREVIOUS_LOGO_2
        );

        if (isOldName || isOldLogo) {
            const updated = { 
                ...parsed, 
                appName: isOldName ? 'ESTOFLOW' : parsed.appName, 
                logo: isOldLogo ? DEFAULT_LOGO : (parsed.logo || DEFAULT_LOGO)
            };
            localStorage.setItem(KEYS.SETTINGS, JSON.stringify(updated));
            return updated;
        }
        return parsed;
    }
    return DEFAULT_SETTINGS;
  },

  saveSettings: (settings: AppSettings) => {
    localStorage.setItem(KEYS.SETTINGS, JSON.stringify(settings));
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Company, ServiceOrder, ServiceStatus, ChecklistItem, ServicePhoto, Currency, AppSettings } from '../types';
import { DEFAULT_CHECKLIST } from '../constants';
import { Plus, Calendar, MapPin, Camera, ClipboardCheck, CheckSquare, Square, Trash2, ChevronLeft, Save, Clock, Phone, Navigation, Share2, MessageCircle } from 'lucide-react';
import { StorageService } from '../services/storageService';

interface ServiceOrdersProps {
  companies: Company[];
  appSettings: AppSettings;
}

export const ServiceOrders: React.FC<ServiceOrdersProps> = ({ companies, appSettings }) => {
  const [orders, setOrders] = useState<ServiceOrder[]>(StorageService.getServiceOrders());
  const [view, setView] = useState<'list' | 'create' | 'detail'>('list');
  const [selectedOrder, setSelectedOrder] = useState<ServiceOrder | null>(null);

  // Form State
  const [formOrder, setFormOrder] = useState<Partial<ServiceOrder>>({});
  const photoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
     // Carregar ordens ao iniciar
     setOrders(StorageService.getServiceOrders());
  }, []);

  const saveOrders = (newOrders: ServiceOrder[]) => {
    setOrders(newOrders);
    StorageService.saveServiceOrders(newOrders);
  };

  const handleCreateNew = () => {
    setFormOrder({
      id: Math.random().toString(36).substr(2, 9),
      status: ServiceStatus.SCHEDULED,
      checklist: DEFAULT_CHECKLIST.map(i => ({...i})),
      photos: [],
      scheduledDate: new Date().toISOString().split('T')[0],
      scheduledTime: '09:00',
      companyId: companies[0]?.id || '',
      price: 0,
      clientName: '',
      clientAddress: '',
      clientPhone: '',
      items: '',
      notes: ''
    });
    setView('create');
  };

  const handleSave = () => {
    if(!formOrder.clientName || !formOrder.scheduledDate) {
      alert("Preencha o nome do cliente e a data.");
      return;
    }

    const newOrder = formOrder as ServiceOrder;
    newOrder.createdAt = newOrder.createdAt || Date.now();

    const updatedOrders = selectedOrder 
      ? orders.map(o => o.id === newOrder.id ? newOrder : o)
      : [...orders, newOrder];

    saveOrders(updatedOrders);
    setView('list');
    setSelectedOrder(null);
  };

  const handleViewDetail = (order: ServiceOrder) => {
    setSelectedOrder(order);
    setFormOrder({...order});
    setView('detail');
  };

  const handleDelete = (id: string) => {
    if(confirm("Tem certeza que deseja apagar esta O.S.?")) {
      const updated = orders.filter(o => o.id !== id);
      saveOrders(updated);
      setView('list');
    }
  };

  // --- CHECKLIST LOGIC ---
  const toggleChecklist = (itemId: string) => {
    if(!formOrder.checklist) return;
    const updated = formOrder.checklist.map(i => 
      i.id === itemId ? { ...i, checked: !i.checked } : i
    );
    setFormOrder({ ...formOrder, checklist: updated });
  };

  // --- PHOTO LOGIC ---
  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'BEFORE' | 'AFTER') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          // Resize image to max 800px to save storage
          const canvas = document.createElement('canvas');
          let width = img.width;
          let height = img.height;
          const MAX_SIZE = 800;

          if (width > height) {
            if (width > MAX_SIZE) {
              height *= MAX_SIZE / width;
              width = MAX_SIZE;
            }
          } else {
            if (height > MAX_SIZE) {
              width *= MAX_SIZE / height;
              height = MAX_SIZE;
            }
          }
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(img, 0, 0, width, height);
          const dataUrl = canvas.toDataURL('image/jpeg', 0.6); // Compress to 60% quality

          const newPhoto: ServicePhoto = {
            id: Math.random().toString(36).substr(2, 9),
            type,
            url: dataUrl,
            timestamp: Date.now()
          };

          setFormOrder(prev => ({
            ...prev,
            photos: [...(prev.photos || []), newPhoto]
          }));
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  const removePhoto = (photoId: string) => {
    if(confirm("Apagar foto?")) {
      setFormOrder(prev => ({
        ...prev,
        photos: (prev.photos || []).filter(p => p.id !== photoId)
      }));
    }
  };

  const openWhatsApp = (order: ServiceOrder) => {
    if(!order.clientPhone) return;
    let phone = order.clientPhone.replace(/[^0-9]/g, '');
    if (phone.length === 9 && phone.startsWith('9')) phone = '244' + phone;

    const text = `Olá *${order.clientName}*! 
Aqui é da *${appSettings.appName}*.
Sobre o agendamento do dia *${new Date(order.scheduledDate).toLocaleDateString()}* às *${order.scheduledTime}*.
Podemos confirmar?`;

    window.open(`https://wa.me/${phone}?text=${encodeURIComponent(text)}`, '_blank');
  };

  const openMaps = (address: string) => {
    window.open(`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}`, '_blank');
  };

  // --- RENDER ---

  if (view === 'list') {
    return (
      <div className="space-y-6 animate-fade-in pb-20">
        <div className="flex justify-between items-center bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
          <div>
            <h2 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
              <ClipboardCheck className="text-brand-500" /> Ordens de Serviço
            </h2>
            <p className="text-sm text-slate-500 dark:text-slate-400">Gerencie agenda, vistorias e fotos.</p>
          </div>
          <button onClick={handleCreateNew} className="bg-brand-600 hover:bg-brand-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 shadow-lg">
            <Plus size={18} /> Nova O.S.
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {orders.sort((a,b) => new Date(b.scheduledDate).getTime() - new Date(a.scheduledDate).getTime()).map(order => (
            <div key={order.id} onClick={() => handleViewDetail(order)} className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-all cursor-pointer group">
              <div className="flex justify-between items-start mb-3">
                 <div>
                    <h3 className="font-bold text-slate-900 dark:text-white text-lg">{order.clientName}</h3>
                    <p className="text-xs text-slate-500 dark:text-slate-400 flex items-center gap-1">
                      <Calendar size={12} /> {new Date(order.scheduledDate).toLocaleDateString()} às {order.scheduledTime}
                    </p>
                 </div>
                 <span className={`px-2 py-1 rounded-md text-xs font-bold uppercase ${
                   order.status === ServiceStatus.COMPLETED ? 'bg-emerald-100 text-emerald-700' :
                   order.status === ServiceStatus.SCHEDULED ? 'bg-blue-100 text-blue-700' :
                   order.status === ServiceStatus.IN_PROGRESS ? 'bg-amber-100 text-amber-700' : 'bg-gray-100 text-gray-700'
                 }`}>
                   {order.status}
                 </span>
              </div>

              <div className="flex items-center gap-2 mb-3 bg-slate-50 dark:bg-slate-900/50 p-2 rounded-lg text-sm text-slate-700 dark:text-slate-300">
                <CheckSquare size={16} className="text-brand-500" />
                <span className="truncate">{order.items || 'Sem descrição'}</span>
              </div>

              <div className="flex justify-between items-center mt-4 border-t border-slate-100 dark:border-slate-700 pt-3">
                 <div className="flex items-center gap-2">
                    {order.photos && order.photos.length > 0 && (
                      <span className="flex items-center gap-1 text-xs text-slate-500 bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded">
                        <Camera size={12} /> {order.photos.length}
                      </span>
                    )}
                 </div>
                 <button className="text-brand-600 font-medium text-sm hover:underline flex items-center gap-1">
                    Abrir Detalhes <ChevronLeft size={16} className="rotate-180" />
                 </button>
              </div>
            </div>
          ))}

          {orders.length === 0 && (
            <div className="col-span-full py-12 text-center text-slate-400 border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-xl">
               <ClipboardCheck className="mx-auto w-12 h-12 mb-3 opacity-50" />
               <p>Nenhuma O.S. registrada.</p>
            </div>
          )}
        </div>
      </div>
    );
  }

  // --- DETAIL / CREATE VIEW ---
  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-20">

      {/* Header with Actions */}
      <div className="flex items-center justify-between bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 sticky top-0 z-20">
         <div className="flex items-center gap-2">
           <button onClick={() => setView('list')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full">
             <ChevronLeft size={24} className="text-slate-600 dark:text-slate-300" />
           </button>
           <h2 className="text-lg font-bold text-slate-900 dark:text-white">
             {view === 'create' ? 'Nova Ordem de Serviço' : `O.S. de ${formOrder.clientName}`}
           </h2>
         </div>
         <div className="flex gap-2">
            {view === 'detail' && (
              <button onClick={() => handleDelete(formOrder.id!)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg">
                <Trash2 size={20} />
              </button>
            )}
            <button onClick={handleSave} className="bg-brand-600 hover:bg-brand-700 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 shadow-lg">
              <Save size={18} /> Salvar
            </button>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

         {/* LEFT COLUMN: INFO */}
         <div className="lg:col-span-2 space-y-6">

            {/* Client Info Card */}
            <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
               <h3 className="text-sm font-bold text-slate-500 uppercase mb-4 flex items-center gap-2">
                 <ClipboardCheck size={16} /> Dados do Serviço
               </h3>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1">Cliente *</label>
                    <input 
                      value={formOrder.clientName} 
                      onChange={e => setFormOrder({...formOrder, clientName: e.target.value})}
                      className="w-full p-2.5 rounded-lg border bg-slate-50 dark:bg-slate-900 dark:border-slate-700 dark:text-white"
                      placeholder="Nome do Cliente"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1">Telefone (WhatsApp)</label>
                    <div className="flex gap-2">
                      <input 
                        value={formOrder.clientPhone} 
                        onChange={e => setFormOrder({...formOrder, clientPhone: e.target.value})}
                        className="w-full p-2.5 rounded-lg border bg-slate-50 dark:bg-slate-900 dark:border-slate-700 dark:text-white"
                        placeholder="923..."
                      />
                      {view === 'detail' && formOrder.clientPhone && (
                        <button onClick={() => openWhatsApp(formOrder as ServiceOrder)} className="p-2.5 bg-emerald-100 text-emerald-600 rounded-lg">
                          <MessageCircle size={20} />
                        </button>
                      )}
                    </div>
                  </div>
               </div>

               <div className="mb-4">
                  <label className="block text-xs font-bold text-slate-500 mb-1">Endereço</label>
                  <div className="flex gap-2">
                    <input 
                      value={formOrder.clientAddress} 
                      onChange={e => setFormOrder({...formOrder, clientAddress: e.target.value})}
                      className="w-full p-2.5 rounded-lg border bg-slate-50 dark:bg-slate-900 dark:border-slate-700 dark:text-white"
                      placeholder="Rua, Bairro, Ponto de Referência"
                    />
                    {view === 'detail' && formOrder.clientAddress && (
                      <button onClick={() => openMaps(formOrder.clientAddress!)} className="p-2.5 bg-blue-100 text-blue-600 rounded-lg">
                        <Navigation size={20} />
                      </button>
                    )}
                  </div>
               </div>

               <div className="grid grid-cols-2 gap-4 mb-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1">Data</label>
                    <input 
                      type="date"
                      value={formOrder.scheduledDate} 
                      onChange={e => setFormOrder({...formOrder, scheduledDate: e.target.value})}
                      className="w-full p-2.5 rounded-lg border bg-slate-50 dark:bg-slate-900 dark:border-slate-700 dark:text-white"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1">Hora</label>
                    <input 
                      type="time"
                      value={formOrder.scheduledTime} 
                      onChange={e => setFormOrder({...formOrder, scheduledTime: e.target.value})}
                      className="w-full p-2.5 rounded-lg border bg-slate-50 dark:bg-slate-900 dark:border-slate-700 dark:text-white"
                    />
                  </div>
               </div>

               <div>
                 <label className="block text-xs font-bold text-slate-500 mb-1">Itens a Higienizar</label>
                 <textarea 
                   value={formOrder.items} 
                   onChange={e => setFormOrder({...formOrder, items: e.target.value})}
                   className="w-full p-2.5 rounded-lg border bg-slate-50 dark:bg-slate-900 dark:border-slate-700 dark:text-white h-20"
                   placeholder="Ex: 1 Sofá 3 Lugares, 2 Cadeiras de Jantar..."
                 />
               </div>
            </div>

            {/* Checklist Card */}
            <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
               <h3 className="text-sm font-bold text-slate-500 uppercase mb-4 flex items-center gap-2">
                 <CheckSquare size={16} /> Vistoria Prévia (Checklist)
               </h3>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {formOrder.checklist?.map(item => (
                    <button 
                      key={item.id}
                      onClick={() => toggleChecklist(item.id)}
                      className={`flex items-center gap-3 p-3 rounded-lg border transition-all text-left ${
                        item.checked 
                        ? 'bg-rose-50 border-rose-200 dark:bg-rose-900/20 dark:border-rose-800' 
                        : 'bg-slate-50 border-slate-100 dark:bg-slate-900 dark:border-slate-700'
                      }`}
                    >
                      <div className={`shrink-0 ${item.checked ? 'text-rose-500' : 'text-slate-300'}`}>
                        {item.checked ? <CheckSquare size={20} /> : <Square size={20} />}
                      </div>
                      <span className={`text-sm font-medium ${item.checked ? 'text-rose-700 dark:text-rose-300' : 'text-slate-600 dark:text-slate-400'}`}>
                        {item.label}
                      </span>
                    </button>
                  ))}
               </div>
               <div className="mt-4">
                  <label className="block text-xs font-bold text-slate-500 mb-1">Observações Técnicas</label>
                  <textarea 
                     value={formOrder.notes}
                     onChange={e => setFormOrder({...formOrder, notes: e.target.value})}
                     className="w-full p-2.5 rounded-lg border bg-slate-50 dark:bg-slate-900 dark:border-slate-700 dark:text-white text-sm h-16"
                     placeholder="Ex: Cliente avisado sobre mancha que pode não sair..."
                  />
               </div>
            </div>

         </div>

         {/* RIGHT COLUMN: STATUS & PHOTOS */}
         <div className="space-y-6">

            {/* Status & Price */}
            <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
               <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Status</label>
               <div className="grid grid-cols-2 gap-2 mb-6">
                 {Object.values(ServiceStatus).map(s => (
                   <button 
                     key={s}
                     onClick={() => setFormOrder({...formOrder, status: s})}
                     className={`px-2 py-2 rounded-lg text-xs font-bold border transition-colors ${
                       formOrder.status === s 
                       ? 'bg-brand-100 border-brand-300 text-brand-700 dark:bg-brand-900 dark:border-brand-700 dark:text-white' 
                       : 'bg-white border-slate-200 text-slate-500 dark:bg-slate-900 dark:border-slate-700 dark:text-slate-400'
                     }`}
                   >
                     {s}
                   </button>
                 ))}
               </div>

               <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Valor Total (Kz)</label>
               <input 
                 type="number"
                 value={formOrder.price}
                 onChange={e => setFormOrder({...formOrder, price: parseFloat(e.target.value)})}
                 className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-2xl font-bold text-emerald-600 dark:text-emerald-400"
               />
            </div>

            {/* Photos */}
            <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
               <h3 className="text-sm font-bold text-slate-500 uppercase mb-4 flex items-center gap-2">
                 <Camera size={16} /> Registro Fotográfico
               </h3>

               {/* Before */}
               <div className="mb-6">
                 <div className="flex justify-between items-center mb-2">
                    <span className="text-xs font-bold text-slate-400 uppercase">Antes</span>
                    <label className="cursor-pointer text-xs bg-brand-50 text-brand-600 px-2 py-1 rounded flex items-center gap-1 hover:bg-brand-100">
                       <Plus size={12} /> Add Foto
                       <input type="file" accept="image/*" className="hidden" onChange={(e) => handlePhotoUpload(e, 'BEFORE')} />
                    </label>
                 </div>
                 <div className="grid grid-cols-3 gap-2">
                    {formOrder.photos?.filter(p => p.type === 'BEFORE').map(photo => (
                      <div key={photo.id} className="relative aspect-square rounded-lg overflow-hidden bg-slate-100 border dark:border-slate-700 group">
                         <img src={photo.url} className="w-full h-full object-cover" alt="Antes" />
                         <button onClick={() => removePhoto(photo.id)} className="absolute top-1 right-1 bg-black/50 text-white p-1 rounded-full opacity-0 group-hover:opacity-100">
                           <Trash2 size={12} />
                         </button>
                      </div>
                    ))}
                    {(!formOrder.photos?.some(p => p.type === 'BEFORE')) && (
                      <div className="col-span-3 py-4 text-center text-xs text-slate-400 bg-slate-50 dark:bg-slate-900/50 rounded-lg border border-dashed border-slate-200 dark:border-slate-700">
                        Sem fotos de entrada
                      </div>
                    )}
                 </div>
               </div>

               {/* After */}
               <div>
                 <div className="flex justify-between items-center mb-2">
                    <span className="text-xs font-bold text-slate-400 uppercase">Depois</span>
                    <label className="cursor-pointer text-xs bg-emerald-50 text-emerald-600 px-2 py-1 rounded flex items-center gap-1 hover:bg-emerald-100">
                       <Plus size={12} /> Add Foto
                       <input type="file" accept="image/*" className="hidden" onChange={(e) => handlePhotoUpload(e, 'AFTER')} />
                    </label>
                 </div>
                 <div className="grid grid-cols-3 gap-2">
                    {formOrder.photos?.filter(p => p.type === 'AFTER').map(photo => (
                      <div key={photo.id} className="relative aspect-square rounded-lg overflow-hidden bg-slate-100 border dark:border-slate-700 group">
                         <img src={photo.url} className="w-full h-full object-cover" alt="Depois" />
