import React, { useState, useMemo } from 'react';
import { Company, FinancialDocument, DocumentType, DocumentStatus, InvoiceItem, ExchangeRates, AppSettings } from '../types';
import { Plus, Printer, Share2, FileText, ArrowRight, Trash2, CheckCircle, X, MessageCircle, Calculator, Wallet } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface InvoicesProps {
  companies: Company[];
  documents: FinancialDocument[];
  onSave: (doc: FinancialDocument) => void;
  onDelete: (id: string) => void;
  rates: ExchangeRates;
  appSettings: AppSettings;
}

export const Invoices: React.FC<InvoicesProps> = ({ companies, documents, onSave, onDelete, rates, appSettings }) => {
  const [mode, setMode] = useState<'list' | 'create' | 'edit'>('list');
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [formData, setFormData] = useState<Partial<FinancialDocument>>({
    items: [],
    type: DocumentType.BUDGET,
    status: DocumentStatus.DRAFT,
    date: new Date().toISOString().split('T')[0]
  });

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // --- HELPER: TOTAL DO DOCUMENTO ---
  const calculateTotal = (items: InvoiceItem[] = []) => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  };

  // --- ESTATÍSTICAS DO MÊS ATUAL ---
  const monthlyStats = useMemo(() => {
    const now = new Date();
    const currentMonthPrefix = now.toISOString().slice(0, 7); // YYYY-MM

    let invoiceTotalAOA = 0;
    let budgetTotalAOA = 0;
    let invoiceCount = 0;
    let budgetCount = 0;

    documents.forEach(doc => {
      // Filtra por empresa, mês atual e ignora cancelados
      if (doc.companyId === selectedCompanyId && 
          doc.date.startsWith(currentMonthPrefix) && 
          doc.status !== DocumentStatus.CANCELLED) {

        const docTotal = calculateTotal(doc.items);

        // Conversão para AOA
        const docCurrency = selectedCompany?.currency || 'USD';
        const rateToUSD = rates[docCurrency] || 1;
        const rateUSDToAOA = rates['AOA'] || 900;

        // Valor em USD -> Valor em AOA
        const valAOA = (docTotal / rateToUSD) * rateUSDToAOA;

        if (doc.type === DocumentType.INVOICE) {
          invoiceTotalAOA += valAOA;
          invoiceCount++;
        } else {
          budgetTotalAOA += valAOA;
          budgetCount++;
        }
      }
    });

    return { invoiceTotalAOA, budgetTotalAOA, invoiceCount, budgetCount };
  }, [documents, selectedCompanyId, rates, selectedCompany]);

  // --- FILTROS & LISTAGEM ---
  const filteredDocs = useMemo(() => {
    return documents.filter(d => d.companyId === selectedCompanyId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [documents, selectedCompanyId]);

  // --- LÓGICA DE FORMULÁRIO ---
  const handleNewDoc = () => {
    if (!selectedCompany) {
      alert("Selecione uma empresa primeiro.");
      return;
    }

    // Auto number logic: Count docs of this type for this company
    const count = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.BUDGET).length;
    const nextNum = count + 1;
    const year = new Date().getFullYear();

    setFormData({
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: DocumentType.BUDGET,
      status: DocumentStatus.DRAFT,
      number: `ORC-${nextNum.toString().padStart(3, '0')}/${year}`,
      date: new Date().toISOString().split('T')[0],
      items: [{ id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }],
      clientName: '',
      clientPhone: '',
      clientTaxID: '',
      notes: 'Este orçamento é válido por 15 dias.'
    });
    setMode('create');
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...(prev.items || []), { id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (itemId: string) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).filter(i => i.id !== itemId)
    }));
  };

  const handleItemChange = (itemId: string, field: keyof InvoiceItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).map(i => i.id === itemId ? { ...i, [field]: value } : i)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.clientName && formData.items && formData.items.length > 0) {
      onSave(formData as FinancialDocument);
      setMode('list');
    } else {
      alert("Preencha o nome do cliente e adicione pelo menos um item.");
    }
  };

  // --- LÓGICA DE AÇÕES ---

  const handleConvertToInvoice = (doc: FinancialDocument) => {
    if (confirm(`Converter orçamento ${doc.number} em Fatura Definitiva?`)) {
       // 1. Marcar orçamento como Aprovado
       onSave({ ...doc, status: DocumentStatus.APPROVED });

       // 2. Criar nova Fatura baseada no orçamento
       const countInv = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.INVOICE).length;
       const nextNum = countInv + 1;
       const year = new Date().getFullYear();

       const newInvoice: FinancialDocument = {
         ...doc,
         id: Math.random().toString(36).substr(2, 9),
         type: DocumentType.INVOICE,
         status: DocumentStatus.SENT,
         number: `FAT-${nextNum.toString().padStart(3, '0')}/${year}`,
         date: new Date().toISOString().split('T')[0],
         notes: 'Obrigado pela preferência.',
         createdAt: Date.now()
       };
       onSave(newInvoice);
       alert(`Fatura ${newInvoice.number} gerada com sucesso!`);
    }
  };

  const handlePDF = (doc: FinancialDocument) => {
    if (!selectedCompany) return;

    const pdf = new jsPDF();
    const pageWidth = pdf.internal.pageSize.width;
    const pageHeight = pdf.internal.pageSize.height;
    const currency = selectedCompany.currency;

    // --- PALETA DE CORES (PROFISSIONAL) ---
    const primaryColor = [15, 76, 117]; // Brand Petrol Blue (from logo)
    const accentColor = doc.type === DocumentType.INVOICE ? [16, 185, 129] : [14, 165, 233]; // Green or Blue
    const textDark = [30, 41, 59];
    const textLight = [100, 116, 139];

    // --- CABEÇALHO ---
    // Aumentar a altura do cabeçalho para acomodar as informações verticais
    const headerHeight = 65; 

    // 1. Barra de Topo
    pdf.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.rect(0, 0, pageWidth, headerHeight, 'F');

    // 2. Logo (Esquerda)
    let hasLogo = false;
    // Posição Y da logo ajustada para centralizar verticalmente no novo headerHeight ou ficar no topo
    const logoY = 10;
    if (appSettings.logo) {
       try {
         pdf.addImage(appSettings.logo, 'PNG', 14, logoY, 24, 24);
         hasLogo = true;
       } catch (e) {
         console.error("Error adding logo", e);
       }
    }

    // 3. Nome da Empresa (Esquerda, ao lado do logo)
    const textStartX = hasLogo ? 45 : 14;
    let currentY = 20;

    pdf.setTextColor(255, 255, 255);
    pdf.setFontSize(18);
    pdf.setFont("helvetica", "bold");
    pdf.text(appSettings.appName, textStartX, currentY);

    // Subtítulo da empresa
    if (appSettings.companySubtitle) {
        currentY += 6;
        pdf.setFontSize(10);
        pdf.setFont("helvetica", "normal");
        pdf.text(appSettings.companySubtitle, textStartX, currentY);
    }

    // Contactos da Empresa no Cabeçalho (Vertical List)
    currentY += 10; // Espaço antes dos contatos
    const lineHeight = 5;

    pdf.setFontSize(9);
    pdf.setTextColor(200, 200, 200); // Cinza claro para contraste no azul

    if(appSettings.phone) {
        pdf.text(`Contacto: ${appSettings.phone}`, textStartX, currentY);
        currentY += lineHeight;
    }
    if(appSettings.email) {
        pdf.text(`Email: ${appSettings.email}`, textStartX, currentY);
        currentY += lineHeight;
    }
    if(appSettings.province) {
        pdf.text(`Província: ${appSettings.province}`, textStartX, currentY);
        currentY += lineHeight;
    }
    if(appSettings.neighborhood) {
        pdf.text(`Bairro: ${appSettings.neighborhood}`, textStartX, currentY);
    }

    // 4. Título do Documento (Direita, Topo)
    pdf.setFontSize(24);
    pdf.setFont("helvetica", "bold");
    pdf.setTextColor(255, 255, 255);
    pdf.text(doc.type.toUpperCase(), pageWidth - 14, 25, { align: 'right' });

    // --- INFORMAÇÕES DO DOCUMENTO E CLIENTE ---
    const topMargin = headerHeight + 15;

    // Bloco Esquerdo: Cliente
    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "bold");
    pdf.text("CLIENTE:", 14, topMargin);

    pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
    pdf.setFontSize(12);
    pdf.text(doc.clientName, 14, topMargin + 6);

    pdf.setFontSize(10);
    pdf.setFont("helvetica", "normal");
    pdf.setTextColor(textLight[0], textLight[1], textLight[2]);
    if (doc.clientPhone) pdf.text(`Tel: ${doc.clientPhone}`, 14, topMargin + 12);
    if (doc.clientTaxID) pdf.text(`NIF: ${doc.clientTaxID}`, 14, topMargin + 17);

    // Bloco Direito: Detalhes do Doc
    const colRight = pageWidth - 60;

    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "bold");
    pdf.text("DETALHES:", colRight, topMargin);

    pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
    pdf.setFontSize(10);

    // Numero
    pdf.setFont("helvetica", "bold");
    pdf.text("Nº Doc:", colRight, topMargin + 6);
    pdf.setFont("helvetica", "normal");
    pdf.text(doc.number, pageWidth - 14, topMargin + 6, { align: 'right' });

    // Data
    pdf.setFont("helvetica", "bold");
    pdf.text("Data:", colRight, topMargin + 12);
    pdf.setFont("helvetica", "normal");
    pdf.text(new Date(doc.date).toLocaleDateString(), pageWidth - 14, topMargin + 12, { align: 'right' });

    // Vencimento (se houver)
    if (doc.dueDate) {
        pdf.setFont("helvetica", "bold");
        pdf.text("Vencimento:", colRight, topMargin + 18);
        pdf.setFont("helvetica", "normal");
        pdf.text(new Date(doc.dueDate).toLocaleDateString(), pageWidth - 14, topMargin + 18, { align: 'right' });
    }

    // Status
    pdf.setFont("helvetica", "bold");
    pdf.text("Status:", colRight, topMargin + (doc.dueDate ? 24 : 18));
    pdf.setTextColor(accentColor[0], accentColor[1], accentColor[2]);
    pdf.text(doc.status.toUpperCase(), pageWidth - 14, topMargin + (doc.dueDate ? 24 : 18), { align: 'right' });


    // --- TABELA DE ITENS ---
    const tableRows = doc.items.map(item => [
      item.description,
      item.quantity,
      `${item.unitPrice.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`,
      `${(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`
    ]);

    autoTable(pdf, {
      startY: topMargin + 35,
      head: [['DESCRIÇÃO', 'QTD', `PREÇO UNIT (${currency})`, `TOTAL (${currency})`]],
      body: tableRows,
      theme: 'grid',
      styles: {
          font: 'helvetica',
          fontSize: 9,
          textColor: textDark,
          lineColor: [230, 230, 230],
          lineWidth: 0.1,
          cellPadding: 4,
      },
      headStyles: {
          fillColor: primaryColor,
          textColor: [255, 255, 255],
          fontStyle: 'bold',
          lineWidth: 0,
      },
      columnStyles: {
        0: { cellWidth: 'auto' }, 
        1: { halign: 'center', cellWidth: 20 },
        2: { halign: 'right', cellWidth: 40 },
        3: { halign: 'right', cellWidth: 40, fontStyle: 'bold' }
      },
      alternateRowStyles: {
          fillColor: [248, 250, 252] // Slate 50
      }
    });

    // --- TOTAIS ---
    // @ts-ignore
    const finalY = pdf.lastAutoTable.finalY + 10;
    const total = calculateTotal(doc.items);

    // Caixa de Totais
    const boxWidth = 90;
    const boxX = pageWidth - boxWidth - 14;

    pdf.setDrawColor(200, 200, 200);
    pdf.line(boxX, finalY, pageWidth - 14, finalY);

    pdf.setFontSize(12);
    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFont("helvetica", "bold");
    pdf.text("TOTAL A PAGAR:", boxX, finalY + 8);
    pdf.text(`${currency} ${total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`, pageWidth - 14, finalY + 8, { align: 'right' });

    // --- RODAPÉ / NOTAS ---
    const footerY = Math.max(finalY + 25, pageHeight - 40);

    // Notas
    if (doc.notes) {
      pdf.setFontSize(9);
      pdf.setFont("helvetica", "bold");
      pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
      pdf.text("Notas / Termos:", 14, footerY);

      pdf.setFontSize(8);
      pdf.setFont("helvetica", "normal");
      pdf.setTextColor(textLight[0], textLight[1], textLight[2]);
      const splitNotes = pdf.splitTextToSize(doc.notes, pageWidth - 28);
      pdf.text(splitNotes, 14, footerY + 5);
    }

    // Info Simples no Rodapé (Já que temos detalhado no topo)
    pdf.setDrawColor(200, 200, 200);
    pdf.line(14, pageHeight - 15, pageWidth - 14, pageHeight - 15);

    pdf.setFontSize(7);
    pdf.setTextColor(150, 150, 150);
    pdf.text(`${appSettings.appName} - Documento gerado digitalmente.`, pageWidth / 2, pageHeight - 8, { align: 'center' });

    pdf.save(`${doc.type}_${doc.clientName.replace(/\s/g, '_')}_${doc.number}.pdf`);
  };

  const handleWhatsApp = (doc: FinancialDocument) => {
    if (!doc.clientPhone) {
      alert("Por favor, adicione o telefone do cliente no documento.");
      return;
    }

    const companyName = appSettings.appName || 'Nossa Empresa';
    const total = calculateTotal(doc.items);
    const currency = selectedCompany?.currency || 'AOA';
    const formattedTotal = total.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

    // Mensagem Limpa (Sem instruções técnicas)
    const text = `Olá *${doc.clientName}*,

Aqui está o seu *${doc.type} ${doc.number}* da *${companyName}*.

💰 Valor Total: *${currency} ${formattedTotal}*

Qualquer dúvida, estamos à disposição!`;

    // 1. Baixar o PDF Automaticamente
    handlePDF(doc);

    // 2. Alertar o usuário da APP (UX importante pois não dá para anexar automático na web)
    alert("📄 O PDF foi baixado para o seu dispositivo!\n\nO WhatsApp abrirá em seguida. Por favor, anexe o arquivo baixado manualmente na conversa.");

    // 3. Abrir WhatsApp após um breve delay para garantir que o download iniciou
    setTimeout(() => {
        let phone = doc.clientPhone!.replace(/[^0-9]/g, '');
        if (phone.length === 9 && phone.startsWith('9')) {
          phone = '244' + phone;
        }
        const url = `https://wa.me/${phone}?text=${encodeURIComponent(text)}`;
        window.open(url, '_blank');
    }, 1000);
  };

  // --- RENDER ---

  if (mode === 'create' || mode === 'edit') {
    return (
      <div className="max-w-4xl mx-auto animate-fade-in">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <FileText className="text-brand-500" />
            {mode === 'create' ? `Novo ${formData.type}` : `Editar ${formData.number}`}
          </h2>
          <button onClick={() => setMode('list')} className="text-slate-500 hover:text-slate-700 dark:text-slate-400">
             <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">

          {/* Header Data */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tipo de Doc</label>
               <select 
                 value={formData.type} 
                 onChange={e => setFormData({...formData, type: e.target.value as DocumentType})}
                 className="w-full p-2.5 rounded-lg border bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300"
                 disabled={mode === 'edit'}
               >
                 <option value={DocumentType.BUDGET}>{DocumentType.BUDGET}</option>
                 <option value={DocumentType.INVOICE}>{DocumentType.INVOICE}</option>
               </select>
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Número</label>
               <input 
                 type="text" 
                 value={formData.number} 
                 readOnly 
                 className="w-full p-2.5 rounded-lg border bg-slate-100 dark:bg-slate-900 text-slate-500 cursor-not-allowed border-slate-200" 
               />
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data</label>
               <input 
                 type="date" 
                 value={formData.date} 
                 onChange={e => setFormData({...formData, date: e.target.value})}
                 className="w-full p-2.5 rounded-lg border bg-white border-slate-300 text-slate-900" 
               />
             </div>
          </div>

          {/* Client Data */}
          <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg mb-6 border border-slate-200 dark:border-slate-700">
            <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-3">Dados do Cliente</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input 
                 placeholder="Nome do Cliente *" 
                 value={formData.clientName}
                 onChange={e => setFormData({...formData, clientName: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
                 required
              />
              <input 
                 placeholder="Telefone (WhatsApp) Ex: 923..." 
                 value={formData.clientPhone}
                 onChange={e => setFormData({...formData, clientPhone: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
              />
              <input 
                 placeholder="NIF (Opcional)" 
                 value={formData.clientTaxID}
                 onChange={e => setFormData({...formData, clientTaxID: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
              />
            </div>
            <p className="text-xs text-slate-500 mt-2">O telefone é usado para enviar o documento via WhatsApp.</p>
          </div>

          {/* Items */}
          <div className="mb-6">
            <div className="flex justify-between items-center mb-2">
               <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300">Itens / Serviços</h3>
            </div>
            <table className="w-full text-sm">
              <thead className="bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300">
                <tr>
                  <th className="p-2 text-left">Descrição</th>
                  <th className="p-2 w-20 text-center">Qtd</th>
                  <th className="p-2 w-32 text-right">Preço Unit</th>
                  <th className="p-2 w-32 text-right">Total</th>
                  <th className="p-2 w-10"></th>
                </tr>
              </thead>
              <tbody>
                {formData.items?.map(item => (
                  <tr key={item.id} className="border-b dark:border-slate-700 bg-white dark:bg-slate-900/50">
                    <td className="p-2">
                      <input 
                        value={item.description}
                        onChange={e => handleItemChange(item.id, 'description', e.target.value)}
                        placeholder="Ex: Consultoria"
                        className="w-full p-1 bg-transparent outline-none text-slate-900 dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="1"
                        value={item.quantity}
                        onChange={e => handleItemChange(item.id, 'quantity', parseInt(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-center text-slate-900 dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="0"
                        value={item.unitPrice}
                        onChange={e => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-right text-slate-900 dark:text-white"
                      />
                    </td>
                    <td className="p-2 text-right font-medium text-slate-900 dark:text-white">
                      {(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}
                    </td>
                    <td className="p-2 text-center">
                      <button type="button" onClick={() => handleRemoveItem(item.id)} className="text-rose-400 hover:text-rose-600"><Trash2 size={14} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button type="button" onClick={handleAddItem} className="mt-2 text-sm text-brand-600 font-medium flex items-center gap-1 hover:underline">
              <Plus size={14} /> Adicionar Item
            </button>
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start gap-6 border-t dark:border-slate-700 pt-6">
            <div className="w-full md:w-1/2">
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Notas / Termos</label>
               <textarea 
                 value={formData.notes}
                 onChange={e => setFormData({...formData, notes: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 text-sm h-24 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
               />
            </div>
            <div className="w-full md:w-1/3 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg">
               <div className="flex justify-between items-center text-lg font-bold text-slate-800 dark:text-white">
                 <span>Total ({selectedCompany?.currency})</span>
                 <span>{calculateTotal(formData.items).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</span>
               </div>
               <button type="submit" className="w-full mt-4 py-3 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg shadow-lg flex justify-center items-center gap-2">
                 <CheckCircle size={18} /> Salvar Documento
               </button>
            </div>
          </div>

        </form>
      </div>
    );
  }

  return (
    <div className="space-y-6">
       {/* Toolbar */}
       <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col md:flex-row justify-between items-center gap-4">
         <div>
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">Orçamentos & Faturas</h2>
            <p className="text-sm text-slate-500 dark:text-slate-400">Gira documentos profissionais em {selectedCompany?.currency || 'AOA'}</p>
         </div>
         <div className="flex items-center gap-3">
            <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="p-2 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
            >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <button 
              onClick={handleNewDoc}
              className="bg-brand-600 hover:bg-brand-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 shadow-md"
            >
              <Plus size={18} /> Novo Orçamento
            </button>
         </div>
       </div>

       {/* Monthly Stats Summary */}
       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-emerald-100 dark:border-emerald-900/30 shadow-sm flex items-center justify-between">
             <div>
                <p className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wide">Faturado este Mês (AOA)</p>
                <h3 className="text-2xl font-bold text-slate-800 dark:text-white mt-1">
                   Kz {monthlyStats.invoiceTotalAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </h3>
                <p className="text-xs text-slate-400 mt-1">{monthlyStats.invoiceCount} faturas emitidas</p>
             </div>
             <div className="p-3 bg-emerald-50 dark:bg-emerald-900/20 rounded-full text-emerald-600 dark:text-emerald-400">
                <Wallet size={24} />
             </div>
          </div>

          <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-blue-100 dark:border-blue-900/30 shadow-sm flex items-center justify-between">
             <div>
                <p className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wide">Orçamentos este Mês (AOA)</p>
                <h3 className="text-2xl font-bold text-slate-800 dark:text-white mt-1">
                   Kz {monthlyStats.budgetTotalAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </h3>
                <p className="text-xs text-slate-400 mt-1">{monthlyStats.budgetCount} orçamentos criados</p>
             </div>
             <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-full text-blue-600 dark:text-blue-400">
                <Calculator size={24} />
             </div>
          </div>
       </div>

       {/* List */}
       <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
         {filteredDocs.length === 0 ? (
           <div className="p-12 text-center text-slate-400">
             <FileText className="mx-auto w-12 h-12 mb-3 opacity-30" />
             <p>Nenhum documento criado para esta empresa.</p>
           </div>
         ) : (
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-500 dark:text-slate-400 text-xs uppercase">
                 <tr>
                   <th className="p-4">Número</th>
                   <th className="p-4">Cliente</th>
                   <th className="p-4">Data</th>
                   <th className="p-4 text-center">Status</th>
                   <th className="p-4 text-right">Total</th>
                   <th className="p-4 text-center">Ações</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                 {filteredDocs.map(doc => (
                   <tr key={doc.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                     <td className="p-4 font-medium text-slate-700 dark:text-slate-200 flex items-center gap-2">
                       {doc.type === DocumentType.INVOICE ? <CheckCircle size={16} className="text-emerald-500" /> : <FileText size={16} className="text-brand-500" />}
                       {doc.number}
                     </td>
                     <td className="p-4 text-slate-600 dark:text-slate-300">
                       <div className="font-medium">{doc.clientName}</div>
                       <div className="text-xs text-slate-400">{doc.clientPhone || '-'}</div>
                     </td>
                     <td className="p-4 text-sm text-slate-500 dark:text-slate-400">
                       {new Date(doc.date).toLocaleDateString()}
                     </td>
                     <td className="p-4 text-center">
                       <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                         doc.status === DocumentStatus.DRAFT ? 'bg-slate-100 text-slate-600' :
                         doc.status === DocumentStatus.SENT ? 'bg-blue-100 text-blue-600' :
                         doc.status === DocumentStatus.APPROVED ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.PAID ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.CANCELLED ? 'bg-rose-100 text-rose-600' : ''
                       }`}>
                         {doc.status}
                       </span>
                     </td>
                     <td className="p-4 text-right font-bold text-slate-700 dark:text-white">
                        {calculateTotal(doc.items).toLocaleString('pt-AO', { minimumFractionDigits: 2 })} <span className="text-xs font-normal text-slate-400">{selectedCompany?.currency}</span>
                     </td>
                     <td className="p-4">
                       <div className="flex items-center justify-center gap-2">
                         <button 
                           onClick={() => handleWhatsApp(doc)} 
                           className="p-2 bg-emerald-100 text-emerald-600 hover:bg-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-400 dark:hover:bg-emerald-900/50 rounded-lg transition-colors" 
                           title="Enviar por WhatsApp"
                         >
                           <MessageCircle size={18} />
                         </button>
                         <button onClick={() => handlePDF(doc)} className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg" title="Baixar PDF">
                           <Printer size={18} />
                         </button>
                         {doc.type === DocumentType.BUDGET && (
                           <button onClick={() => handleConvertToInvoice(doc)} className="p-2 text-brand-600 hover:bg-brand-50 dark:hover:bg-brand-900/20 rounded-lg" title="Converter em Fatura">
                             <ArrowRight size={18} />
                           </button>
                         )}
                         <button onClick={() => onDelete(doc.id)} className="p-2 text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg" title="Apagar">
                           <Trash2 size={18} />
                         </button>
                       </div>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
           </div>
         )}
       </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Company, FinancialDocument, DocumentType, DocumentStatus, InvoiceItem, ExchangeRates, AppSettings } from '../types';
import { Plus, Printer, Share2, FileText, ArrowRight, Trash2, CheckCircle, X, MessageCircle, Calculator, Wallet } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface InvoicesProps {
  companies: Company[];
  documents: FinancialDocument[];
  onSave: (doc: FinancialDocument) => void;
  onDelete: (id: string) => void;
  rates: ExchangeRates;
  appSettings: AppSettings;
}

export const Invoices: React.FC<InvoicesProps> = ({ companies, documents, onSave, onDelete, rates, appSettings }) => {
  const [mode, setMode] = useState<'list' | 'create' | 'edit'>('list');
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [formData, setFormData] = useState<Partial<FinancialDocument>>({
    items: [],
    type: DocumentType.BUDGET,
    status: DocumentStatus.DRAFT,
    date: new Date().toISOString().split('T')[0]
  });

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // --- HELPER: TOTAL DO DOCUMENTO ---
  const calculateTotal = (items: InvoiceItem[] = []) => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  };

  // --- ESTATÍSTICAS DO MÊS ATUAL ---
  const monthlyStats = useMemo(() => {
    const now = new Date();
    const currentMonthPrefix = now.toISOString().slice(0, 7); // YYYY-MM

    let invoiceTotalAOA = 0;
    let budgetTotalAOA = 0;
    let invoiceCount = 0;
    let budgetCount = 0;

    documents.forEach(doc => {
      // Filtra por empresa, mês atual e ignora cancelados
      if (doc.companyId === selectedCompanyId && 
          doc.date.startsWith(currentMonthPrefix) && 
          doc.status !== DocumentStatus.CANCELLED) {

        const docTotal = calculateTotal(doc.items);

        // Conversão para AOA
        const docCurrency = selectedCompany?.currency || 'USD';
        const rateToUSD = rates[docCurrency] || 1;
        const rateUSDToAOA = rates['AOA'] || 900;

        // Valor em USD -> Valor em AOA
        const valAOA = (docTotal / rateToUSD) * rateUSDToAOA;

        if (doc.type === DocumentType.INVOICE) {
          invoiceTotalAOA += valAOA;
          invoiceCount++;
        } else {
          budgetTotalAOA += valAOA;
          budgetCount++;
        }
      }
    });

    return { invoiceTotalAOA, budgetTotalAOA, invoiceCount, budgetCount };
  }, [documents, selectedCompanyId, rates, selectedCompany]);

  // --- FILTROS & LISTAGEM ---
  const filteredDocs = useMemo(() => {
    return documents.filter(d => d.companyId === selectedCompanyId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [documents, selectedCompanyId]);

  // --- LÓGICA DE FORMULÁRIO ---
  const handleNewDoc = () => {
    if (!selectedCompany) {
      alert("Selecione uma empresa primeiro.");
      return;
    }

    // Auto number logic: Count docs of this type for this company
    const count = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.BUDGET).length;
    const nextNum = count + 1;
    const year = new Date().getFullYear();

    setFormData({
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: DocumentType.BUDGET,
      status: DocumentStatus.DRAFT,
      number: `ORC-${nextNum.toString().padStart(3, '0')}/${year}`,
      date: new Date().toISOString().split('T')[0],
      items: [{ id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }],
      clientName: '',
      clientPhone: '',
      clientTaxID: '',
      notes: 'Este orçamento é válido por 15 dias.'
    });
    setMode('create');
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...(prev.items || []), { id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (itemId: string) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).filter(i => i.id !== itemId)
    }));
  };

  const handleItemChange = (itemId: string, field: keyof InvoiceItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).map(i => i.id === itemId ? { ...i, [field]: value } : i)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.clientName && formData.items && formData.items.length > 0) {
      onSave(formData as FinancialDocument);
      setMode('list');
    } else {
      alert("Preencha o nome do cliente e adicione pelo menos um item.");
    }
  };

  // --- LÓGICA DE AÇÕES ---

  const handleConvertToInvoice = (doc: FinancialDocument) => {
    if (confirm(`Converter orçamento ${doc.number} em Fatura Definitiva?`)) {
       // 1. Marcar orçamento como Aprovado
       onSave({ ...doc, status: DocumentStatus.APPROVED });

       // 2. Criar nova Fatura baseada no orçamento
       const countInv = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.INVOICE).length;
       const nextNum = countInv + 1;
       const year = new Date().getFullYear();

       const newInvoice: FinancialDocument = {
         ...doc,
         id: Math.random().toString(36).substr(2, 9),
         type: DocumentType.INVOICE,
         status: DocumentStatus.SENT,
         number: `FAT-${nextNum.toString().padStart(3, '0')}/${year}`,
         date: new Date().toISOString().split('T')[0],
         notes: 'Obrigado pela preferência.',
         createdAt: Date.now()
       };
       onSave(newInvoice);
       alert(`Fatura ${newInvoice.number} gerada com sucesso!`);
    }
  };

  const handlePDF = (doc: FinancialDocument) => {
    if (!selectedCompany) return;

    const pdf = new jsPDF();
    const pageWidth = pdf.internal.pageSize.width;
    const pageHeight = pdf.internal.pageSize.height;
    const currency = selectedCompany.currency;

    // --- PALETA DE CORES (PROFISSIONAL) ---
    const primaryColor = [15, 76, 117]; // Brand Petrol Blue (from logo)
    const accentColor = doc.type === DocumentType.INVOICE ? [16, 185, 129] : [14, 165, 233]; // Green or Blue
    const textDark = [30, 41, 59];
    const textLight = [100, 116, 139];

    // --- CABEÇALHO ---
    // Aumentar a altura do cabeçalho para acomodar as informações verticais
    const headerHeight = 65; 

    // 1. Barra de Topo
    pdf.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.rect(0, 0, pageWidth, headerHeight, 'F');

    // 2. Logo (Esquerda)
    let hasLogo = false;
    // Posição Y da logo ajustada para centralizar verticalmente no novo headerHeight ou ficar no topo
    const logoY = 10;
    if (appSettings.logo) {
       try {
         // Detectar formato da imagem (JPEG ou PNG) para evitar erros
         let imgFormat = 'PNG';
         if (appSettings.logo.startsWith('data:image/jpeg') || appSettings.logo.toLowerCase().endsWith('.jpg') || appSettings.logo.toLowerCase().endsWith('.jpeg')) {
            imgFormat = 'JPEG';
         }

         pdf.addImage(appSettings.logo, imgFormat, 14, logoY, 24, 24);
         hasLogo = true;
       } catch (e) {
         console.error("Error adding logo", e);
       }
    }

    // 3. Nome da Empresa (Esquerda, ao lado do logo)
    const textStartX = hasLogo ? 45 : 14;
    let currentY = 20;

    pdf.setTextColor(255, 255, 255);
    pdf.setFontSize(18);
    pdf.setFont("helvetica", "bold");
    pdf.text(appSettings.appName, textStartX, currentY);

    // Subtítulo da empresa
    if (appSettings.companySubtitle) {
        currentY += 6;
        pdf.setFontSize(10);
        pdf.setFont("helvetica", "normal");
        pdf.text(appSettings.companySubtitle, textStartX, currentY);
    }

    // Contactos da Empresa no Cabeçalho (Vertical List)
    currentY += 10; // Espaço antes dos contatos
    const lineHeight = 5;

    pdf.setFontSize(9);
    pdf.setTextColor(200, 200, 200); // Cinza claro para contraste no azul

    if(appSettings.phone) {
        pdf.text(`Contacto: ${appSettings.phone}`, textStartX, currentY);
        currentY += lineHeight;
    }
    if(appSettings.email) {
        pdf.text(`Email: ${appSettings.email}`, textStartX, currentY);
        currentY += lineHeight;
    }
    if(appSettings.province) {
        pdf.text(`Província: ${appSettings.province}`, textStartX, currentY);
        currentY += lineHeight;
    }
    if(appSettings.neighborhood) {
        pdf.text(`Bairro: ${appSettings.neighborhood}`, textStartX, currentY);
    }

    // 4. Título do Documento (Direita, Topo)
    pdf.setFontSize(24);
    pdf.setFont("helvetica", "bold");
    pdf.setTextColor(255, 255, 255);
    pdf.text(doc.type.toUpperCase(), pageWidth - 14, 25, { align: 'right' });

    // --- INFORMAÇÕES DO DOCUMENTO E CLIENTE ---
    const topMargin = headerHeight + 15;

    // Bloco Esquerdo: Cliente
    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "bold");
    pdf.text("CLIENTE:", 14, topMargin);

    pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
    pdf.setFontSize(12);
    pdf.text(doc.clientName, 14, topMargin + 6);

    pdf.setFontSize(10);
    pdf.setFont("helvetica", "normal");
    pdf.setTextColor(textLight[0], textLight[1], textLight[2]);
    if (doc.clientPhone) pdf.text(`Tel: ${doc.clientPhone}`, 14, topMargin + 12);
    if (doc.clientTaxID) pdf.text(`NIF: ${doc.clientTaxID}`, 14, topMargin + 17);

    // Bloco Direito: Detalhes do Doc
    const colRight = pageWidth - 60;

    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "bold");
    pdf.text("DETALHES:", colRight, topMargin);

    pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
    pdf.setFontSize(10);

    // Numero
    pdf.setFont("helvetica", "bold");
    pdf.text("Nº Doc:", colRight, topMargin + 6);
    pdf.setFont("helvetica", "normal");
    pdf.text(doc.number, pageWidth - 14, topMargin + 6, { align: 'right' });

    // Data
    pdf.setFont("helvetica", "bold");
    pdf.text("Data:", colRight, topMargin + 12);
    pdf.setFont("helvetica", "normal");
    pdf.text(new Date(doc.date).toLocaleDateString(), pageWidth - 14, topMargin + 12, { align: 'right' });

    // Vencimento (se houver)
    if (doc.dueDate) {
        pdf.setFont("helvetica", "bold");
        pdf.text("Vencimento:", colRight, topMargin + 18);
        pdf.setFont("helvetica", "normal");
        pdf.text(new Date(doc.dueDate).toLocaleDateString(), pageWidth - 14, topMargin + 18, { align: 'right' });
    }

    // Status
    pdf.setFont("helvetica", "bold");
    pdf.text("Status:", colRight, topMargin + (doc.dueDate ? 24 : 18));
    pdf.setTextColor(accentColor[0], accentColor[1], accentColor[2]);
    pdf.text(doc.status.toUpperCase(), pageWidth - 14, topMargin + (doc.dueDate ? 24 : 18), { align: 'right' });


    // --- TABELA DE ITENS ---
    const tableRows = doc.items.map(item => [
      item.description,
      item.quantity,
      `${item.unitPrice.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`,
      `${(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`
    ]);

    autoTable(pdf, {
      startY: topMargin + 35,
      head: [['DESCRIÇÃO', 'QTD', `PREÇO UNIT (${currency})`, `TOTAL (${currency})`]],
      body: tableRows,
      theme: 'grid',
      styles: {
          font: 'helvetica',
          fontSize: 9,
          textColor: textDark,
          lineColor: [230, 230, 230],
          lineWidth: 0.1,
          cellPadding: 4,
      },
      headStyles: {
          fillColor: primaryColor,
          textColor: [255, 255, 255],
          fontStyle: 'bold',
          lineWidth: 0,
      },
      columnStyles: {
        0: { cellWidth: 'auto' }, 
        1: { halign: 'center', cellWidth: 20 },
        2: { halign: 'right', cellWidth: 40 },
        3: { halign: 'right', cellWidth: 40, fontStyle: 'bold' }
      },
      alternateRowStyles: {
          fillColor: [248, 250, 252] // Slate 50
      }
    });

    // --- TOTAIS ---
    // @ts-ignore
    const finalY = pdf.lastAutoTable.finalY + 10;
    const total = calculateTotal(doc.items);

    // Caixa de Totais
    const boxWidth = 90;
    const boxX = pageWidth - boxWidth - 14;

    pdf.setDrawColor(200, 200, 200);
    pdf.line(boxX, finalY, pageWidth - 14, finalY);

    pdf.setFontSize(12);
    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFont("helvetica", "bold");
    pdf.text("TOTAL A PAGAR:", boxX, finalY + 8);
    pdf.text(`${currency} ${total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`, pageWidth - 14, finalY + 8, { align: 'right' });

    // --- RODAPÉ / NOTAS ---
    const footerY = Math.max(finalY + 25, pageHeight - 40);

    // Notas
    if (doc.notes) {
      pdf.setFontSize(9);
      pdf.setFont("helvetica", "bold");
      pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
      pdf.text("Notas / Termos:", 14, footerY);

      pdf.setFontSize(8);
      pdf.setFont("helvetica", "normal");
      pdf.setTextColor(textLight[0], textLight[1], textLight[2]);
      const splitNotes = pdf.splitTextToSize(doc.notes, pageWidth - 28);
      pdf.text(splitNotes, 14, footerY + 5);
    }

    // Info Simples no Rodapé (Já que temos detalhado no topo)
    pdf.setDrawColor(200, 200, 200);
    pdf.line(14, pageHeight - 15, pageWidth - 14, pageHeight - 15);

    pdf.setFontSize(7);
    pdf.setTextColor(150, 150, 150);
    pdf.text(`${appSettings.appName} - Documento gerado digitalmente.`, pageWidth / 2, pageHeight - 8, { align: 'center' });

    pdf.save(`${doc.type}_${doc.clientName.replace(/\s/g, '_')}_${doc.number}.pdf`);
  };

  const handleWhatsApp = (doc: FinancialDocument) => {
    if (!doc.clientPhone) {
      alert("Por favor, adicione o telefone do cliente no documento.");
      return;
    }

    const companyName = appSettings.appName || 'Nossa Empresa';
    const total = calculateTotal(doc.items);
    const currency = selectedCompany?.currency || 'AOA';
    const formattedTotal = total.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

    // Mensagem Limpa (Sem instruções técnicas)
    const text = `Olá *${doc.clientName}*,

Aqui está o seu *${doc.type} ${doc.number}* da *${companyName}*.

💰 Valor Total: *${currency} ${formattedTotal}*

Qualquer dúvida, estamos à disposição!`;

    // 1. Baixar o PDF Automaticamente
    handlePDF(doc);

    // 2. Alertar o usuário da APP (UX importante pois não dá para anexar automático na web)
    alert("📄 O PDF foi baixado para o seu dispositivo!\n\nO WhatsApp abrirá em seguida. Por favor, anexe o arquivo baixado manualmente na conversa.");

    // 3. Abrir WhatsApp após um breve delay para garantir que o download iniciou
    setTimeout(() => {
        let phone = doc.clientPhone!.replace(/[^0-9]/g, '');
        if (phone.length === 9 && phone.startsWith('9')) {
          phone = '244' + phone;
        }
        const url = `https://wa.me/${phone}?text=${encodeURIComponent(text)}`;
        window.open(url, '_blank');
    }, 1000);
  };

  // --- RENDER ---

  if (mode === 'create' || mode === 'edit') {
    return (
      <div className="max-w-4xl mx-auto animate-fade-in">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <FileText className="text-brand-500" />
            {mode === 'create' ? `Novo ${formData.type}` : `Editar ${formData.number}`}
          </h2>
          <button onClick={() => setMode('list')} className="text-slate-500 hover:text-slate-700 dark:text-slate-400">
             <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">

          {/* Header Data */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Tipo de Doc</label>
               <select 
                 value={formData.type} 
                 onChange={e => setFormData({...formData, type: e.target.value as DocumentType})}
                 className="w-full p-2.5 rounded-lg border bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white border-slate-300"
                 disabled={mode === 'edit'}
               >
                 <option value={DocumentType.BUDGET}>{DocumentType.BUDGET}</option>
                 <option value={DocumentType.INVOICE}>{DocumentType.INVOICE}</option>
               </select>
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Número</label>
               <input 
                 type="text" 
                 value={formData.number} 
                 readOnly 
                 className="w-full p-2.5 rounded-lg border bg-slate-100 dark:bg-slate-900 text-slate-500 cursor-not-allowed border-slate-200" 
               />
             </div>
             <div>
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data</label>
               <input 
                 type="date" 
                 value={formData.date} 
                 onChange={e => setFormData({...formData, date: e.target.value})}
                 className="w-full p-2.5 rounded-lg border bg-white border-slate-300 text-slate-900" 
               />
             </div>
          </div>

          {/* Client Data */}
          <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg mb-6 border border-slate-200 dark:border-slate-700">
            <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-3">Dados do Cliente</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input 
                 placeholder="Nome do Cliente *" 
                 value={formData.clientName}
                 onChange={e => setFormData({...formData, clientName: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
                 required
              />
              <input 
                 placeholder="Telefone (WhatsApp) Ex: 923..." 
                 value={formData.clientPhone}
                 onChange={e => setFormData({...formData, clientPhone: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
              />
              <input 
                 placeholder="NIF (Opcional)" 
                 value={formData.clientTaxID}
                 onChange={e => setFormData({...formData, clientTaxID: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
              />
            </div>
            <p className="text-xs text-slate-500 mt-2">O telefone é usado para enviar o documento via WhatsApp.</p>
          </div>

          {/* Items */}
          <div className="mb-6">
            <div className="flex justify-between items-center mb-2">
               <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300">Itens / Serviços</h3>
            </div>
            <table className="w-full text-sm">
              <thead className="bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300">
                <tr>
                  <th className="p-2 text-left">Descrição</th>
                  <th className="p-2 w-20 text-center">Qtd</th>
                  <th className="p-2 w-32 text-right">Preço Unit</th>
                  <th className="p-2 w-32 text-right">Total</th>
                  <th className="p-2 w-10"></th>
                </tr>
              </thead>
              <tbody>
                {formData.items?.map(item => (
                  <tr key={item.id} className="border-b dark:border-slate-700 bg-white dark:bg-slate-900/50">
                    <td className="p-2">
                      <input 
                        value={item.description}
                        onChange={e => handleItemChange(item.id, 'description', e.target.value)}
                        placeholder="Ex: Consultoria"
                        className="w-full p-1 bg-transparent outline-none text-slate-900 dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="1"
                        value={item.quantity}
                        onChange={e => handleItemChange(item.id, 'quantity', parseInt(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-center text-slate-900 dark:text-white"
                      />
                    </td>
                    <td className="p-2">
                      <input 
                        type="number"
                        min="0"
                        value={item.unitPrice}
                        onChange={e => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value))}
                        className="w-full p-1 bg-transparent outline-none text-right text-slate-900 dark:text-white"
                      />
                    </td>
                    <td className="p-2 text-right font-medium text-slate-900 dark:text-white">
                      {(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}
                    </td>
                    <td className="p-2 text-center">
                      <button type="button" onClick={() => handleRemoveItem(item.id)} className="text-rose-400 hover:text-rose-600"><Trash2 size={14} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button type="button" onClick={handleAddItem} className="mt-2 text-sm text-brand-600 font-medium flex items-center gap-1 hover:underline">
              <Plus size={14} /> Adicionar Item
            </button>
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start gap-6 border-t dark:border-slate-700 pt-6">
            <div className="w-full md:w-1/2">
               <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Notas / Termos</label>
               <textarea 
                 value={formData.notes}
                 onChange={e => setFormData({...formData, notes: e.target.value})}
                 className="w-full p-2.5 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder:text-slate-400 text-sm h-24 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
               />
            </div>
            <div className="w-full md:w-1/3 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg">
               <div className="flex justify-between items-center text-lg font-bold text-slate-800 dark:text-white">
                 <span>Total ({selectedCompany?.currency})</span>
                 <span>{calculateTotal(formData.items).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</span>
               </div>
               <button type="submit" className="w-full mt-4 py-3 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg shadow-lg flex justify-center items-center gap-2">
                 <CheckCircle size={18} /> Salvar Documento
               </button>
            </div>
          </div>

        </form>
      </div>
    );
  }

  return (
    <div className="space-y-6">
       {/* Toolbar */}
       <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col md:flex-row justify-between items-center gap-4">
         <div>
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">Orçamentos & Faturas</h2>
            <p className="text-sm text-slate-500 dark:text-slate-400">Gira documentos profissionais em {selectedCompany?.currency || 'AOA'}</p>
         </div>
         <div className="flex items-center gap-3">
            <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="p-2 rounded-lg border bg-slate-50 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
            >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <button 
              onClick={handleNewDoc}
              className="bg-brand-600 hover:bg-brand-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 shadow-md"
            >
              <Plus size={18} /> Novo Orçamento
            </button>
         </div>
       </div>

       {/* Monthly Stats Summary */}
       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-emerald-100 dark:border-emerald-900/30 shadow-sm flex items-center justify-between">
             <div>
                <p className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wide">Faturado este Mês (AOA)</p>
                <h3 className="text-2xl font-bold text-slate-800 dark:text-white mt-1">
                   Kz {monthlyStats.invoiceTotalAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </h3>
                <p className="text-xs text-slate-400 mt-1">{monthlyStats.invoiceCount} faturas emitidas</p>
             </div>
             <div className="p-3 bg-emerald-50 dark:bg-emerald-900/20 rounded-full text-emerald-600 dark:text-emerald-400">
                <Wallet size={24} />
             </div>
          </div>

          <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-blue-100 dark:border-blue-900/30 shadow-sm flex items-center justify-between">
             <div>
                <p className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wide">Orçamentos este Mês (AOA)</p>
                <h3 className="text-2xl font-bold text-slate-800 dark:text-white mt-1">
                   Kz {monthlyStats.budgetTotalAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </h3>
                <p className="text-xs text-slate-400 mt-1">{monthlyStats.budgetCount} orçamentos criados</p>
             </div>
             <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-full text-blue-600 dark:text-blue-400">
                <Calculator size={24} />
             </div>
          </div>
       </div>

       {/* List */}
       <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
         {filteredDocs.length === 0 ? (
           <div className="p-12 text-center text-slate-400">
             <FileText className="mx-auto w-12 h-12 mb-3 opacity-30" />
             <p>Nenhum documento criado para esta empresa.</p>
           </div>
         ) : (
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-500 dark:text-slate-400 text-xs uppercase">
                 <tr>
                   <th className="p-4">Número</th>
                   <th className="p-4">Cliente</th>
                   <th className="p-4">Data</th>
                   <th className="p-4 text-center">Status</th>
                   <th className="p-4 text-right">Total</th>
                   <th className="p-4 text-center">Ações</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                 {filteredDocs.map(doc => (
                   <tr key={doc.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                     <td className="p-4 font-medium text-slate-700 dark:text-slate-200 flex items-center gap-2">
                       {doc.type === DocumentType.INVOICE ? <CheckCircle size={16} className="text-emerald-500" /> : <FileText size={16} className="text-brand-500" />}
                       {doc.number}
                     </td>
                     <td className="p-4 text-slate-600 dark:text-slate-300">
                       <div className="font-medium">{doc.clientName}</div>
                       <div className="text-xs text-slate-400">{doc.clientPhone || '-'}</div>
                     </td>
                     <td className="p-4 text-sm text-slate-500 dark:text-slate-400">
                       {new Date(doc.date).toLocaleDateString()}
                     </td>
                     <td className="p-4 text-center">
                       <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                         doc.status === DocumentStatus.DRAFT ? 'bg-slate-100 text-slate-600' :
                         doc.status === DocumentStatus.SENT ? 'bg-blue-100 text-blue-600' :
                         doc.status === DocumentStatus.APPROVED ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.PAID ? 'bg-emerald-100 text-emerald-600' :
                         doc.status === DocumentStatus.CANCELLED ? 'bg-rose-100 text-rose-600' : ''
                       }`}>
                         {doc.status}
                       </span>
                     </td>
                     <td className="p-4 text-right font-bold text-slate-700 dark:text-white">
                        {calculateTotal(doc.items).toLocaleString('pt-AO', { minimumFractionDigits: 2 })} <span className="text-xs font-normal text-slate-400">{selectedCompany?.currency}</span>
                     </td>
                     <td className="p-4">
                       <div className="flex items-center justify-center gap-2">
                         <button 
                           onClick={() => handleWhatsApp(doc)} 
                           className="p-2 bg-emerald-100 text-emerald-600 hover:bg-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-400 dark:hover:bg-emerald-900/50 rounded-lg transition-colors" 
                           title="Enviar por WhatsApp"
                         >
                           <MessageCircle size={18} />
                         </button>
                         <button onClick={() => handlePDF(doc)} className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg" title="Baixar PDF">
                           <Printer size={18} />
                         </button>
                         {doc.type === DocumentType.BUDGET && (
                           <button onClick={() => handleConvertToInvoice(doc)} className="p-2 text-brand-600 hover:bg-brand-50 dark:hover:bg-brand-900/20 rounded-lg" title="Converter em Fatura">
                             <ArrowRight size={18} />
                           </button>
                         )}
                         <button onClick={() => onDelete(doc.id)} className="p-2 text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg" title="Apagar">
                           <Trash2 size={18} />
                         </button>
                       </div>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
           </div>
         )}
       </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Company, Transaction, TransactionType, ExchangeRates, Currency, AppSettings } from '../types';
import { Download, FileText, Calendar, Building, Printer, FileSpreadsheet } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface ReportsProps {
  companies: Company[];
  transactions: Transaction[];
  rates: ExchangeRates;
  appSettings: AppSettings;
}

export const Reports: React.FC<ReportsProps> = ({ companies, transactions, rates, appSettings }) => {
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));

  // Helper: Convert to AOA
  const toAOA = (amt: number, currency?: string) => {
    if (!currency) return amt;
    const rateToUSD = rates[currency] || 1;
    const rateUSDToAOA = rates[Currency.AOA] || 900;

    const inUSD = amt / rateToUSD;
    return inUSD * rateUSDToAOA;
  };

  const getFilteredData = () => {
     const company = companies.find(c => c.id === selectedCompanyId);
     if (!company) return null;

     const monthlyTransactions = transactions.filter(t => 
      t.companyId === selectedCompanyId && 
      t.date.startsWith(selectedMonth)
    );

    return { company, monthlyTransactions };
  }

  const generatePDF = () => {
    const data = getFilteredData();
    if (!data) return;
    const { company, monthlyTransactions } = data;

    const incomeAOA = monthlyTransactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + toAOA(t.amount, company.currency), 0);

    const expenseAOA = monthlyTransactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + toAOA(t.amount, company.currency), 0);

    const profitAOA = incomeAOA - expenseAOA;
    const margin = incomeAOA > 0 ? ((profitAOA / incomeAOA) * 100).toFixed(2) : '0';

    // Agrupar por categoria (AOA)
    const categorySummary: Record<string, { type: TransactionType, amount: number }> = {};
    monthlyTransactions.forEach(t => {
      const aoaAmount = toAOA(t.amount, company.currency);
      if (!categorySummary[t.category]) {
        categorySummary[t.category] = { type: t.type, amount: 0 };
      }
      categorySummary[t.category].amount += aoaAmount;
    });

    // 2. Inicializar PDF
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.width;

    // -- CORES --
    const primaryColor = [14, 165, 233]; // Brand-500
    const profitColor = [16, 185, 129]; // Emerald
    const expenseColor = [239, 68, 68]; // Red
    const slateColor = [51, 65, 85]; // Slate-700

    // 3. Cabeçalho
    doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.rect(0, 0, pageWidth, 40, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("Relatório Financeiro Mensal (AOA)", 14, 20);

    doc.setFontSize(12);
    doc.setFont("helvetica", "normal");
    doc.text(`Empresa: ${company.name}`, 14, 30);

    const [year, month] = selectedMonth.split('-');
    const dateStr = new Date(parseInt(year), parseInt(month)-1).toLocaleDateString('pt-PT', { month: 'long', year: 'numeric' });
    doc.text(`Período: ${dateStr}`, 14, 36);

    // Custom Logo in Header
    if (appSettings.logo) {
       try {
         // Detectar formato da imagem (JPEG ou PNG)
         let imgFormat = 'PNG';
         if (appSettings.logo.startsWith('data:image/jpeg') || appSettings.logo.toLowerCase().endsWith('.jpg') || appSettings.logo.toLowerCase().endsWith('.jpeg')) {
            imgFormat = 'JPEG';
         }
         doc.addImage(appSettings.logo, imgFormat, pageWidth - 25, 5, 15, 15);
       } catch (e) {
         console.error("Error adding logo", e);
       }
    }

    doc.setFontSize(10);
    doc.text(`Gerado por: ${appSettings.appName}`, pageWidth - 60, 36);

    let currentY = 50;

    // 4. Resumo Executivo (Cards)
    doc.setTextColor(slateColor[0], slateColor[1], slateColor[2]);
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text("Resumo Financeiro (Valores em Kwanzas)", 14, currentY);
    currentY += 10;

    const summaryData = [
      [`Receita Total`, `Kz ${incomeAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`],
      [`Despesa Total`, `Kz ${expenseAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`],
      [`Lucro Líquido`, `Kz ${profitAOA.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`],
      [`Margem de Lucro`, `${margin}%`]
    ];

    autoTable(doc, {
      startY: currentY,
      head: [['Indicador', 'Valor (AOA)']],
      body: summaryData,
      theme: 'grid',
      headStyles: { fillColor: [241, 245, 249], textColor: [51, 65, 85], fontStyle: 'bold' }, // Slate-100
      columnStyles: {
        0: { fontStyle: 'bold', cellWidth: 100 },
        1: { halign: 'right' }
      },
      styles: { fontSize: 11, cellPadding: 6 }
    });

    // @ts-ignore
    currentY = doc.lastAutoTable.finalY + 15;

    // 5. Detalhamento por Categoria (Top 5 Despesas)
    doc.text("Top Despesas por Categoria (AOA)", 14, currentY);
    currentY += 8;

    const expenseCategories = Object.entries(categorySummary)
      .filter(([_, data]) => data.type === TransactionType.EXPENSE)
      .sort((a, b) => b[1].amount - a[1].amount)
      .map(([name, data]) => [name, `Kz ${data.amount.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`]);

    if (expenseCategories.length > 0) {
      autoTable(doc, {
        startY: currentY,
        head: [['Categoria', 'Total Gasto (AOA)']],
        body: expenseCategories,
        theme: 'striped',
        headStyles: { fillColor: expenseColor, textColor: 255 },
        columnStyles: { 1: { halign: 'right' } }
      });
      // @ts-ignore
      currentY = doc.lastAutoTable.finalY + 15;
    } else {
      doc.setFontSize(10);
      doc.setFont("helvetica", "italic");
      doc.text("Nenhuma despesa registrada neste período.", 14, currentY + 5);
      currentY += 15;
    }

    // 6. Tabela Completa de Transações
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.setTextColor(slateColor[0], slateColor[1], slateColor[2]);
    doc.text("Detalhamento de Transações", 14, currentY);
    currentY += 8;

    const rows = monthlyTransactions
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map(t => [
        new Date(t.date).toLocaleDateString('pt-PT'),
        t.category,
        t.description || '-',
        t.type === TransactionType.INCOME ? 'Entrada' : 'Saída',
        `Kz ${toAOA(t.amount, company.currency).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`
      ]);

    autoTable(doc, {
      startY: currentY,
      head: [['Data', 'Categoria', 'Descrição', 'Tipo', 'Valor (AOA)']],
      body: rows,
      theme: 'striped',
      headStyles: { fillColor: slateColor, textColor: 255 },
      columnStyles: {
        4: { halign: 'right', fontStyle: 'bold' }
      },
      didParseCell: function(data) {
        // Colorir o texto de Entrada/Saída
        if (data.section === 'body' && data.column.index === 3) {
            if (data.cell.raw === 'Entrada') {
                data.cell.styles.textColor = profitColor;
            } else {
                data.cell.styles.textColor = expenseColor;
            }
        }
      }
    });

    // 7. Salvar PDF
    const filename = `Relatorio_AOA_${company.name.replace(/\s+/g, '_')}_${selectedMonth}.pdf`;
    doc.save(filename);
  };

  const generateCSV = () => {
    const data = getFilteredData();
    if (!data) return;
    const { company, monthlyTransactions } = data;

    const headers = ['Data', 'Empresa', 'Tipo', 'Categoria', 'Descrição', 'Valor Original', 'Moeda Orig.', 'Valor AOA'];
    const rows = monthlyTransactions.map(t => [
      t.date,
      company.name,
      t.type === TransactionType.INCOME ? 'Entrada' : 'Saida',
      `"${t.category}"`, // Escape quotes
      `"${t.description || ''}"`,
      t.amount,
      company.currency,
      toAOA(t.amount, company.currency).toFixed(2)
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `Extrato_AOA_${company.name}_${selectedMonth}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="bg-white dark:bg-slate-800 p-8 rounded-xl shadow-lg border border-slate-100 dark:border-slate-700">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <Printer size={32} />
          </div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">Relatórios Oficiais (AOA)</h2>
          <p className="text-slate-500 dark:text-slate-400 max-w-lg mx-auto">
            Gere documentos completos com análise financeira, totais por categoria e histórico detalhado, convertidos para Kwanzas.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-2xl mx-auto bg-slate-50 dark:bg-slate-900/50 p-6 rounded-xl border border-slate-200 dark:border-slate-700">
          <div>
             <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
               <Building size={16} /> Empresa
             </label>
             <select 
               value={selectedCompanyId} 
               onChange={(e) => setSelectedCompanyId(e.target.value)}
               className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
             >
               {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
             </select>
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
               <Calendar size={16} /> Mês de Referência
             </label>
             <input 
               type="month" 
               value={selectedMonth} 
               onChange={(e) => setSelectedMonth(e.target.value)}
               className="w-full p-3 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
             />
          </div>

          <div className="md:col-span-2 pt-2 flex flex-col md:flex-row gap-3">
            <button 
              onClick={generatePDF}
              className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-brand-600 hover:bg-brand-700 text-white font-bold rounded-lg transition-all shadow-lg shadow-brand-500/20 active:scale-95"
            >
              <FileText size={22} />
              Baixar PDF (AOA)
            </button>

            <button 
              onClick={generateCSV}
              className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-lg transition-all shadow-lg shadow-emerald-500/20 active:scale-95"
            >
              <FileSpreadsheet size={22} />
              Baixar CSV (Excel)
            </button>
          </div>

          <div className="md:col-span-2 text-center text-xs text-slate-400 mt-1">
             PDF para leitura e impressão, CSV para análise em Excel. Todos os valores convertidos.
          </div>
        </div>
      </div>

      {/* Preview Section */}
      <div className="border-t border-slate-200 dark:border-slate-800 pt-8">
        <h3 className="text-lg font-semibold text-slate-700 dark:text-slate-300 mb-4 flex items-center gap-2">
          <FileText size={20} /> O que está incluído no relatório?
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
          <div className="p-4 bg-emerald-50 dark:bg-emerald-900/10 rounded-lg border border-emerald-100 dark:border-emerald-900/20">
            <span className="font-bold text-emerald-700 dark:text-emerald-400 block mb-1">Resumo em Kwanzas</span>
            <p className="text-slate-600 dark:text-slate-400">Totais de entradas, saídas, lucro líquido real e margem de lucratividade convertidos.</p>
          </div>
          <div className="p-4 bg-blue-50 dark:bg-blue-900/10 rounded-lg border border-blue-100 dark:border-blue-900/20">
            <span className="font-bold text-blue-700 dark:text-blue-400 block mb-1">Análise por Categoria</span>
            <p className="text-slate-600 dark:text-slate-400">Agrupamento automático de gastos para identificar onde o dinheiro está sendo investido.</p>
          </div>
          <div className="p-4 bg-amber-50 dark:bg-amber-900/10 rounded-lg border border-amber-100 dark:border-amber-900/20">
            <span className="font-bold text-amber-700 dark:text-amber-400 block mb-1">Extrato Detalhado</span>
            <p className="text-slate-600 dark:text-slate-400">Lista cronológica de todas as transações com valores em AOA e Moeda Original.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Company, FinancialDocument, DocumentType, DocumentStatus, InvoiceItem, ExchangeRates, AppSettings } from '../types';
import { Plus, Printer, Share2, FileText, ArrowRight, Trash2, CheckCircle, X, MessageCircle, Calculator, Wallet } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface InvoicesProps {
  companies: Company[];
  documents: FinancialDocument[];
  onSave: (doc: FinancialDocument) => void;
  onDelete: (id: string) => void;
  rates: ExchangeRates;
  appSettings: AppSettings;
}

export const Invoices: React.FC<InvoicesProps> = ({ companies, documents, onSave, onDelete, rates, appSettings }) => {
  const [mode, setMode] = useState<'list' | 'create' | 'edit'>('list');
  const [selectedCompanyId, setSelectedCompanyId] = useState(companies[0]?.id || '');
  const [formData, setFormData] = useState<Partial<FinancialDocument>>({
    items: [],
    type: DocumentType.BUDGET,
    status: DocumentStatus.DRAFT,
    date: new Date().toISOString().split('T')[0]
  });

  const selectedCompany = companies.find(c => c.id === selectedCompanyId);

  // --- HELPER: TOTAL DO DOCUMENTO ---
  const calculateTotal = (items: InvoiceItem[] = []) => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  };

  // --- ESTATÍSTICAS DO MÊS ATUAL ---
  const monthlyStats = useMemo(() => {
    const now = new Date();
    const currentMonthPrefix = now.toISOString().slice(0, 7); // YYYY-MM

    let invoiceTotalAOA = 0;
    let budgetTotalAOA = 0;
    let invoiceCount = 0;
    let budgetCount = 0;

    documents.forEach(doc => {
      // Filtra por empresa, mês atual e ignora cancelados
      if (doc.companyId === selectedCompanyId && 
          doc.date.startsWith(currentMonthPrefix) && 
          doc.status !== DocumentStatus.CANCELLED) {

        const docTotal = calculateTotal(doc.items);

        // Conversão para AOA
        const docCurrency = selectedCompany?.currency || 'USD';
        const rateToUSD = rates[docCurrency] || 1;
        const rateUSDToAOA = rates['AOA'] || 900;

        // Valor em USD -> Valor em AOA
        const valAOA = (docTotal / rateToUSD) * rateUSDToAOA;

        if (doc.type === DocumentType.INVOICE) {
          invoiceTotalAOA += valAOA;
          invoiceCount++;
        } else {
          budgetTotalAOA += valAOA;
          budgetCount++;
        }
      }
    });

    return { invoiceTotalAOA, budgetTotalAOA, invoiceCount, budgetCount };
  }, [documents, selectedCompanyId, rates, selectedCompany]);

  // --- FILTROS & LISTAGEM ---
  const filteredDocs = useMemo(() => {
    return documents.filter(d => d.companyId === selectedCompanyId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [documents, selectedCompanyId]);

  // --- LÓGICA DE FORMULÁRIO ---
  const handleNewDoc = () => {
    if (!selectedCompany) {
      alert("Selecione uma empresa primeiro.");
      return;
    }

    // Auto number logic: Count docs of this type for this company
    const count = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.BUDGET).length;
    const nextNum = count + 1;
    const year = new Date().getFullYear();

    setFormData({
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompanyId,
      type: DocumentType.BUDGET,
      status: DocumentStatus.DRAFT,
      number: `ORC-${nextNum.toString().padStart(3, '0')}/${year}`,
      date: new Date().toISOString().split('T')[0],
      items: [{ id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }],
      clientName: '',
      clientPhone: '',
      clientTaxID: '',
      notes: 'Este orçamento é válido por 15 dias.'
    });
    setMode('create');
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...(prev.items || []), { id: Math.random().toString(36), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (itemId: string) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).filter(i => i.id !== itemId)
    }));
  };

  const handleItemChange = (itemId: string, field: keyof InvoiceItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: (prev.items || []).map(i => i.id === itemId ? { ...i, [field]: value } : i)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.clientName && formData.items && formData.items.length > 0) {
      onSave(formData as FinancialDocument);
      setMode('list');
    } else {
      alert("Preencha o nome do cliente e adicione pelo menos um item.");
    }
  };

  // --- LÓGICA DE AÇÕES ---

  const handleConvertToInvoice = (doc: FinancialDocument) => {
    if (confirm(`Converter orçamento ${doc.number} em Fatura Definitiva?`)) {
       // 1. Marcar orçamento como Aprovado
       onSave({ ...doc, status: DocumentStatus.APPROVED });

       // 2. Criar nova Fatura baseada no orçamento
       const countInv = documents.filter(d => d.companyId === selectedCompanyId && d.type === DocumentType.INVOICE).length;
       const nextNum = countInv + 1;
       const year = new Date().getFullYear();

       const newInvoice: FinancialDocument = {
         ...doc,
         id: Math.random().toString(36).substr(2, 9),
         type: DocumentType.INVOICE,
         status: DocumentStatus.SENT,
         number: `FAT-${nextNum.toString().padStart(3, '0')}/${year}`,
         date: new Date().toISOString().split('T')[0],
         notes: 'Obrigado pela preferência.',
         createdAt: Date.now()
       };
       onSave(newInvoice);
       alert(`Fatura ${newInvoice.number} gerada com sucesso!`);
    }
  };

  const handlePDF = (doc: FinancialDocument) => {
    if (!selectedCompany) return;

    const pdf = new jsPDF();
    const pageWidth = pdf.internal.pageSize.width;
    const pageHeight = pdf.internal.pageSize.height;
    const currency = selectedCompany.currency;

    // --- PALETA DE CORES (PROFISSIONAL) ---
    const primaryColor = [15, 76, 117]; // Brand Petrol Blue (from logo)
    const accentColor = doc.type === DocumentType.INVOICE ? [16, 185, 129] : [14, 165, 233]; // Green or Blue
    const textDark = [30, 41, 59];
    const textLight = [100, 116, 139];

    // --- CABEÇALHO ---
    // Aumentar a altura do cabeçalho para acomodar informações e evitar sobreposição
    const headerHeight = 70; 

    // 1. Barra de Fundo do Cabeçalho
    pdf.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.rect(0, 0, pageWidth, headerHeight, 'F');

    // 2. Logo (Esquerda Superior)
    let hasLogo = false;
    const logoY = 12;
    const logoSize = 24;

    if (appSettings.logo) {
       try {
         // Detectar formato da imagem para evitar erro "Incomplete or corrupt PNG"
         let imgFormat = 'PNG';
         // Se for a URL específica do usuário ou terminar em jpg/jpeg, forçar JPEG
         if (appSettings.logo.includes('supaimg') || appSettings.logo.toLowerCase().endsWith('.jpg') || appSettings.logo.toLowerCase().endsWith('.jpeg') || appSettings.logo.startsWith('data:image/jpeg')) {
            imgFormat = 'JPEG';
         }

         pdf.addImage(appSettings.logo, imgFormat, 14, logoY, logoSize, logoSize);
         hasLogo = true;
       } catch (e) {
         console.error("Error adding logo", e);
       }
    }

    // 3. Nome da Empresa (Ao lado do logo)
    const textStartX = hasLogo ? 45 : 14;
    let currentY = 22;

    pdf.setTextColor(255, 255, 255);
    pdf.setFontSize(16);
    pdf.setFont("helvetica", "bold");

    // Usar splitTextToSize para garantir que o nome não invada a área direita
    const maxNameWidth = 90; 
    const splitName = pdf.splitTextToSize(appSettings.appName, maxNameWidth);
    pdf.text(splitName, textStartX, currentY);

    // Ajustar Y baseado no tamanho do nome (se ocupou 2 linhas)
    const nameHeight = splitName.length * 6;
    currentY += (nameHeight - 4); 

    // Subtítulo da empresa
    if (appSettings.companySubtitle) {
        pdf.setFontSize(9);
        pdf.setFont("helvetica", "normal");
        pdf.setTextColor(200, 210, 230);
        const splitSubtitle = pdf.splitTextToSize(appSettings.companySubtitle, maxNameWidth);
        pdf.text(splitSubtitle, textStartX, currentY + 5);
    }

    // 4. Título do Documento (Direita Superior - ALINHADO À DIREITA)
    // Isso garante que nunca sobreponha o logo ou nome
    pdf.setFontSize(26);
    pdf.setFont("helvetica", "bold");
    pdf.setTextColor(255, 255, 255);
    pdf.text(doc.type.toUpperCase(), pageWidth - 14, 25, { align: 'right' });

    pdf.setFontSize(10);
    pdf.setFont("helvetica", "normal");
    pdf.setTextColor(200, 210, 230);
    pdf.text(`Nº ${doc.number}`, pageWidth - 14, 32, { align: 'right' });

    // 5. Contatos da Empresa (Abaixo do logo/nome, ainda no cabeçalho azul)
    // Definir uma posição fixa Y abaixo dos elementos superiores
    let contactY = 48;
    const contactX = 14;

    pdf.setFontSize(8);
    pdf.setTextColor(220, 220, 220);

    // Grid simples para contatos para economizar espaço vertical se necessário
    let contactText = "";
    if(appSettings.phone) contactText += `Tel: ${appSettings.phone}  |  `;
    if(appSettings.email) contactText += `Email: ${appSettings.email}`;

    pdf.text(contactText, contactX, contactY);

    let addressText = "";
    if(appSettings.province) addressText += `${appSettings.province}`;
    if(appSettings.neighborhood) addressText += `, ${appSettings.neighborhood}`;

    if (addressText) {
        pdf.text(addressText, contactX, contactY + 4);
    }


    // --- DADOS DO CLIENTE E DETALHES ---
    const topMargin = headerHeight + 15;

    // Bloco Esquerdo: Cliente
    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "bold");
    pdf.text("FATURAR A:", 14, topMargin);

    pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
    pdf.setFontSize(11);
    pdf.text(doc.clientName, 14, topMargin + 6);

    pdf.setFontSize(9);
    pdf.setFont("helvetica", "normal");
    pdf.setTextColor(textLight[0], textLight[1], textLight[2]);
    if (doc.clientPhone) pdf.text(`Tel: ${doc.clientPhone}`, 14, topMargin + 11);
    if (doc.clientTaxID) pdf.text(`NIF: ${doc.clientTaxID}`, 14, topMargin + 15);

    // Bloco Direito: Datas e Status
    const colRight = pageWidth - 60;

    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFontSize(10);
    pdf.setFont("helvetica", "bold");
    pdf.text("DADOS:", colRight, topMargin);

    pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
    pdf.setFontSize(9);

    // Data
    pdf.setFont("helvetica", "bold");
    pdf.text("Emissão:", colRight, topMargin + 6);
    pdf.setFont("helvetica", "normal");
    pdf.text(new Date(doc.date).toLocaleDateString(), pageWidth - 14, topMargin + 6, { align: 'right' });

    // Vencimento (se houver)
    if (doc.dueDate) {
        pdf.setFont("helvetica", "bold");
        pdf.text("Vencimento:", colRight, topMargin + 11);
        pdf.setFont("helvetica", "normal");
        pdf.text(new Date(doc.dueDate).toLocaleDateString(), pageWidth - 14, topMargin + 11, { align: 'right' });
    }

    // Status
    const statusY = doc.dueDate ? topMargin + 16 : topMargin + 11;
    pdf.setFont("helvetica", "bold");
    pdf.text("Estado:", colRight, statusY);
    pdf.setTextColor(accentColor[0], accentColor[1], accentColor[2]);
    pdf.text(doc.status.toUpperCase(), pageWidth - 14, statusY, { align: 'right' });


    // --- TABELA DE ITENS ---
    const tableRows = doc.items.map(item => [
      item.description,
      item.quantity,
      `${item.unitPrice.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`,
      `${(item.quantity * item.unitPrice).toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`
    ]);

    autoTable(pdf, {
      startY: topMargin + 25,
      head: [['DESCRIÇÃO', 'QTD', `PREÇO UNIT (${currency})`, `TOTAL (${currency})`]],
      body: tableRows,
      theme: 'grid',
      styles: {
          font: 'helvetica',
          fontSize: 9,
          textColor: textDark,
          lineColor: [230, 230, 230],
          lineWidth: 0.1,
          cellPadding: 4,
      },
      headStyles: {
          fillColor: primaryColor,
          textColor: [255, 255, 255],
          fontStyle: 'bold',
          lineWidth: 0,
      },
      columnStyles: {
        0: { cellWidth: 'auto' }, 
        1: { halign: 'center', cellWidth: 20 },
        2: { halign: 'right', cellWidth: 40 },
        3: { halign: 'right', cellWidth: 40, fontStyle: 'bold' }
      },
      alternateRowStyles: {
          fillColor: [248, 250, 252] // Slate 50
      }
    });

    // --- TOTAIS ---
    // @ts-ignore
    const finalY = pdf.lastAutoTable.finalY + 10;
    const total = calculateTotal(doc.items);

    // Caixa de Totais
    const boxWidth = 90;
    const boxX = pageWidth - boxWidth - 14;

    pdf.setDrawColor(200, 200, 200);
    pdf.line(boxX, finalY, pageWidth - 14, finalY);

    pdf.setFontSize(12);
    pdf.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    pdf.setFont("helvetica", "bold");
    pdf.text("TOTAL LÍQUIDO:", boxX, finalY + 8);
    pdf.text(`${currency} ${total.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}`, pageWidth - 14, finalY + 8, { align: 'right' });

    // --- RODAPÉ / NOTAS ---
    const footerY = Math.max(finalY + 25, pageHeight - 40);

    // Notas
    if (doc.notes) {
      pdf.setFontSize(9);
      pdf.setFont("helvetica", "bold");
      pdf.setTextColor(textDark[0], textDark[1], textDark[2]);
      pdf.text("Notas & Termos:", 14, footerY);

      pdf.setFontSize(8);
      pdf.setFont("helvetica", "normal");
      pdf.setTextColor(textLight[0], textLight[1], textLight[2]);
      const splitNotes = pdf.splitTextToSize(doc.notes, pageWidth - 28);
      pdf.text(splitNotes, 14, footerY + 5);
    }

    // Rodapé Fixo
    pdf.setDrawColor(200, 200, 200);
    pdf.line(14, pageHeight - 15, pageWidth - 14, pageHeight - 15);

    pdf.setFontSize(7);
    pdf.setTextColor(150, 150, 150);
    pdf.text(`Processado por ${appSettings.appName} | Documento isento de selo fiscal.`, pageWidth / 2, pageHeight - 8, { align: 'center' });

    pdf.save(`${doc.type}_${doc.clientName.replace(/\s/g, '_')}_${doc.number}.pdf`);
  };

  const handleWhatsApp = (doc: FinancialDocument) => {
    if (!doc.clientPhone) {
      alert("Por favor, adicione o telefone do cliente no documento.");
      return;
    }

    const companyName = appSettings.appName || 'Nossa Empresa';
    const total = calculateTotal(doc.items);
